window.QUESTION_BANK = {"marx":{"name":"马克思主义基本原理","chapters":[{"id":"daolun","name":"导论"},{"id":"ch1","name":"第一章"},{"id":"ch2","name":"第二章"},{"id":"ch3","name":"第三章"},{"id":"ch4","name":"第四章"},{"id":"ch5","name":"第五章"},{"id":"ch6","name":"第六章"},{"id":"ch7","name":"第七章"}],"questions":[{"stem":"马克思主义是","options":{"A":"马克思和恩格斯创立并为继承者在实践中不断发展着的马克思主义。","B":"马克思和恩格斯创立的哲学和政治经济学的理论体系。","C":"马克思和恩格斯创立的科学社会主义和政治经济学的理论体系。","D":"马克思和恩格斯创立的政治经济学和哲学的理论体系。"},"answer":"A","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_1"},{"stem":"1844年8月底，马克思和恩格斯在巴黎会面。这次会面使他们发现彼此的基本观点完全一致，于是开始了在科学理论研究和革命活动中的长期合作。马克思和恩格斯首次系统阐述历史唯物主义基本观点的著作是","options":{"A":"《神圣家族》","B":"《德意志意识形态》","C":"《哲学的贫困》","D":"《共产党宣言》"},"answer":"B","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_2"},{"stem":"马克思主义最根本的世界观和方法论是","options":{"A":"科学社会主义理论","B":"政治经济学理论","C":"辩证唯物主义和历史唯物主义","D":"阶级斗争学说"},"answer":"C","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_3"},{"stem":"马克思主义最鲜明的政治立场是","options":{"A":"推翻资本主义制度","B":"建立无产阶级专政","C":"实现共产主义","D":"致力于实现以劳动人民为主体的最广大人民的根本利益"},"answer":"D","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_4"},{"stem":"马克思主义哲学的直接理论来源是","options":{"A":"英国古典政治经济学","B":"法国空想社会主义","C":"德国古典哲学","D":"法国哲学"},"answer":"C","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_5"},{"stem":"马克思主义鲜明特征概括起来是","options":{"A":"阶级性和人民性的统一","B":"革命性和科学性的统一","C":"实践性和发展性的统一","D":"科学性和发展性的统一"},"answer":"B","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_6"},{"stem":"马克思主义产生的经济根源是","options":{"A":"工业革命","B":"资本主义经济危机","C":"阶级斗争","D":"资本主义生产力和生产关系的矛盾运动"},"answer":"D","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_7"},{"stem":"马克思、恩格斯进一步发展和完善了的英国古典政治经济学理论是","options":{"A":"辩证法","B":"历史观","C":"劳动价值论","D":"剩余价值论"},"answer":"C","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_8"},{"stem":"马克思主义产生的阶级基础和实践基础是","options":{"A":"资本主义的剥削和压迫","B":"无产阶级作为一支独立的政治力量登上了历史舞台","C":"工人罢工和起义","D":"工人运动得到了“农民的合唱”"},"answer":"B","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_9"},{"stem":"“哲学把无产阶级当做自己的物质武器，同样，无产阶级也把哲学当做自己的精神武器”，这一论断的含义是","options":{"A":"马克思主义是无产阶级的世界观和方法论","B":"哲学的存在方式是物质","C":"无产阶级掌握哲学就由自在阶级转变为自为阶级","D":"无产阶级的存在方式是哲学"},"answer":"A","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_10"},{"stem":"马克思、恩格斯始终站在革命斗争的最前沿,他们的一生是为推翻旧世界,建立新世界 而不息战斗的一生。马克思恩格斯领导创建的世界上第一个无产阶级政党是","options":{"A":"国际工人协会","B":"正义者联盟","C":"共产主义者同盟","D":"社会主义工人国际"},"answer":"C","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_11"},{"stem":"在19世纪三大工人运动中,集中反映工人阶级政治要求的是","options":{"A":"法国里昂工人起义","B":"英国宪章运动","C":"芝加哥工人起义","D":"德国西里西亚纺织工人起义"},"answer":"B","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_12"},{"stem":"1848年2月，（ ）的发表，标志着马克思主义的公开问世。","options":{"A":"《自然辩证法》","B":"《神圣家族》","C":"《共产党宣言》","D":"《资本论》"},"answer":"C","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_13"},{"stem":"1871年，巴黎工人起义并成立巴黎公社，马克思代表第一国际写出了著名的（ ），高度赞扬了巴黎工人的伟大创举。","options":{"A":"《法兰西内战》","B":"《资本论》","C":"《共产党宣言》","D":"《反杜林论》"},"answer":"A","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_14"},{"stem":"科学社会主义从理论变为现实的标志是（ ）。","options":{"A":"巴黎公社","B":"俄国十月革命的胜利","C":"中国新民主主义革命的胜利","D":"世界反法西斯战争的胜利"},"answer":"B","chapter":"导论","subject":"marx","type":"single","id":"marx_导论_single_15"},{"stem":"作为一个完整的科学体系，马克思主义理论体系的三个主要组成部分是","options":{"A":"马克思主义政治学","B":"马克思主义政治经济学","C":"科学社会主义","D":"马克思主义哲学"},"answer":"BCD","chapter":"导论","subject":"marx","type":"multi","id":"marx_导论_multi_1"},{"stem":"马克思主义的直接理论来源是","options":{"A":"德国古典哲学","B":"英国古典政治经济学","C":"法国、英国的空想社会主义","D":"法国启蒙思想"},"answer":"ABC","chapter":"导论","subject":"marx","type":"multi","id":"marx_导论_multi_2"},{"stem":"马克思、恩格斯最重要的理论贡献是","options":{"A":"辩证法","B":"劳动价值理论","C":"唯物史观","D":"剩余价值学说"},"answer":"CD","chapter":"导论","subject":"marx","type":"multi","id":"marx_导论_multi_3"},{"stem":"马克思主义的基本特征是","options":{"A":"科学性","B":"人民性","C":"实践性","D":"发展性"},"answer":"ABCD","chapter":"导论","subject":"marx","type":"multi","id":"marx_导论_multi_4"},{"stem":"19世纪法国和英国空想社会主义最有代表性的人物是（ ）。","options":{"A":"昂利·圣西门","B":"沙尔·傅立叶","C":"罗伯特·欧文","D":"托马斯·莫尔"},"answer":"ABC","chapter":"导论","subject":"marx","type":"multi","id":"marx_导论_multi_5"},{"stem":"指导中国社会主义建设的理论基础是马克思恩格斯创立的马克思主义。（  ）","answer":"B","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_1"},{"stem":"社会主义从空想到科学在人类思想史上具有划时代的意义。（  ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_2"},{"stem":"《德意志意识形态》首次系统阐述了历史唯物主义的基本观点。（ ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_3"},{"stem":"马克思主义哲学是马克思、恩格斯将黑格尔的辩证法和费尔巴哈的唯物主义结合在一起的产物。（  ）","answer":"B","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_4"},{"stem":"马克思主义无差别地代表一切人的利益。（  ）","answer":"B","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_5"},{"stem":"马克思主义政治经济学是对英国古典政治经济学的继承。（  ）","answer":"B","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_6"},{"stem":"列宁对社会主义革命学说的重大贡献是提出了社会主义革命可以在经济文化比较落后的国家首先取得胜利的理论。（  ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_7"},{"stem":"在第一次世界大战中成为东西方矛盾焦点和帝国主义政治体系最薄弱环节的国家是俄国。（  ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_8"},{"stem":"恩格斯写出了《反杜林论》，全面阐述了马克思主义理论体系。（ ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_9"},{"stem":"在实践的基础上马克思主义实现了革命性和科学性的统一。（  ）","answer":"A","chapter":"导论","subject":"marx","type":"judge","id":"marx_导论_judge_10"},{"stem":"什么是马克思主义？马克思主义具有哪些基本的特征？","answer":"","chapter":"导论","subject":"marx","type":"short","id":"marx_导论_short_1"},{"stem":"空想社会主义与科学社会主义的根本区别是什么？","answer":"","chapter":"导论","subject":"marx","type":"short","id":"marx_导论_short_2"},{"stem":"恩格斯认为，全部哲学、特别是近代哲学的重大的基本问题是","options":{"A":"哲学与人类生存活动之间的内在联系问题","B":"人与周围世界的基本联系问题","C":"思维和存在的关系问题","D":"关于人的本质问题"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_1"},{"stem":"对哲学基本问题第一方面的不同回答是划分（ ）的标准","options":{"A":"唯物主义和唯心主义","B":"辩证法和形而上学","C":"可知论与不可知论","D":"一元论和二元论"},"answer":"A","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_2"},{"stem":"对哲学基本问题第二个方面的不同回答是划分( )的标准","options":{"A":"唯物主义和唯心主义","B":"反映论和先验论","C":"可知论和不可知论","D":"唯物史观和唯心史观"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_3"},{"stem":"“旧唯物主义是半截子的唯物主义”，这是指","options":{"A":"旧唯物主义是形而上学的唯物主义","B":"旧唯物主义在社会历史观上是唯心主义","C":"旧唯物主义是机械唯物主义","D":"旧唯物主义割裂了运动与静止的辩证法"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_4"},{"stem":"从哲学基本问题的角度看，物质的唯一特性是","options":{"A":"运动性","B":"客观实在性","C":"不可分性","D":"时空性"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_5"},{"stem":"古希腊米利都学派的代表人物泰勒斯提出了 “水是万物的本原” 的论点，春秋时代《管子》书中的《水地》篇中也表述了 “水是万物的根源 ” 的学说。上述观点","options":{"A":"是完全正确的，属于辩证唯物主义的观点","B":"不符合客观实际，属于唯心主义的观点","C":"是古代朴素唯物主义的观点，既具有合理性和进步性，又具有明显的局限性","D":"否认了意识是物质的产物和反映"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_6"},{"stem":"鲁迅说 :“天才们无论怎样说大话，归根结底，还是不能凭空创造。描神画鬼，毫无对证，本可以专靠了神思，所谓‘天马行空 ’似的挥写了，然而他们写出来的，也不过是三只眼，长脖子，就是在常见的人体上，增加了眼睛一只，增长了颈子二三尺而已。” 这表明","options":{"A":"一切要从实际出发","B":"人具有主观能动性","C":"任何观念都是对客观存在的真实反映","D":"事物之间是普遍联系的"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_7"},{"stem":"马克思主义认为世界的真正统一性在于它的","options":{"A":"实践性","B":"运动性","C":"物质性","D":"矛盾性"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_8"},{"stem":"人工智能的出现对马克思主义哲学意识论的意义是","options":{"A":"否定了物质对意识的决定作用","B":"改变了人类意识活动的规律性","C":"肯定了人工智能可以代替意识的能动活动","D":"丰富了物质与意识相互关系内容"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_9"},{"stem":"辩证的同一是","options":{"A":"指事物与其自身完全等同","B":"不包含差别的绝对同一","C":"以差别、对立为前提的同一","D":"不包含否定因素的同一"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_10"},{"stem":"区分新旧事物的标志在于看它们","options":{"A":"是不是在新的历史条件下出现的","B":"是不是符合事物发展规律.具有强大的生命力","C":"是不是有新形式和新特点","D":"是不是得到大多数人的承认"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_11"},{"stem":"物质的唯一特性是","options":{"A":"永恒性","B":"客观实在性","C":"可知性","D":"不可知性"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_12"},{"stem":"黑格尔说，割下来的手就不是真正的人手了。这句话表达的哲学道理是","options":{"A":"承认世界的统一性","B":"承认世界的本原是物质的","C":"否认联系的形而上学观点","D":"承认普遍联系的辩证法观点"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_13"},{"stem":"辩证唯物主义认为，度是","options":{"A":"事物的质量和数量的界限","B":"事物保持其质的稳定性的数量界限","C":"事物保持其量的稳定性的范围","D":"事物发生变化的关节点"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_14"},{"stem":"辩证法的否定即“扬弃”，它的含义是指","options":{"A":"抛弃","B":"事物中好的方面和坏的方面的组合","C":"纯粹的否定","D":"既克服又保留"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_15"},{"stem":"运动是物质","options":{"A":"内在本质","B":"外部表现","C":"唯一特性","D":"根本属性"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_16"},{"stem":"“人不能两次踏进同一条河流\"和“人一次也不能踏进同一条河流\"这两种观点是","options":{"A":"前者是辩证法，后者是诡辩论","B":"前者是形而上学，后者是辩证法","C":"是相同的，只是强调的方面不同","D":"二者都是辩证法，后者是对前者的发展"},"answer":"A","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_17"},{"stem":"时间和空间是","options":{"A":"物质的两种根本属性","B":"物质运动之外的两种存在物","C":"运动着的物质的存在形式","D":"人的感性直观的先天形式"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_18"},{"stem":"从动物心理发展到人类意识起决定作用的是","options":{"A":"人脑的形成","B":"语言的产生","C":"生产劳动","D":"文明的发展"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_19"},{"stem":"“观念的东西不外是移入人的头脑并在人的头脑中改造过的物质的东西而已”，这个命题表明：","options":{"A":"人脑是意识的器官和源泉","B":"意识是客观存在的主观映象","C":"意识是人脑产生的特殊物质","D":"观念和物质没有本质的区别"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_20"},{"stem":"中国古代哲学家荀子说：“心不在焉，则白黑在前而目不见，雷鼓在侧而耳不闻。” 这段话表明人的意识具有","options":{"A":"客观性","B":"能动性","C":"对象性","D":"任意性"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_21"},{"stem":"哲学上的一元论，就是认为","options":{"A":"世界是物质的","B":"世界是精神的","C":"世界是发展的","D":"世界是统一的"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_22"},{"stem":"辩证法和形而上学的根本分歧在于是否承认","options":{"A":"事物是客观存在的","B":"事物是普遍联系的","C":"事物是运动发展的","D":"内部矛盾是事物发展的动力"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_23"},{"stem":"矛盾的基本属性是","options":{"A":"普遍性和特殊性","B":"绝对性和相对性","C":"变动性和稳定性","D":"斗争性和同一性．"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_24"},{"stem":"习近平指出，要学习掌握事物矛盾运动的基本原理，不断强化问题意识，积极面对和化解前进中遇到的矛盾。在工作中，我们既要注重总体谋划，又要注重牵住“牛鼻子”。从哲学上讲，“既要注重总体谋划，又要注重牵住‘牛鼻子’”这句话体现的是","options":{"A":"要坚持矛盾斗争性和同一性的统一","B":"要坚持量变与质变的辩证关系","C":"要正确把握整体与部分的不同功能","D":"要坚持两点论和重点论的统一"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_25"},{"stem":"“鸡蛋从外面打破是食物，从内部打破是生命”，从哲学上讲，这说明","options":{"A":"外因必须通过内因起作用","B":"辩证否定是事物内部矛盾运动的结果","C":"真理是主观性和相对性的辩证统一","D":"必然产生于事物内部的根本矛盾"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_26"},{"stem":"否定之否定规律在","options":{"A":"事物经过一次辩证否定后才表现出来","B":"事物完成一个发展周期后完整地表现出来","C":"事物发展的任何阶段上表现出来","D":"事物经过量变向质变的转化后表现出来"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_27"},{"stem":"矛盾问题的精髓是","options":{"A":"矛盾的普遍性和特殊性关系的问题","B":"矛盾的同一性和斗争性关系的问题","C":"主要矛盾和次要矛盾关系的问题","D":"矛盾的主要方面和次要方面关系的问题"},"answer":"A","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_28"},{"stem":"庄子说：“是亦彼也，彼亦是也”。这个命题的哲学思想是","options":{"A":"辩证法的","B":"承认事物的内在联系的","C":"否认事物差别的诡辩论观点","D":"将事物差别绝对化的形而上学观点"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_29"},{"stem":"做事情时要区分可能性和不可能性，两者的区别在于","options":{"A":"人的主观努力程度","B":"对人是否有利","C":"现实中有无根据和条件","D":"现实中的根据和条件是否充分"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_30"},{"stem":"“哲学史宛如色彩斑斓的壁毯，其中唯物主义与唯心主义犹如浓粗的经线贯穿上下，而辩证法与形而上学如同纬纱交织其中。”关于这句话，以下说法正确的是","options":{"A":"唯物主义就是辩证法","B":"唯心主义就是形而上学","C":"唯物主义、唯心主义和辩证法、形而上学是对哲学基本问题两个方面的不同回答","D":"唯物主义与唯心主义的对立和斗争中交织着辩证法与形而上学的对立和斗争"},"answer":"D","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_31"},{"stem":"传统职业被人工智能替代，早已不是科幻小说的情节。例如，无人驾驶就让卡车司机顾虑重重，不少拥有清晰评估标准、工作业绩可衡量的职业也面临机器换人的可能。据一份报告显示，到2033年，美国将会有47％的工作被人工智能取代，其中比例最高的就是电话营销员、保险业务员、运动裁判员等。甚至微软机器诗人“小冰”还出版了诗集，尽管众人对其作品所见不一，但这件事说明如写诗、作曲这类依赖灵感的创造性工作也正在受到人工智能的挑战。以上材料说明","options":{"A":"人工智能可以模拟和扩展人脑的某些活动","B":"人工智能已经具备情感、信念、意志等人类意识形式","C":"机器人已经可以从事某些实践活动","D":"人们已经完全认识了大脑的机能"},"answer":"A","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_32"},{"stem":"法国生命哲学家柏格森十分强调运动变化，以至他的哲学被称为“变的哲学”。在柏格森看来，“事物和状态不过是我们的心灵所采取的一种观点，事物是不存在的，存在的只有动作。”这句话的错误在于否认了","options":{"A":"世界万物是永恒发展的","B":"运动形式具有多样性","C":"物质是运动的承担者","D":"运动是事物的存在方式和唯一属性"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_33"},{"stem":"民间有一种迷信说法叫作“喜鹊叫喜，乌鸦叫丧”。这句话的错误在于否定了联系的","options":{"A":"普遍性","B":"多样性","C":"客观性","D":"条件性"},"answer":"C","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_34"},{"stem":"“君子以思患而豫防之”，有备才能无患。党的十八大以来，习近平总书记十分重视底线思维，强调凡事不能超越底线。如法律底线、政策底线、利益底线、道德底线等，一旦被突破，就会出现无法接受的坏结果。从哲学的角度分析，底线是指","options":{"A":"联系的条件性","B":"度的关节点","C":"主要矛盾","D":"事物发展的连续性"},"answer":"B","chapter":"第一章","subject":"marx","type":"single","id":"marx_第一章_single_35"},{"stem":"马克思主义哲学“物质观”的提出给人们认识什么是物质带来了一场根本性的变革。其突出表现包括","options":{"A":"物质的唯一特性是客观实在性","B":"人类的实践活动也是物质的一种形态","C":"物质是各种具体实物的总和","D":"人类社会也是物质的一种形态"},"answer":"ABD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_1"},{"stem":"主观能动性和客观规律性的关系表现在","options":{"A":"不怕做不到，就怕想不到","B":"客观规律限制了主观能动性的发挥","C":"只有发挥主观能动性才能认识和利用客观规律","D":"只有尊重客观规律才能充分发挥主观能动性"},"answer":"CD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_2"},{"stem":"2017年6月，我国科学家利用“墨子号”量子科学实验卫星在国际上率先成功实现了千公里级的星地双向量子纠缠分发。“量子纠缠”就是两个(或多个)粒子共同造成的量子状态，无论粒子之间相隔多远，测量其中一个粒子必然会影响其他粒子。“量子纠缠”现象虽然未被完全认知，但它仍然能够说明","options":{"A":"世界的真正统一性在于它的物质性","B":"事物联系的主观性和偶然性","C":"事物联系的复杂性和多样性","D":"物质世界联系的客观性和普遍性"},"answer":"ACD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_3"},{"stem":"目前，科学家首次精确发现人类大脑记忆是如何形成的。即人脑内侧颞叶负责自觉回忆体验事件和场景情节，在形成新的记忆内容时，神经细胞会在精确的时间产生激活，开始回忆之前曾看到过的物品或情景。这表明","options":{"A":"意识是物质世界长期发展的产物","B":"大脑是产生意识的生理基础","C":"意识是客观存在的主观映像","D":"意识是人脑的机能和属性"},"answer":"ABD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_4"},{"stem":"列宁说 :“物质是标志客观实在的哲学范畴,这种客观实在是人通过感觉感知的,它不依赖于我们的感觉而存在,为我们的感觉所复写、摄影、反映。 ”其含义是","options":{"A":"物质的共同特性是客观实在性","B":"物质是标志客观实在的哲学范畴","C":"物质这一客观实在是可以认识的对象","D":"物质是看得见、摸得着的"},"answer":"ABC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_5"},{"stem":"人类历史上的每一次科技革命都与材料的发展息息相关，而新材料的研制却是颇为不易的。人工智能可以借助数据共享，对先进材料的物理化学性质进行预测、筛选，从而加快新材料的合成和生产。作为人工智能的一个分支，机器学习算法在辅助新材料设计时尤为“得力”，其工作过程主要包括“描述符”生成、模型构建和验证、材料预测、实验验证等步骤。人工智能辅助新材料研发的过程表明（ ） 科学研究能够任意改变物质的性质和结构","options":{"B":"人工智能能够取代人类对物质世界的认识","C":"人类对于物质的认识是一个不断深化的过程","D":"具体的物质结构和性质的变化并不改变世界的物质性"},"answer":"CD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_6"},{"stem":"马克思在《1844年经济学哲学手稿》中指出：“生产生活就是类生活，这是产生生命的生活。一个种的整体特性、种的类特性就在于生命活动的性质，而自由的有意识的活动恰恰就是人的类特性。”从意识的本质来看","options":{"A":"意识是一种特殊的物质","B":"意识来源于人脑","C":"意识在形式上是主观的","D":"意识是客观世界的主观映象"},"answer":"CD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_7"},{"stem":"唯物辩证法的总特征是","options":{"A":"联系的观点","B":"矛盾的观点","C":"发展的观点","D":"辨证否定的观点"},"answer":"AC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_8"},{"stem":"建立在大数据与不断升级的各种算法技术基础上的现代人工智能，正在深刻影响当代人类生活。但是，即使是最先进的智能机器，也达不到人类智能的层级，无法真正具有人的意识，不可能取代或超越人类智能。这是因为","options":{"A":"人工智能不具备情感、信念、意志等人的意识形式。","B":"人工智能不可能真正具备人类的社会属性","C":"人工智能难以完全具备理解自然语言真实意义的能力","D":"人脑中总有许多东西是人工智能无法化约的"},"answer":"ABCD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_9"},{"stem":"下列选项中，体现发展的实质的有","options":{"A":"因祸得福，祸福相依","B":"无产阶级专政代替资产阶级专政","C":"培育出新优质品种","D":"原始社会的公有制经过私有制到社会主义的公有制"},"answer":"BCD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_10"},{"stem":"马克思指出 :“批判的武器当然不能代替武器的批判,物质的力量只能用物质的力量来摧毁,但是理论一经掌握群众,也会变成物质的力量 ”,这说明","options":{"A":"思想观念的革命可以彻底解决社会问题","B":"对客观世界的批判和改造必须依靠物质力量来实现","C":"理论和精神可以通过群众转化为物质力量","D":"人的意识不仅反映客观世界,并且通过实践改变和创造客观世界"},"answer":"BCD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_11"},{"stem":"辩证的否定是","options":{"A":"事物的自我否定","B":"事物发展的环节","C":"事物联系的环节","D":"既克服又保留"},"answer":"ABCD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_12"},{"stem":"“揠苗助长”却事与愿违，“庖丁解牛”则事半功倍。这两则结果不同的寓言故事共同说明的哲学道理有","options":{"A":"不同的人对同一事物的规律有不同的反映","B":"人具有主观能动性，可以改变和利用客观规律","C":"发挥主观能动性必须以尊重规律为前提","D":"物质决定意识，意识对物质具有巨大的反作用"},"answer":"CD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_13"},{"stem":"互联网公司的合并重组潮中，从优酷土豆、滴滴快的的合并，到58同城战略入股赶集网，都诠释了解决矛盾的一种方式。解决矛盾的形式有","options":{"A":"矛盾双方同归于尽","B":"这矛盾一方克服另一方","C":"矛盾双方形成协同运动的新形式","D":"矛盾双方融合成一个新事物"},"answer":"ABCD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_14"},{"stem":"《国语·郑语》中有一句话：“夫和实生物，同则不继。以他平他谓之和，故能丰长而物旧之。若以同裨同，尽乃弃矣。”这句话蕴含的辩证法思想有","options":{"A":"矛盾的同一是包含差别的同一","B":"对立面的统一是事物发展的动力","C":"不包含内部差别的事物就不能存在和发展","D":"矛盾的一方只有克服另一方才能达到统一"},"answer":"ABC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_15"},{"stem":"某地充分挖掘丰富的稻田资源，大力推广稻渔综合种养，助农增收致富。农民采用新的耕作模式后，稻为鱼提供遮阴和有机物质，鱼游动促进了稻床通风透气，加上鱼类不断翻动泥土，让稻田水不断充氧，同时鱼的排泄物为禾苗提供了有机肥料，从而促进了禾苗的生根分蘖和扬花抽穗，升级后的稻田综合种养显现了“稻好鱼肯定多，鱼多稻肯定好”的良性循环效应。采用这种种养方式的稻田不施化肥农药，出产的生态稻米口感好、价格高，既保护了自然环境又实现了农民的增收。“稻田养鱼”给我们的启示有","options":{"A":"事物之间有其固有的客观联系","B":"人们可以发现并利用规律来实现自己的目的","C":"顺应自然就是不要对自然的事物做任何改动","D":"实现人与自然的和谐统一需要正确的实践方式"},"answer":"ABD","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_16"},{"stem":"物联网是通过信息传感设备将各种物品与互联网连接起来，实现物品的自动识别、定位、跟踪、控制和信息的互联共享。近几年来，物联网技术开始越来越广泛地应用于经济和社会生活之中。这表明","options":{"A":"人们可以根据自己的主观要求创造事物间的联系","B":"联系具有普遍性，事物之间的联系形式是多样的","C":"人类可以根据事物固有的联系建立新的具体联系","D":"事物间的联系因具有“人化”的特点进而主观化"},"answer":"BC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_17"},{"stem":"“一语不能践，万卷徒空虚”，在“不忘初心、牢记使命”主题教育工作会议上，习近平强调力戒形式主义、官僚主义。2019年3月，中共中央办公厅发出《关于解决形式主义突出问题为基层减负的通知》，一针见血地指出了当前不少困扰基层的形式主义问题。从哲学的角度分析，之所以要反对形式主义，是因为","options":{"A":"内容决定形式，形式是为内容服务的","B":"形式脱离内容就失去了自己存在的价值和意义","C":"当内容相对稳定时，形式对于内容是可有可无的","D":"同一内容可以有多种形式，而同一种形式无法表现不同的内容"},"answer":"AB","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_18"},{"stem":"列宁曾经把现象比作河水上面的泡沫，而把本质比作下面的深流。这一比喻形象地说明了本质与现象的关系，以下说法正确的有","options":{"A":"本质只能通过理性思维才能把握","B":"现象离不开本质，但本质可以离开现象","C":"现象是多变的，本质是相对稳定的","D":"真象和本质是同一的，假象和本质不是同一的"},"answer":"AC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_19"},{"stem":"钱钟书在《围城》中写道：“天下就没有偶然，那不过是化了妆的、戴了面具的必然。”“偶然是化了妆的必然”的哲理在于","options":{"A":"没有纯粹的偶然","B":"偶然和必然产生和形成的原因相同","C":"偶然背后隐藏着必然","D":"偶然是不存在的"},"answer":"AC","chapter":"第一章","subject":"marx","type":"multi","id":"marx_第一章_multi_20"},{"stem":"系统化理论化的世界观和方法论就是哲学。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_1"},{"stem":"和谐意味着矛盾消失了。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_2"},{"stem":"唯物主义是可知论，唯心主义是不可知论。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_3"},{"stem":"物质就是具体存在的事物。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_4"},{"stem":"既然人脑是产生意识的器官，那么意识的发展都可以还原为物理化学过程。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_5"},{"stem":"鬼神观念和错误的认识也是对客观世界的反映。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_6"},{"stem":"质变比量变更重要。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_7"},{"stem":"否定就是新旧事物之间“一刀两断”。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_8"},{"stem":"新出现的事物就是发展的表现。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_9"},{"stem":"矛盾的同一性是指矛盾双方没有差别和对立。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_10"},{"stem":"科学是研究必然性的，所以偶然性是科学的敌人。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_11"},{"stem":"假象是客观存在的现象，也反映事物的本质。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_12"},{"stem":"静止是运动的特殊状态。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_13"},{"stem":"发展是数量的增减、场所的变更。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_14"},{"stem":"事物的根本性质暂时不变是相对静止的一种表现形式。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_15"},{"stem":"人工智能的出现，意味着人的意识可以脱离人脑而存在。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_16"},{"stem":"存在就是被感知。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_17"},{"stem":"人的意识不仅是自然界长期发展的产物，而且是社会历史发展的产物。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_18"},{"stem":"内容决定形式，所以一种内容只能有一种形式与之相适应。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_19"},{"stem":"时空是与物质运动无关、而单独存在的。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_20"},{"stem":"宇宙间的一切都是相互关联的，整个宇宙不过是一系列原因结果的无穷链条。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_21"},{"stem":"人工智能是人的意识能动性的一种特殊表现，是人的本质力量的对象化、现实化。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_22"},{"stem":"辩证矛盾就是逻辑矛盾。（     ）","answer":"B","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_23"},{"stem":"物、物质，无非是各种物的总和，而这个概念就是从这一总和中抽象出来的。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_24"},{"stem":"世界不是既成事物的集合体，而是过程的集合体。（     ）","answer":"A","chapter":"第一章","subject":"marx","type":"judge","id":"marx_第一章_judge_25"},{"stem":"简述辩证唯物主义的物质定义及其意义。","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_1"},{"stem":"意识的本质及其能动作用是什么？","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_2"},{"stem":"简述主要矛盾和次要矛盾及其辩证关系？","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_3"},{"stem":"简述矛盾的普遍性和特殊性及其相互关系。","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_4"},{"stem":"简述量变与质变的辩证关系。","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_5"},{"stem":"简述辩证否定观的基本内容。","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_6"},{"stem":"简述矛盾同一性、斗争性在事物发展中的作用","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_7"},{"stem":"如何正确处理发挥人的主观能动性与尊重客观规律性的关系？","answer":"","chapter":"第一章","subject":"marx","type":"short","id":"marx_第一章_short_8"},{"stem":"自由王国是指人们","options":{"A":"处于绝对自由的动物世界","B":"彻底摆脱自然规律和社会规律的神仙世界","C":"通过自由竞争实现帕累托最优的自由市场","D":"能够利用既定的自然规律和社会规律，消灭奴役和剥削的社会形态"},"answer":"D","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_1"},{"stem":"马克思主义认为实践是","options":{"A":"主体与客体通过中介相互作用的过程","B":"主体创造客体的活动","C":"主体适应客观环境的活动","D":"作为主体的人的日常活动"},"answer":"A","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_2"},{"stem":"实践主体和客体相互作用的关系，最根本的是","options":{"A":"认识关系","B":"实践关系","C":"价值关系","D":"辩证关系"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_3"},{"stem":"“世界不会满足人，人决心以自己的行动来改变世界。”这句话体现的是实践基本特征中的","options":{"A":"自觉能动性","B":"物质性","C":"客观性","D":"社会历史性"},"answer":"A","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_4"},{"stem":"从物到感觉和思想与从思想和感觉到物的对立，反映的是","options":{"A":"可知论和不可知论的对立","B":"经验论和唯理论的对立","C":"唯物主义反映论与唯心主义先验论的对立","D":"形而上学与辩证法的对立"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_5"},{"stem":"“社会上一旦有技术上的需要，则这种需要会比十所大学更能把科学推向前进。”这说明","options":{"A":"自然科学是认识发展的动力","B":"技术推动了科学的发展","C":"实践是认识发展的动力","D":"科学进步是实践的目的"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_6"},{"stem":"在人与客观规律的关系问题上,人的主观能动性表现在","options":{"A":"人可以创造客观规律","B":"人可以改变客观规律","C":"人可以认识和利用客观规律","D":"人可以消灭客观规律"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_7"},{"stem":"近年来，为了向更多人更好地传播科学、艺术、文化等知识，许多地方把博物馆搬到了线上，借助技术手段，让知识可感、可视。通过虚拟现实技术。游览者可以与展品“零距离”接触。线上博物馆的发展说明","options":{"A":"精神文化的生产是一个纯粹的意识过程","B":"科学文化实践只能通过虚拟实践的方式实现","C":"实践的发展过程是一个范围不断扩大、程度不断加深、效果不断提升的过程","D":"认识关系是实践的主体和客体相互作用关系中最根本的关系"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_8"},{"stem":"古希腊的怀疑论者们强调说对同一事物,不同的人感觉是不同的,如同一盆水,有人感觉说温,有人感觉说凉。这说明","options":{"A":"世界的真实状况是人们无法知道的","B":"认识结果与外部世界无关","C":"认识具有主体差异性","D":"认识具有客观性"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_9"},{"stem":"两条根本对立的认识路线是","options":{"A":"可知论与不可知论的对立","B":"革命能动的反映论与直观被动的反映论的对立","C":"辩证法与形而上学的对立","D":"唯物主义反映论与唯心主义先验论的对立"},"answer":"D","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_10"},{"stem":"把经过实践检验的理论看成绝对真理,并当作检验其他一切认识真理性的标准,这是一种","options":{"A":"形而上学的观点","B":"唯物辩证法的观点","C":"相对主义的观点","D":"经验论的观点"},"answer":"A","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_11"},{"stem":"习近平形象地指出：“要按照已经认识到的规律来办，在实践中再加深对规律的认识，而不是脚踩西瓜皮，滑到哪里算哪里。”这句话说明","options":{"A":"先有认识后有实践","B":"认识是实践的基础","C":"正确的认识才能指导实践取得成功","D":"实践是盲目的"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_12"},{"stem":"列宁指出 :“只要再多走一小步,哪怕是向同一方向迈的一小步,真理便会变成谬误。” 这句话表明","options":{"A":"真理和谬误是认识的两个阶段","B":"真理和谬误没有确定的区别","C":"真理具有相对性","D":"真理的标准是双重的"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_13"},{"stem":"任何科学理论都不能穷尽真理,而只能在实践中不断开辟认识真理的道路。这说明","options":{"A":"真理具有绝对性","B":"真理具有客观性","C":"真理具有相对性","D":"真理具有全面性"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_14"},{"stem":"“追求真理比占有真理更宝贵。”德国诗人莱辛的这一著名诗句所蕴含的哲理是","options":{"A":"认识经历着从感性认识到理性认识的发展","B":"认识的根本目的是透过现象认识本质","C":"改造世界比认识世界更重要","D":"认识过程不能停滞，而应该不断扩展和深化"},"answer":"D","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_15"},{"stem":"实践是检验真理的唯一标准，因为实践是一种","options":{"A":"具有客观现实性的活动","B":"客观见之于主观的活动","C":"具有自觉能动性的活动","D":"具有社会历史性的活动"},"answer":"A","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_16"},{"stem":"实践作为检验真理的标准，既是确定的又是不确定的，其不确定性是因为","options":{"A":"有些真理是根本无法过实践来加以检验的","B":"任何实践检验都需要一定的逻辑证明作为其补充的手段","C":"作为检验真理标准的实践总要受到各种条件的限制","D":"不同的人、不同的阶级各有其不同的实践标准"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_17"},{"stem":"真理与价值统一的基础是","options":{"A":"认识","B":"科研","C":"创新","D":"实践"},"answer":"D","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_18"},{"stem":"（ ）是人类生存和发展最基本的活动，是人类社会生活的本质，是人的认识产生和发展的基础，也是真理与价值统一的基础。","options":{"A":"实践","B":"物质","C":"规律","D":"真理"},"answer":"A","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_19"},{"stem":"实践基础上的理论创新，是","options":{"A":"决定着社会的发展趋势","B":"社会发展和变革的先导","C":"决定着社会的变革力度","D":"国家兴旺发达的不竭动力"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_20"},{"stem":"“必然王国”和“自由王国”是历史性的概念，它是指社会活动的","options":{"A":"两条不同的道路","B":"两个不同的模式","C":"两种不同的选择","D":"两种不同的状态"},"answer":"D","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_21"},{"stem":"轻视感性认识而片面夸大理性认识的作用，会导致","options":{"A":"宿命论","B":"唯理论","C":"诡辩论","D":"经验论"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_22"},{"stem":"“生活中从不缺少美，而是缺少发现美的眼睛。”从马克思主义哲学的角度，对这句话的正确理解是","options":{"A":"客观事物的存在取决于主体的感知","B":"非理性因素在感性认识中起决定性作用","C":"认识是主体与客体相互作用的过程和结果","D":"人的感觉器官的选择性是人的认识能力的界限"},"answer":"C","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_23"},{"stem":"天空繁星密布，而首先成为天文学研究对象的是与人们确定季节关系密切的星体；地球上的生物品种难以计数，而人们首先研究的还是与农业和畜牧业有关的为数不多的植物和动物。这说明","options":{"A":"实践是认识的起点，认识是实践的归宿","B":"实践的需要推动着认识的发展","C":"实践锻炼和提高了主体的认识能力","D":"科学研究具有相对独立性"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_24"},{"stem":"同一个物理学规律可以用不同的数学公式或语言文字的形式加以表述，而这一规律本身不会随之改变。这说明","options":{"A":"真理标准是确定性与不确定性的统一","B":"真理表达形式的多样性并不否认真理内容的客观性","C":"真理本身就是客观事物","D":"真理的绝对性寓于真理的相对性之中"},"answer":"B","chapter":"第二章","subject":"marx","type":"single","id":"marx_第二章_single_25"},{"stem":"马克思说 :“批判的武器当然不能代替武器的批判,物质的力量只能用物质力量来摧毁。但是理论一经群众掌握,也会变成物质力量。 ”该论断所包含的思想是","options":{"A":"理论需要中介以介入历史的运动","B":"理论不能代替实践","C":"理论对实践具有指导作用","D":"理论在任何条件下都不能改造世界"},"answer":"ABC","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_1"},{"stem":"“单凭观察所得的经验，是绝不能充分证明必然性的，这是如此正确，以至于不能从太阳总是在早晨升起来判断它明天会再升起。”恩格斯这段话的含义是","options":{"A":"感性认识有待于上升为理性认识","B":"感性认识具有局限性","C":"事物的必然性与感性经验毫无关系","D":"归纳方法不是万能的"},"answer":"ABD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_2"},{"stem":"实践的基本特征有","options":{"A":"客观实在性","B":"自觉能动性","C":"社会历史性","D":"主观随意性"},"answer":"ABC","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_3"},{"stem":"认识的发展过程经历两次飞跃：第一次飞跃是由实践到认识，第二次飞跃是从认识到实践的飞跃，这是认识过程中更为重要的一次飞跃。下列关于两次飞跃的论述正确的是","options":{"A":"感性认识与理性认识的基础都是实践","B":"认识的第一次飞跃必须经过理性思维的作用","C":"认识的第二次飞跃必须坚持理论与实际相结合的原则","D":"理论必须被群众所掌握，才能转化为改造社会、改造自然的物质力量"},"answer":"ABCD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_4"},{"stem":"理性认识的形式有","options":{"A":"表象","B":"概念","C":"判断","D":"推理"},"answer":"BCD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_5"},{"stem":"下列观点错误的是","options":{"A":"有用即真理","B":"真理和谬误没有绝对的界限","C":"谎言说一百遍就变成真理","D":"真理具有一元性"},"answer":"AC","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_6"},{"stem":"毛泽东在《反对本本主义》一文中谈道，“马克思主义的“本本”是要学习的，但是必须同我国的实际情况相结合。我们需要“本本”，但是一定要纠正脱离实际情况的本本主义”“必须洗刷唯心精神”。本本主义和教条主义的错误根源在于","options":{"A":"过分强调理性认识忽视了感性认识的重要性","B":"理性认识没有上升到实践","C":"认为经验是衡量是非得失的标准","D":"没有经过理性的思考"},"answer":"AB","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_7"},{"stem":"在认识的本质问题上，各种哲学派别有着不同的观点。其中，旧唯物主义认识论的缺陷在于","options":{"A":"没有坚持从物到感觉和思想的认识路线","B":"不了解实践对认识的决定作用","C":"夸大了人类认识的能动性","D":"没有把认识看作一个辩证发展的过程"},"answer":"BD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_8"},{"stem":"毛泽东说：“感觉到了的东西我们不能立刻理解它，只有理解了的东西才能更深刻地感觉它”，这表明","options":{"A":"感性认识是不可靠的","B":"由感性认识而来的理性认识反过来促进感性认识的发展","C":"感性认识应该上升到理性认识","D":"理性认识与感性认识根本对立"},"answer":"BC","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_9"},{"stem":"对于同一棵大树,在木匠眼中是木材,画家看到的是色彩和色调,植物学家看到的是它的形态特征,这是由于","options":{"A":"人的感觉受理性指导","B":"理性认识渗透进了感性认识","C":"已有的认识影响感觉活动","D":"不同学科的理论前提限定了实践观察的角度"},"answer":"ABCD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_10"},{"stem":"有人曾说：“读万卷书，书，是别人走过的路；行万里路，路，是自己撰写的书。”读万卷书，更要行万里路，从哲学上讲，这是因为","options":{"A":"真理是永恒不变的，而现实世界是多种多样的","B":"理论是否正确要接受实践检验，并在实践中得到丰富和发展","C":"人们通过实践获得认识的最终目的是为实践服务","D":"感性认识高于理性认识"},"answer":"BC","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_11"},{"stem":"辩证唯物主义认识论与旧唯物主义认识论的区别表现在","options":{"A":"是否承认认识是主观对客观世界的反映","B":"是否承认实践对认识的决定作用","C":"是否承认认识是摹写与创造的统一","D":"是否承认认识是一个辩证发展过程"},"answer":"BCD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_12"},{"stem":"认识过程主要是理性思维的过程，同时又包含非理性因素的参与。以下属于承认并重视非理性因素的重要作用的名言是","options":{"A":"“没有“人的感情”，就从来没有也不可能有人对于真理的追求”","B":"“没有革命的理论便没有革命的运动”","C":"“以为只有诗人才需要想象，这是没有道理的，这是愚蠢的偏见！甚至在数学上也需要想象，甚至微积分的发现没有想象也是不可能的”","D":"“在科学上没有平坦的大道，只有不畏劳苦沿着陡峭山路攀登的人，才有希望到达光辉的顶点”"},"answer":"ACD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_13"},{"stem":"基因编辑是应对遗传性疾病的一种潜在治疗办法，但其技术运用极具争议，这不仅是因为基因的的变化会传给后代并最终有可能影响整个基因库，而且更重要的是基因编辑会产生长远而深刻的社会影响，可能衍生出一一系列棘手的伦理、法律和安全难题。正因如此，许多国家对人类基因编辑技术制定了相应的伦理、法律规范。人类严格控制基因编辑行为的原因在于","options":{"A":"人的实践活动要遵循真理尺度与价值尺度的统一","B":"基因编辑技术可能突破人类的伦理道德底线","C":"科学技术有时表现为异己的、敌对的力量","D":"人的实践活动是合规律性与合目的性的统一"},"answer":"ABCD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_14"},{"stem":"近年来，在互联网上经常出现一些针对特定演出、摄影作品好坏美丑的热议，网友们甚至还创造出“艺术可以冷门，但不可以邪门”的调侃，价值评价是主体对客体价值以及价值大小做作的评判或判断，通过揭示客体对于主体的意义，形成对客体的不同态度，如肯定或否定、喜欢或反感、美或丑、善或恶、公正或偏私等。以下关系关于价值评价说法正确的有","options":{"A":"价值评价以客体本身的属性、关系或发展过程为反映内容，以求“真”为认识目的","B":"价值评价是对客体价值关系的主观反映，评价结果的差异性是无法避免的","C":"评价作为价值判断活动具有主观性，评价结果没有正确与错误之分","D":"价值评价要以真理为根据，要以广大人民的需要和利益为根本。"},"answer":"BD","chapter":"第二章","subject":"marx","type":"multi","id":"marx_第二章_multi_15"},{"stem":"实践性是马克思主义理论区别于其他理论的根本特征。（     ）","answer":"A","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_1"},{"stem":"“彼亦一是非，此亦一是非”就是“仁者见仁，智者见智”，二者都是对客观真理的否定。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_2"},{"stem":"凡是亲眼所见、亲耳所听都是直接经验，是对客观事物本质的、真实的反映。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_3"},{"stem":"人类不能穷尽对世界的认识，因此世界不可以被认识的。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_4"},{"stem":"正确的意识是对客观世界的反映，错误的意识不是对客观世界的反映。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_5"},{"stem":"主体客体化与客体主体化的双向运动是人类实践活动两个不可分割的方面，它们互为前提、互为媒介，人类就是通过这种运动形式不断解决着现实世界的矛盾。（     ）","answer":"A","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_6"},{"stem":"认识是主体对客体的能动反映。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_7"},{"stem":"坚持马克思主义就是要完全、彻底地把马克思主义的所有理论贯彻下去，不能有一丝一毫的修改。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_8"},{"stem":"已被实践证明为正确的理论，对于人们的新的认识具有重要的指导作用，因此,可以和实践一样，作为检验真理的标准。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_9"},{"stem":"成功的实践是真理尺度和价值尺度的统一。（     ）","answer":"A","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_10"},{"stem":"自由是必然的根据和限度。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_11"},{"stem":"认识是主体与客体的相互作用。（     ）","answer":"A","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_12"},{"stem":"直接经验和间接经验是第一性和第二性的关系。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_13"},{"stem":"真理是客观存在的。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_14"},{"stem":"如果没有理性，眼睛就是最坏的见证人。（     ）","answer":"B","chapter":"第二章","subject":"marx","type":"judge","id":"marx_第二章_judge_15"},{"stem":"简述实践对认识的决定作用。","answer":"","chapter":"第二章","subject":"marx","type":"short","id":"marx_第二章_short_1"},{"stem":"简述感性认识和理性认识的辩证关系。","answer":"","chapter":"第二章","subject":"marx","type":"short","id":"marx_第二章_short_2"},{"stem":"试用真理的绝对性和相对性辩证关系原理，说明如何正确对待马克思主义。","answer":"","chapter":"第二章","subject":"marx","type":"short","id":"marx_第二章_short_3"},{"stem":"为什么说实践是检验真理的唯一标准？","answer":"","chapter":"第二章","subject":"marx","type":"short","id":"marx_第二章_short_4"},{"stem":"划分历史唯物主义和历史唯心主义的标准，在于是否承认","options":{"A":"英雄人物的历史作用","B":"阶级斗争必然要导致无产阶级专政","C":"社会存在决定社会意识","D":"人的意识在社会生活中的作用"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_1"},{"stem":"全部人类社会关系中,最基础的关系是","options":{"A":"血缘亲族关系","B":"社会生产关系","C":"政治思想关系","D":"阶级压迫关系"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_2"},{"stem":"地理环境在社会发展中的作用主要通过","options":{"A":"对人的心理素质的影响才能实现","B":"对人的生理结构的影响才能实现","C":"对生产过程的影响才能实现","D":"对民族气质的影响才能实现"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_3"},{"stem":"在生产关系诸内容中，最主要的、居支配地位的是","options":{"A":"生产资料的所有制","B":"生产要素的配置比例","C":"产品的分配和消费关系","D":"人与人在生产中的交换关系"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_4"},{"stem":"在社会发展中起决定性的因素是","options":{"A":"自然地理环境","B":"人口因素","C":"社会政治因素","D":"生产方式"},"answer":"D","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_5"},{"stem":"马克思指出，“社会形态发展是自然历史过程”，这是指","options":{"A":"社会形态的发展与自然界的发展完全一样","B":"社会形态的发展也是自发的过程","C":"社会形态的发展是客观的、有规律的发展过程","D":"社会形态的发展与主体的活动无关"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_6"},{"stem":"唯物史观认为，只有把人看作现实的人，才能正确把握人及其活动的本质，把握人与社会历史的关系。人的本质是","options":{"A":"从所有个体的人身上抽象出来的共同性","B":"单个人天生就具有的东西","C":"一切社会关系的总和","D":"人的自然属性和社会属性的综合"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_7"},{"stem":"理解整个人类发展史的最关键的钥匙是","options":{"A":"文化艺术发展史","B":"生产方式发展史","C":"宗教信仰变迁史","D":"政治制度演变史"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_8"},{"stem":"法律作为上层建筑的重要组成部分，不是凭空产生的，也不是永恒存在的，是由一定的社会物质生活条件所决定的。决定法律本质、内容和发展方向的根本因素是","options":{"A":"地理环境","B":"物质资料的生产方式","C":"人口素质","D":"统治阶级的意志"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_9"},{"stem":"国家的本质是","options":{"A":"管理社会各项事业","B":"实现正义与自由","C":"保卫国家领土主权的完整","D":"统治阶级压迫被统治阶级的工具"},"answer":"D","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_10"},{"stem":"在整个上层建筑中，政治上层建筑居主导地位，其核心是","options":{"A":"国家政权","B":"政治法律思想","C":"道德、艺术","D":"政党"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_11"},{"stem":"区分不同社会经济形态根本标志是","options":{"A":"生产资料所有制的性质","B":"上层建筑的性质","C":"掌握政权的阶级","D":"生产力和生产关系相统一的程度"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_12"},{"stem":"人民群众既是历史的“剧中人”，又是历史的“剧作者”，这是","options":{"A":"历史唯心主义的观点","B":"折中主义的观点","C":"历史唯物主义的观点","D":"历史循环论的观点"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_13"},{"stem":"历史上杰出人物的产生","options":{"A":"是纯粹偶然的","B":"是纯粹必然的","C":"是偶然与必然的统一","D":"有的是偶然有的是必然"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_14"},{"stem":"“手推磨产生的是封建主的社会，蒸汽磨产生的是工业资本家的社会”，这句话揭示了","options":{"A":"生产工具是衡量生产力发展水平的重要尺度","B":"科学技术是第一生产力","C":"社会形态的更替在其一定的顺序性","D":"生产关系决定生产工具的变化发展"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_15"},{"stem":"社会革命根源于","options":{"A":"社会中人口太多","B":"少数英雄人物组织暴动","C":"先进思想和革命理论的传播","D":"社会基本矛盾的尖锐化"},"answer":"D","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_16"},{"stem":"人民群众是历史的创造者，其根本原因在于人民群众","options":{"A":"占人口大多数","B":"是社会历史实践的主体","C":"具有先进思想","D":"掌握历史发展规律"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_17"},{"stem":"阶级实质上是一个","options":{"A":"思想范畴","B":"经济范畴","C":"政治范畴","D":"文化范畴"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_18"},{"stem":"马克思在《德意志意识形态》中指出，“人们为了能够“创造历史”，必须能够生活”，“不是意识决定生活，而是生活决定意识”。相比唯物史观，唯心史观的缺陷在于","options":{"A":"没有看到社会意识具有相对独立性","B":"没有认识到哲学是作为上层建筑的社会意识形式","C":"没有考察思想动机背后的物质动因","D":"没有看到经济基础与上层建筑是辩证统一的"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_19"},{"stem":"划分阶级的根本标志是","options":{"A":"人们的政治态度和立场","B":"分配的多少","C":"对生产资料关系的不同所造成的不同经济地位","D":"人们在生产过程中所起的不同作用"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_20"},{"stem":"严格意义上的社会革命是指","options":{"A":"思想.文化.技术领域的重大变革","B":"生产关系的形态发生根本意义的更替","C":"执政者针对国内外形势调整政治经济的相关政策","D":"农民起义建立新的王朝"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_21"},{"stem":"恩格斯说过:“经济上落后的国家在哲学上仍然能够演奏第一小提琴。”这说明","options":{"A":"社会意识并不都是社会存在的反映","B":"社会意识与社会存在发展的不完全同步性和不平衡性","C":"社会意识中的各种形式之间相互作用","D":"社会意识具有历史继承性"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_22"},{"stem":"“在共同生活和共同劳动中,需要有一个为公共利益服务的机构,这就是国家。国家的目的是利用社会力量去谋求社会的福利。 ”这段话","options":{"A":"指明了国家对内职能和对外职能的界限","B":"确认了国家是具有强制力的机构","C":"承认国家是个历史范畴","D":"抹煞了国家的阶级本质"},"answer":"D","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_23"},{"stem":"中秋节是中国传统节日，起源于上古时代，普及于汉代，定型于唐朝初年，盛行于宋朝以后。在这一天，全球的华人华侨不论身在何处、生活在哪个国家地区，很多家庭都会聚在一起赏月、吃月饼，庆祝这一古老节日。以上材料说明","options":{"A":"建立在一定社会关系基础上的制度体制和风俗习惯是永恒不变的","B":"风俗习惯是社会存在的重要组成部分","C":"文化为社会发展提供凝聚力量","D":"文化在整个上层建筑中居于主导地位"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_24"},{"stem":"世界历史是指各民族、国家通过普遍交往，打破孤立隔绝的状态，进入相互依存、相互联系的世界整体化的历史。世界历史形成和发展的基础是","options":{"A":"生产方式的发展变革","B":"普遍交往","C":"社会革命","D":"科技发展"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_25"},{"stem":"人类同疾病较量最有力的武器就是科学技术，人类战胜大灾大疫离不开科学发展和技术创新。马克思主义认为，科学技术是","options":{"A":"社会形态变革的决定力量","B":"社会存在和发展的基础及决定力量","C":"先进生产力的集中体现和主要标志","D":"区分社会经济时代的客观依据"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_26"},{"stem":"上层建筑指的是建立在经济基础之上的意识形态以及制度、组织和设施。判断一种上层建筑是否先进，取决于","options":{"A":"它是否代表劳动人民的利益","B":"它维护的经济基础是否能适应生产力的发展","C":"它是否能为它的经济基础服务","D":"它能否促进经济基础的发展"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_27"},{"stem":"马克思认为，资本主义社会的产生有三条道路，即从封建制度的“衰亡”中产生；从奴隶制和农奴制的“解体”中产生；从原始公有制的“崩溃”中产生。这体现了","options":{"A":"社会形态更替的多样性","B":"社会形态跨越的随意性","C":"社会发展规律的主观性","D":"人类历史发展的曲折性"},"answer":"A","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_28"},{"stem":"马克思指出，判断一个变革时代不能以该时代的意识为依据，相反，这个意识必须从物质生活的矛盾中去解释。这里的“物质生活的矛盾”从根本上说是","options":{"A":"人类社会与自然界的现存冲突","B":"经济基础与上层建筑的现存冲突","C":"社会生产力与生产关系的现存冲突","D":"社会存在与社会意识的现存冲突"},"answer":"C","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_29"},{"stem":"恩格斯指出：“所谓“社会主义社会”不是一种一成不变的东西，而应当和任何其他社会創度一样，把它看成经常变化和改革的社会。”改革是在同一社会形态内，通过调整、变革不适合生产力发展要求的生产关系和上层建筑的某些部分及环节来完成的。改革的实质是","options":{"A":"改革是最高意义上的革命力量","B":"改革是社会制度的自我完善与发展","C":"改革是推动社会发展的又一重要动力","D":"改革是阶级社会发展的直接动力"},"answer":"B","chapter":"第三章","subject":"marx","type":"single","id":"marx_第三章_single_30"},{"stem":"社会存在包括","options":{"A":"自然地理环境","B":"人口因素","C":"物质生产方式","D":"全部社会关系"},"answer":"ABC","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_1"},{"stem":"生产资料所有制形式是生产关系的基础。这是因为","options":{"A":"它决定整个生产关系的性质","B":"它决定人们在生产中的地位及相互关系","C":"它决定生产力水平的高低","D":"它决定产品的分配方式"},"answer":"ABD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_2"},{"stem":"英雄人物“一言可以兴邦，一言可以丧邦”，他的意志可以改变历史发展的方向，这种观点是","options":{"A":"否认历史必然性的唯意志论","B":"否认历史偶然性的机械论","C":"社会意识决定社会存在的具体表现","D":"夸大个人作用的英雄史观"},"answer":"ACD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_3"},{"stem":"人类历史中的文明，不论是古代文明，还是近现代文明，都在不同民族那里有不同的表现，人类文明具有多样性，每一种文明都","options":{"A":"在特定的自然环境、历史背景、民族传统中生长起来的","B":"体现着独特的生产、生活、交往方式","C":"代表一方文化的沃土和绿洲","D":"人类文明的重要组成部分"},"answer":"ABCD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_4"},{"stem":"下列各对矛盾属于社会基本矛盾的有","options":{"A":"个人与社会之间的矛盾","B":"人与自然之间的矛盾","C":"生产力和生产关系之间的矛盾","D":"经济基础和上层建筑之间的矛盾"},"answer":"CD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_5"},{"stem":"“革命是历史的火车头”，这是马克思在总结欧洲1848年革命经验时提出的科学论断。革命是引起事物从旧质到新质的飞跃，是推动事物发生的根本变革。马克思主义认为，社会革命","options":{"A":"对人类社会的发展具有重要的推动作用","B":"是新、旧社会形态实现更替的重要手段","C":"是阶级斗争的最高表现形式","D":"是解决社会危机的唯一途径"},"answer":"ABC","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_6"},{"stem":"某些人认为,“根本没有阶级，只有分工，社会生产组织中无非是“组织者 ” 和“执行者 ”的不同。“这种“分工论 ”","options":{"A":"正确地揭示了资本家和工人合作共赢的关系","B":"掩盖生产资料所有制是划分阶级的主要依据","C":"否认阶级的实质是一部分人无偿占有另一部分人的劳动","D":"正确地揭示了资本家和工人的收入依据"},"answer":"BC","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_7"},{"stem":"正确评价历史人物的方法是","options":{"A":"古为今用的方法","B":"历史分析方法","C":"一分为二的方法","D":"阶级分析方法"},"answer":"BD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_8"},{"stem":"上层建筑由诸多要素构成,下列各项属于上层建筑要素的有","options":{"A":"军队、警察、法院等设施","B":"政治思想和政治制度","C":"法律思想和法律制度","D":"艺术、道德、宗教"},"answer":"ABCD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_9"},{"stem":"“如果资本主义的灭亡是由科学保证了的,为什么还要费那么大的力气去为它安排葬礼呢? ”这种观点的错误在于","options":{"A":"抹煞社会规律实现的特点","B":"否认革命在社会质变中的作用","C":"否认历史观上的决定论原则","D":"否定科学是推动历史前进的革命力量"},"answer":"AB","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_10"},{"stem":"唯心主义历史观之所以没有正确解决社会存在和社会意识的关系问题,主要是由于","options":{"A":"不懂得物质生产实践在社会生活中的地位和作用","B":"夸大了社会意识的社会作用","C":"夸大了社会存在的社会作用","D":"不理解社会的本质"},"answer":"ABD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_11"},{"stem":"马克思指出 :“一个社会即使探索到本身运动的自然规律,……它还是既不能跳过也不能用法令取消自然的发展阶段。但是它能缩短和减轻分娩的痛苦。 ”这表明","options":{"A":"人类社会的发展是合规律性与合目的性的统一","B":"社会发展过程与自然界演变过程一样都是自觉的","C":"人的自觉选择在社会发展中具有重要作用","D":"人类总体历史进程是不可超越的"},"answer":"ACD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_12"},{"stem":"以下选项中属于上层建筑的有","options":{"A":"宗教、哲学","B":"语言","C":"道德、艺术","D":"法庭、监狱"},"answer":"ACD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_13"},{"stem":"鲁迅先生说 :“穷人绝无开交易所折本的懊恼，煤油大王哪会知道北方拾煤渣老婆子身受的酸辛，灾区的饥民,大约总不去种兰花,像阔人老太爷一样…… ”这段话包含的历史唯物主义的道理是","options":{"A":"社会意识是社会存在在人们头脑中的反映","B":"社会意识对社会存在具有反作用","C":"每个人的意识,要受到社会生活的制约，取决于他们的社会地位.生活环境","D":"在阶级社会中，人们的意识具有阶级性"},"answer":"ACD","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_14"},{"stem":"唯物史观主张人民群众是历史的创造者，并不是否定个人在社会历史中的作用，而是要具体地分析个人及其作用的性质、大小以及个人与群众的关系。下列说法正确的有","options":{"A":"社会历史发展是无数个人合力作用的结果","B":"历史人物不能决定和改变历史发展的总进程和总方向","C":"历史人物的出现体现了必然与偶然的统一","D":"历史人物对推动历史的发展起着进步作用"},"answer":"ABC","chapter":"第三章","subject":"marx","type":"multi","id":"marx_第三章_multi_15"},{"stem":"一切历史都是思想发展史。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_1"},{"stem":"生产资料所有制关系是生产关系的基础。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_2"},{"stem":"社会意识的发展形式和规律完全由社会存在决定。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_3"},{"stem":"科学技术发展可以解决一切社会问题。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_4"},{"stem":"全部社会意识都属于思想上层建筑。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_5"},{"stem":"社会政治制度是社会发展的最终决定力量。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_6"},{"stem":"群众和英雄共同创造历史。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_7"},{"stem":"上层建筑对经济基础的反作用，可能是积极的、进步的，也可能是消极的、衰退的。","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_8"},{"stem":"社会形态更替归根结底是政体国体改变的结果。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_9"},{"stem":"地理环境决定着人的性格特征和社会制度。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_10"},{"stem":"自然科学、语言学、形式逻辑属于非意识形态。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_11"},{"stem":"政治法律思想在意识形态中居于核心地位，发挥主导作用。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_12"},{"stem":"生产力状况是生产关系形成的客观前提和物质基础。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_13"},{"stem":"生产力的任何发展都会立即引起生产关系的变革。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_14"},{"stem":"人民群众之所以是历史的创造者，最根本的原因在于人民群众具有先进的思想。（      ）17.社会形态是经济基础和上层建筑的统一体。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_15"},{"stem":"历史唯物主义就是经济决定论。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_16"},{"stem":"生产关系对生产力有反作用，因而变革生产关系就能促进生产力的发展。（      ）","answer":"A","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_17"},{"stem":"劳动创造了人和人类社会。（      ）","answer":"B","chapter":"第三章","subject":"marx","type":"judge","id":"marx_第三章_judge_18"},{"stem":"为什么说物质资料的生产方式是社会发展的决定力量？","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_1"},{"stem":"简述社会意识相对独立性及其表现。","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_2"},{"stem":"简述生产力与生产关系、经济基础与上层建筑的辩证关系。","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_3"},{"stem":"如何认识科学技术在社会发展中的作用。","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_4"},{"stem":"为什么说人民群众是历史的创造者？","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_5"},{"stem":"简述社会存在与社会意识的关系。","answer":"","chapter":"第三章","subject":"marx","type":"short","id":"marx_第三章_short_6"},{"stem":"揭示资本主义本质的出发点是","options":{"A":"对私有制为基础的简单商品经济进行研究","B":"对自然经济进行研究","C":"对生产力进行研究","D":"对生产关系进行研究"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_1"},{"stem":"商品经济是作为自然经济的对立物而产生和发展起来的。商品经济是以交换为目的而进行生产的经济形式。要满足商品的顺利交换，其前提在于必须存在社会分工，另一方面还需要","options":{"A":"生产资料和劳动产品属于不同的所有者","B":"商品具有使用价值与价值","C":"商品的社会属性在于价值 、","D":"商品价值体现了人与人之间的社会经济关系"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_2"},{"stem":"如果部门的劳动生产率提高，同一劳动在单位时间内创造的","options":{"A":"使用价值增加，单位商品的价值量变小","B":"使用价值增加，单位商品的价值量变大","C":"总价值量增加，单位商品的价值量变大","D":"总价值量减少，单位商品的价值量变大"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_3"},{"stem":"商品经济是通过商品货币关系实行等价交换的经济形式，它的基本规律是","options":{"A":"货币流通规律","B":"价值规律","C":"竞争规律","D":"剩余价值规律"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_4"},{"stem":"马克思说:“一切商品对它们的所有者是非使用价值，对它们的非所有者是使用价值。”这句话表明","options":{"A":"有使用价值的不一定有价值","B":"商品的使用价值是对它的消费者而言","C":"商品所有者同时获得使用价值和价值","D":"商品是使用价值和价值的对立统一"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_5"},{"stem":"使生产者与生产资料相分离，将货币资本迅速集中于少数人手中的历史过程就是","options":{"A":"资本积累","B":"资本积聚","C":"资本原始积累","D":"资本集中"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_6"},{"stem":"商品价值量的多少是由","options":{"A":"商品的供求状况决定的","B":"生产商品的劳动时间决定的","C":"商品生产者的个别劳动时间决定的","D":"生产商品的社会必要劳动时间决定的"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_7"},{"stem":"在商品经济中，形成价值的抽象劳动的支出必须借助于","options":{"A":"具体劳动","B":"剩余劳动","C":"商品的生产形式","D":"资本主义生产方式"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_8"},{"stem":"商品生产者要获得更多收益必须使生产商品的","options":{"A":"个别劳动时间等于倍加的社会必要劳动时间","B":"个别劳动时间等于社会必要劳动时间","C":"个别劳动时间大于社会必要劳动时间","D":"个别劳动时间小于社会必要劳动时间"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_9"},{"stem":"资本主义经济制度形成的前提条件是","options":{"A":"等价交换","B":"劳动成为商品","C":"劳动力成为商品","D":"货币所有者把货币投入生产领域"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_10"},{"stem":"马克思通过对资本主义生产中价值增殖过程的分析，把雇佣工人的劳动时间分为","options":{"A":"生产使用价值的时间和生产价值的时间","B":"转移旧价值的时间和创造新价值的时间","C":"必要劳动时间和剩余劳动时间","D":"个别劳动时间和社会必要劳动时间"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_11"},{"stem":"剩余价值产生的唯一源泉是","options":{"A":"雇佣劳动者的剩余劳动","B":"雇佣劳动者的必要劳动","C":"雇佣劳动者的具体劳动","D":"雇佣劳动者的抽象劳动"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_12"},{"stem":".资本家总是非常关心自己所生产的商品的效能，利用各种技术手段来检测商品是否合格、是否满足消费者的需求。资本家关心商品使用价值的根本原因在于","options":{"A":"资本家觉悟高，能从社会利益的角度考虑问题","B":"迫于资本主义国家法律、法令的要求","C":"使用价值是价值的物质承担者，商品的使用价值影响着资本循环能否正常进行","D":"商品性能越好，使用价值越高，所含价值量就越高，从而一定能卖出更好的价钱"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_13"},{"stem":"个别资本家追逐的超额剩余价值是通过","options":{"A":"延长工作日的绝对工作时间实现的","B":"提高其他企业的劳动生产率实现的","C":"提高自己企业的劳动生产率实现的","D":"全社会劳动生产率普遍提高实现的"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_14"},{"stem":"马克思认为资本主义制度下的工资掩盖了资本主义剥削的实质，这是因为工资","options":{"A":"是劳动者的必要劳动创造的价值","B":"是劳动力的价值","C":"是劳动力的价格","D":"表现为劳动的价格"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_15"},{"stem":"资本主义基本矛盾是","options":{"A":"生产与需要的矛盾","B":"无产阶级和资产阶级的矛盾","C":"生产力和上层建筑的矛盾","D":"生产社会化和生产资料资本主义私人占有的矛盾"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_16"},{"stem":"资本循环的三种职能形式是","options":{"A":"产业资本、商业资本、借贷资本","B":"固定资本、流动资本、生产资本","C":"货币资本、生产资本、商品资本","D":"不变资本、可变资本、流通资本"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_17"},{"stem":"社会再生产的核心问题是","options":{"A":"剩余价值的实现问题","B":"社会总产品的实现问题","C":"社会总产值的构成问题","D":"国民收入的分配问题"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_18"},{"stem":"资本主义经济危机的实质是","options":{"A":"生产过剩的危机","B":"生产不足的危机","C":"生产相对过剩的危机","D":"生产绝对过剩的危机"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_19"},{"stem":"资本主义经济危机呈现出周期性的原因在于","options":{"A":"资本主义基本矛盾","B":"资本主义基本矛盾运动的阶段性","C":"无产阶级和资产阶级矛盾激化产生的","D":"资本主义再生产的周期性"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_20"},{"stem":"商品拜物教的本质是","options":{"A":"不必要的消费取代了必要的消费","B":"物与物的交换关系取代了人与人的关系","C":"商品的生产和流通被资本家操控","D":"人可以自由的生产和消费商品"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_21"},{"stem":"马克思指出 :“如果物没有用,那么其中包含的劳动也就没有用,不能算作劳动,因此 不形成价值。 ”这段话说明","options":{"A":"价值的存在以物的有用性为前提","B":"价值的存在与物的有用性互为前提","C":"只要物是有用的,它就有价值","D":"物越是有用就越有价值"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_22"},{"stem":"资本主义国家的选举的实质是","options":{"A":"资产阶级和无产阶级分权","B":"每个公民都能通过竞选参与政治活动，表达自己的要求","C":"人民当家作主","D":"协调统治阶级内部利益关系和矛盾的重要措施"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_23"},{"stem":"价值形式，就是商品价值的表现形式，也就是交换价值。在商品交换的发展过程中，价值形式的发展经历了四个阶段。其中不存在等价物的价值形式是","options":{"A":"简单的或偶然的价值形式","B":"总和的或扩大的价值形式","C":"一般价值形式","D":"货币形式"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_24"},{"stem":"《资本论》中有这样的表述:“对上衣来说，无论是裁缝自己穿还是他的顾客穿，都是一样的。”这主要是因为无论谁穿","options":{"A":"上衣都起着使用价值的作用","B":"上衣都起着价值的作用","C":"上衣都是抽象劳动的结果","D":"上衣都是社会劳动的结果"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_25"},{"stem":"某企业新投资了一家工厂，花费100万元购买土地和厂房之后，又花费了100万元购买机器、原材料。经过分析，该企业的资本有机构成为4：1。在经过一轮的生产之后，企业资本金上涨到400万元。该工厂的剩余价值率为","options":{"A":"50%","B":"100%","C":"200%","D":"300%"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_26"},{"stem":"近年来，数字货币的概念越来越火热，引起了人们对货币本质的新一轮讨论。有专家指出，随着经济的发展和技术的进步，货币在发展过程中被不同的价值符号所代表，从金属货币、纸币、电子货币到数字货币不断转变。每种不同的货币形式代表了人们不同的信任形式。马克思主义认为，货币是","options":{"A":"固定充当一般等价物的特殊商品","B":"资本的唯一物质形态","C":"商品特有的社会属性","D":"可以带来剩余价值的价值"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_27"},{"stem":"消费者的下列经济行为中，属于货币执行价值尺度职能的是","options":{"A":"缴纳房屋契税9000元","B":"购买商品房，合同约定房价30万元","C":"在装饰材料市场现购材料5万元","D":"按购房合同约定，第二年付房款10万元"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_28"},{"stem":"某资本家经营的企业原来一天的工作时间为8小时，剩余价值率为100％。在其他条件不变的情况下，如果采取绝对剩余价值的生产方法将剩余价值率提高到200％，且不提高劳动强度的话，则工人一天的工作时间将变为","options":{"A":"10小时","B":"12小时","C":"14小时","D":"16小时"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_29"},{"stem":"资本主义生产过程不仅是生产使用价值的劳动过程，同时是生产剩余价值的价值增殖过程。价值增殖过程是剩余价值的生产过程，这是资本主义生产过程的主要方面。所谓价值增殖过程，是超过了一定点而延长了的价值的形成过程，这里的“一定点”指的是雇佣工人","options":{"A":"转移生产资料价值的时间","B":"转移劳动力价值的时间","C":"创造使用价值的时间","D":"再生产自己劳动力价值的时间"},"answer":"D","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_30"},{"stem":"资本家提高对工人剥削程度的方法是多种多样的，最基本的方法有两种，即绝对剩余价值的生产和相对剩余价值的生产。绝对剩余价值的生产和相对剩余价值的生产都是依靠","options":{"A":"延长工人的剩余劳动时间获得的","B":"提高劳动生产率获得的","C":"减少工人的必要劳动时间获得的","D":"延长工作日获得的"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_31"},{"stem":"资本在资本主义生产过程中采取生产资料和劳动力两种形态。马克思将资本区分为不变资本与可变资本的根据是","options":{"A":"资本不同部分在剩余价值生产中的不同作用","B":"资本不同部分在周转中的不同方式","C":"资本在循环中的不同职能","D":"资本不同部分的物质形态是否改变"},"answer":"A","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_32"},{"stem":"产业资本在资本循环过程中要在不同阶段依次执行不同的职能。其中执行商品资本职能的是","options":{"A":"贮藏阶段","B":"售卖阶段","C":"购买阶段","D":"生产阶段"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_33"},{"stem":"恩格斯指出：“马克思一有机会就提醒读者注意，决不要把他所说的剩余价值同利润或资本赢利相混淆。”之所以不要把剩余价值同利润或资本赢利相混淆，是因为利润","options":{"A":"与剩余价值无本质联系","B":"掩盖了剩余价值与全部预付资本的关系","C":"掩盖了剩余价值与可变资本的关系","D":"与剩余价值的来源不同"},"answer":"C","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_34"},{"stem":"利润平均化规律，反映了在瓜分剩余价值上，资本家之间虽然存在竞争和矛盾，但在加强对工人阶级的剥削以榨取更大量的剩余价值这一点上，资本家之间有着共同的阶级利益。平均利润的出现是","options":{"A":"同一部门内不同企业之间竞争的结果","B":"不同部门之间竞争的结果","C":"国际上同类企业之间竞争的结果","D":"不同行业之间工人联合斗争的结果"},"answer":"B","chapter":"第四章","subject":"marx","type":"single","id":"marx_第四章_single_35"},{"stem":"货币是固定地充当一般等价物的商品，体现商品生产者之间的社会经济关系。货币具有五种基本职能，其中价值尺度和流通手段是货币的两个最基本的职能。下列关于这两种职能说法正确的有","options":{"A":"货币执行价值尺度职能时可以是观念上的货币","B":"纸币也可以执行价值尺度的职能","C":"货币执行流通手段职能时必须是现实中的货币","D":"价值的表现形式"},"answer":"ACD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_1"},{"stem":"一切商品都包含着使用价值和价值二因素，商品是使用价值和价值的统一。这表明","options":{"A":"缺少使用价值和价值任何一方面，都不能成为商品","B":"没有使用价值就没有价值","C":"有使用价值，但不是劳动产品，也不是商品","D":"有使用价值，也是劳动产品，但只是供生产者自己消费，也不是商品"},"answer":"ABCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_2"},{"stem":"劳动力成为商品的基本条件是","options":{"A":"社会劳动力缺乏，劳动力奇货可居","B":"劳动者没有任何生产生活资料，不得不靠出卖自己的劳动力为生","C":"劳动者的人身彻底依附资本家","D":"劳动者是自由人，能把自己的劳动力作为自己的商品来支配"},"answer":"BD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_3"},{"stem":"马克思主义劳动价值论批判地继承了英国古典政治经济学的观点，为剩余价值的创立奠定了基础，具有重要的理论和实践意义。具体表现在","options":{"A":"马克思创立的劳动二重性理论成为理解政治经济学的枢纽","B":"揭示了商品经济的一般规律，为社会主义市场经济发展提供理论指导","C":"认为脑力劳动也是创造价值的劳动","D":"科技、知识、信息等生产要素能够创造价值"},"answer":"ABC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_4"},{"stem":"绝对剩余价值生产和相对剩余价值生产的共同点","options":{"A":"都体现着资本家对工人的剥削关系","B":"都延长了剩余劳动时间","C":"都增加了剩余价值量","D":"都提高了剩余价值率"},"answer":"ABCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_5"},{"stem":"第二次世界大战后，发达资本主义国家工人工作日有所缩短，这表明","options":{"A":"对工人剥削程度有所减轻","B":"劳动生产率明显提高","C":"必要劳动时间大为缩短","D":"相对剩余价值成为主要剥削形式"},"answer":"BCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_6"},{"stem":"资本主义的利润率","options":{"A":"是剩余价值与全部可变资本的比率","B":"是剩余价值与全部预付资本的比率","C":"是剩余价值率的转化形式","D":"反映资本家对工人的剥削程度"},"answer":"BC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_7"},{"stem":"电子商务的发展,对加快资本周转速度起着重要作用,体现在缩短","options":{"A":"资本由货币资本转化为生产资本的时间","B":"资本由商品资本转化为货币资本的时间","C":"原材料的储备时间","D":"劳动者加工劳动对象的时间"},"answer":"ABC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_8"},{"stem":"纺织厂的资本家购买的用于生产的棉花属于","options":{"A":"不变资本","B":"可变资本","C":"流动资本","D":"固定资本"},"answer":"AC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_9"},{"stem":"资本主义生产目的是追逐利润最大化。为了获得尽可能多的利润，分布在不同部门(行业)的资本家之间必然展开激烈的竞争，而竞争的结果必将导致利润率的平均化。利润率平均化的过程意味着","options":{"A":"某企业工人创造的剩余价值有被其他资本家侵占的可能","B":"各部门内不同资本家的等量投资所得到的利润大体上均等","C":"各部门资本家在加强对工人阶级的剥削上有着共同的阶级利益","D":"不从事直接生产的银行资本家所获得的利润总是低于平均利润"},"answer":"AC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_10"},{"stem":"剩余价值规律","options":{"A":"反映资本主义生产的实质","B":"揭示资本主义生产的目的和达到目的的手段","C":"在资本主义社会起主导作用","D":"决定资本主义生产的主要方面和主要过程"},"answer":"ABCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_11"},{"stem":"下列现象中掩盖资本主义剥削关系实质或程度的有","options":{"A":"工资表现为“劳动的价格 ”","B":"剩余价值取得了利润的形态","C":"利润转化为平均利润","D":"资本家与工人形式上的“自由”“平等”关系"},"answer":"ABCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_12"},{"stem":"在资本主义商品生产的条件下，每个资本家总是力图不断改进技术，改善经营管理，从而获得超额剩余价值。各个资本家追求超额剩余价值的结果是","options":{"A":"整个资本家阶级普遍获得相对剩余价值","B":"劳动力商品的价值增加","C":"全社会劳动生产率的提高","D":"剩余劳动时间缩短"},"answer":"AC","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_13"},{"stem":"马克思说:“一切现实的危机的最终原因始终是群众贫穷和群众的消费受到限制，而与此相对立，资本主义生产却竭力发展生产力,好像只有社会的绝对的消费能力才是生产力发展的界限。”这段论述表明","options":{"A":"社会的绝对的消费能力导致了经济危机的发生","B":"经济危机的发生根本上在于资本主义的基本矛盾","C":"资本积累与无限扩大生产也是经济危机发生的原因","D":"经济危机的发生与群众的贫穷及其消费能力受到限制有关"},"answer":"BCD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_14"},{"stem":"资本是在运动中增殖的，资本周而复始、不断反复的循环，就叫资本的周转。其他条件不变的情况下，以下关于资本周转说法正确的有","options":{"A":"资本周转速度与资本周转时间成反比","B":"加快流动资本的周转速度可以加快资本周转速度","C":"加快资本周转速度能够提高剩余价值率","D":"加快资本周转速度能够增加年剩余价值量"},"answer":"ABD","chapter":"第四章","subject":"marx","type":"multi","id":"marx_第四章_multi_15"},{"stem":"市场经济是与自然经济、商品经济对应的经济形式。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_1"},{"stem":"商品经济是以交换为目的而进行生产的经济形式。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_2"},{"stem":"商品买卖过程中一手交钱一手交货，这里一手交钱的钱体现的是货币的支付手段职能。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_3"},{"stem":"价格围绕价值上下波动意味着价格波动的平均值就是价值。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_4"},{"stem":"没有不变资本购买生产资料，工人就不能创造剩余价值，所以剩余价值是由资本家的全部预付资本生产出来的。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_5"},{"stem":"资本家支付给工人的工资，是用来购买工人的劳动的报酬。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_6"},{"stem":"资本主义厂房里的机器、设备、工具等既是不变资本，又是固定资本。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_7"},{"stem":"流动资本是在生产中发生价值增值的资本。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_8"},{"stem":"资本主义工资是工人全部劳动的报酬。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_9"},{"stem":"无产阶级和资产阶级之间的矛盾，是资本主义社会的基本矛盾。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_10"},{"stem":"资本就是货币，货币不一定是资本。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_11"},{"stem":"剩余价值不在流通领域产生，又离不开流通领域。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_12"},{"stem":"剩余价值与利润在量上是相等的。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_13"},{"stem":"资本的技术构成决定着资本的价值构成，资本技术构成的变化往往会引起资本价值构成的变化。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_14"},{"stem":"生产价格的出现违背了价值规律。(    )","answer":"B","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_15"},{"stem":"劳动二重性理论是理解马克思主义政治经济学的枢纽。(    )","answer":"A","chapter":"第四章","subject":"marx","type":"judge","id":"marx_第四章_judge_16"},{"stem":"简述商品的二因素与劳动二重性的关系。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_1"},{"stem":"简述价值、生产价格、市场价格三个概念的区别。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_2"},{"stem":"简述劳动力商品的价值。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_3"},{"stem":"简述资本主义经济危机的本质及原因。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_4"},{"stem":"简述剩余价值生产的两种基本方法。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_5"},{"stem":"简述不变资本与可变资本划分的依据、内容和意义。","answer":"","chapter":"第四章","subject":"marx","type":"short","id":"marx_第四章_short_6"},{"stem":"垄断的形成是","options":{"A":"国家干预经济生活的结果","B":"生产和资本集中发展到一定阶段的结果","C":"生产资本输出的结果","D":"金融资本统治的结果"},"answer":"B","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_1"},{"stem":"资本主义基本矛盾“包含着现代的一切冲突的萌芽”，资本主义生产方式越是占统治地位，越是发展，“社会的生产和资本主义占有的不相容性，也必然越加鲜明地表现出来”。表明","options":{"A":"资本主义能够自己发展到社会主义","B":"资本主义的发展分为自由竞争和垄断两个阶段","C":"国家垄断资本主义是资本主义的最高形式","D":"资本主义的内在矛盾决定了资本主义必然被社会主义所代替"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_2"},{"stem":"垄断资本的实质在于","options":{"A":"获得垄断地位","B":"获得垄断利润","C":"获得垄断价格","D":"获得垄断统治"},"answer":"B","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_3"},{"stem":"国家垄断资本主义的宏观调节体现的是","options":{"A":"全体社会成员的利益","B":"个别金融寡头的经济利益","C":"垄断资产阶级的整体利益","D":"国有企业的经济利益"},"answer":"C","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_4"},{"stem":"资本社会化的最高形式是","options":{"A":"生产社会化","B":"国家垄断资本主义","C":"垄断资本主义","D":"经营管理社会化"},"answer":"B","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_5"},{"stem":"金融资本是由工业垄断资本和银行垄断资本融合在一起而形成的一种垄断资本。在金融资本形成的基础上，产生了金融寡头。金融寡头在政治上对国家机器的控制主要表现在","options":{"A":"国家政权与私人垄断资本融合在一起","B":"建立政策咨询机构","C":"宏观调节与微观规制","D":"亲自担任或指派代理人担任政府要职"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_6"},{"stem":"国家垄断资本主义是垄断资本主义的新发展，它对资本主义经济的发展产生了积极的作用。可以说，它的出现","options":{"A":"在一定程度上促进了社会生产力的发展","B":"消除了资本主义的基本矛盾","C":"从根本上解决了社会问题","D":"使经济危机的出现频率降低"},"answer":"A","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_7"},{"stem":"资本主义经济发展中,资本集中的直接后果是","options":{"A":"社会总资本急剧增加","B":"社会就业率明显提高","C":"个别资本规模迅速扩大","D":"绝对剩余价值总量快速增长"},"answer":"C","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_8"},{"stem":"垄断利润是","options":{"A":"资本家获得的超额利润","B":"垄断组织获得的平均利润","C":"垄断组织获得的一般利润","D":"垄断组织获得的超过平均利润的高额利润"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_9"},{"stem":"资本主义国家的福利制度从根本上","options":{"A":"提高了劳动者的工资福利","B":"表明资产阶级同劳动人民的利益是一致的","C":"减轻了对雇佣劳动者的剥削","D":"没有减轻对雇佣劳动者的剥削,是羊毛出在羊身上"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_10"},{"stem":"垄断资本主义国家事实上的主宰者是","options":{"A":"银行资本家","B":"工业资本家","C":"金融寡头","D":"商业资本家"},"answer":"C","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_11"},{"stem":"资产阶级国家参与社会再生产的目的是","options":{"A":"实现供求总量平衡,调整优化经济结构","B":"合理配置资源,提高社会生产力","C":"实现充分就业","D":"保证垄断资产阶级获得高额垄断利润"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_12"},{"stem":"资本输出的实质是","options":{"A":"发达国家帮助发展中国家发展经济的手段","B":"发达国家带动其商品输出的手段","C":"发达国与发展中国家的一种互助互利关系","D":"金融资本掠夺、剥削和奴役其它国家和人民的重要手段"},"answer":"D","chapter":"第五章","subject":"marx","type":"single","id":"marx_第五章_single_13"},{"stem":"垄断利润是","options":{"A":"凭借垄断地位获得的利润","B":"超过平均利润的高额利润","C":"资本主义的平均利润","D":"垄断资本所有权在经济上的实现形式"},"answer":"ABD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_1"},{"stem":"下列各项正确表述垄断与竞争关系的有","options":{"A":"垄断是在竞争的基础上产生的","B":"垄断消除了竞争","C":"垄断与竞争并存","D":"垄断使竞争更加激烈和复杂"},"answer":"ACD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_2"},{"stem":"私人垄断资本主义向国家垄断资本主义过渡","options":{"A":"是资本主义生产社会化的客观要求","B":"是资本主义基本矛盾发展的必然结果","C":"在一定程度上促进了资本主义生产的发展","D":"从根本上解决资本主义基本矛盾"},"answer":"ABC","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_3"},{"stem":"与第二次世界大战之前的资本主义相比,当代资本主义生产关系中的社会阶层、阶级 结构发生了很多新的变化,主要表现在","options":{"A":"知识型和服务型劳动者数量随科技不断深入而持续地增加","B":"资本家由从前的直接生产经营者变成了以股票为生的食利者","C":"职工持股和参与决策使得劳动者成为资本家集团的重要力量","D":"高级职业经理成为资本主义社会大公司经营活动的实际控制者"},"answer":"ABD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_4"},{"stem":"当代资本主义社会在经济、政治等诸多方面发生了许多新变化，其原因在于","options":{"A":"当代科技革命和生产力的发展所产生的根本推动作用","B":"工人阶级争取自身权利和利益斗争的重要作用","C":"社会主义制度初步显示的优越性对资本主义产生了重要影响","D":"改良主义政党对资本主义制度的改革"},"answer":"ABCD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_5"},{"stem":"垄断并不能消除竞争，反而使竞争变得更加复杂和剧烈。垄断下的竞争包括","options":{"A":"垄断组织内部的竞争","B":"垄断组织之间的竞争","C":"垄断组织与非垄断组织之间的竞争","D":"非垄断的中小企业之间的竞争"},"answer":"ABCD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_6"},{"stem":"马克思、恩格斯在《共产党宣言》中指出：“资产阶级在它的不到一百年的阶级统治中所创造的生产力，比过去一切世代创造的全部生产力还要多，还要大。自然力的征服，机器的采用，化学在工业和农业中的应用，轮船的行驶，铁路的通行，电报的使用，整个整个大陆的开垦，河川的通航，仿佛用法术从地下呼唤出来的大量人口——过去哪一个世纪料想到在社会劳动里蕴藏有这样的生产力呢？”资本主义社会生产力迅速发展的主要原因是","options":{"A":"资本追逐剩余价值的内在动力","B":"市场激烈竞争的外在压力","C":"无产阶级反对资产阶级的斗争","D":"资本主义国家对市场的全面控制"},"answer":"AB","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_7"},{"stem":"垄断资本所获得的高额利润，归根到底来自无产阶级和其他劳动人民所创造的剩余价值，具体来说，垄断利润的来源包括","options":{"A":"加强对国内无产阶级和其他劳动人民的剥削","B":"通过控制市场占有非垄断企业的利润","C":"加强对其他国家劳动人民的剥削和掠夺","D":"通过资本主义国家政权进行有利于垄断资本的再分配"},"answer":"ABCD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_8"},{"stem":"国家垄断资本主义形成和发展的原因有","options":{"A":"科技进步和生产社会化程度进一步提高的产物","B":"资本主义基本矛盾进一步尖锐化的结果","C":"应对经济波动和经济危机深化的要求","D":"缓和社会矛盾、协调利益关系的要求"},"answer":"ABCD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_9"},{"stem":"近年来，全球主要经济体同步聚焦反垄断，前有智能手机芯片巨头高通在中国、韩国、欧盟等地被判巨额罚款，后有脸书、谷歌等互联网科技巨头正面临着越来越广泛的反垄断调查。有专家认为，随着互联网企业和平台经济的迅速发展，针对此类涉嫌垄断行为的规制将进一步加强。垄断资本向世界扩展的经济动因包括","options":{"A":"争夺商品销售市场","B":"将国内过剩的资本输出，以在别国谋求高额利润","C":"将部分要害核心技术转移到国外，以取得在别国的垄断优势","D":"确保原材料和能源的可靠来源"},"answer":"ABD","chapter":"第五章","subject":"marx","type":"multi","id":"marx_第五章_multi_10"},{"stem":"垄断是资本集中发展的结果。（      ）","answer":"B","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_1"},{"stem":"垄断价格长期使商品的价格背离其价值，因而否定了价值规律。（      ）","answer":"B","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_2"},{"stem":"国家垄断资本主义的出现克服了资本主义社会生产的无政府状态。（      ）","answer":"B","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_3"},{"stem":"从本质上讲，经济全球化是生产力发展和社会化大生产的必然要求。（      ）","answer":"A","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_4"},{"stem":"当代资本主义发生的变化意味着资本主义生产关系的根本性质发生了变化。（      ）","answer":"B","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_5"},{"stem":"十九世纪末二十世纪初资本主义国家进入了国家垄断资本主义阶段。（      ）","answer":"A","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_6"},{"stem":"国家垄断资本主义的出现是资本主义经济制度内的经济关系调整。（      ）","answer":"B","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_7"},{"stem":"二战后资本主义发生的新变化是人类社会发展规律与资本主义经济规律作用的结果。（      ）","answer":"A","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_8"},{"stem":"资本输出到发展中国家，促进了其经济发展，是绝对有利的经济加速途径。（      ）","answer":"A","chapter":"第五章","subject":"marx","type":"judge","id":"marx_第五章_judge_9"},{"stem":"垄断和竞争的关系是什么？","answer":"","chapter":"第五章","subject":"marx","type":"short","id":"marx_第五章_short_1"},{"stem":"简述国家垄断资本主义的实质及作用。","answer":"","chapter":"第五章","subject":"marx","type":"short","id":"marx_第五章_short_2"},{"stem":"简述当代资本主义变化的新特征。","answer":"","chapter":"第五章","subject":"marx","type":"short","id":"marx_第五章_short_3"},{"stem":"科学社会主义创立的直接思想来源是","options":{"A":"英法的空想社会主义学说","B":"德国古典哲学","C":"唯物史观和剩余价值学说","D":"英国古典政治经济学"},"answer":"C","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_1"},{"stem":"空想社会主义的开山之作《乌托邦》一书的作者是","options":{"A":"英国的莫尔","B":"法国的圣西门","C":"法国的傅立叶","D":"英国的欧文"},"answer":"A","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_2"},{"stem":"科学社会主义之所以能够超越空想社会主义,是因为把争取无产阶级和全人类解放的斗争建立在","options":{"A":"暴力革命形式上","B":"社会发展客观规律的基础上","C":"批判空想社会主义","D":"共产主义者同盟上"},"answer":"B","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_3"},{"stem":"无产阶级夺取政权的第一次伟大尝试是","options":{"A":"法国巴黎公社革命","B":"俄国十月革命","C":"中国新民主主义革命","D":"英国光荣革命"},"answer":"A","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_4"},{"stem":"列宁得出社会主义可能在一国或数国首先取得胜利的依据是","options":{"A":"资本主义必然灭亡，社会主义和共产主义必然胜利的规律","B":"帝国主义时代资本主义政治经济发展不平衡的规律","C":"资本主义国家无产阶级与资产阶级斗争的规律","D":"无产阶级是最先进最革命的阶级的原理"},"answer":"B","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_5"},{"stem":"十月革命实现了社会主义（ ）的伟大飞跃，开辟了人类历史的新纪元。","options":{"A":"从空想到科学","B":"从一国到多国","C":"从理想到现实","D":"从新民主主义革命到社会主义革命"},"answer":"C","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_6"},{"stem":"无产阶级专政的实质是","options":{"A":"领导社会主义建设","B":"对敌对阶级进行统治专政","C":"无产阶级作为统治阶级掌握国家政权","D":"使社会主义从空想变成现实"},"answer":"C","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_7"},{"stem":"经济和政治发展的不平衡是资本主义的绝对规律，由此应当得出的结论是","options":{"A":"无产阶级革命至少将在几个主要的资本主义国家同时发生","B":"社会主义可能在经济文化相对落后的俄国首先取得胜利","C":"社会主义可能首先在少数甚至在单独一个资本主义国家内获得胜利","D":"社会主义可能在经济文化相对发达的国家首先取得胜利"},"answer":"C","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_8"},{"stem":"列宁指出：“马克思丝毫不想制造乌托邦，不想凭空猜测无法知道的事情。马克思提出共产主义的问题，正像一个自然科学家已经知道某一新的生物变种是怎样产生以及朝着哪个方向演变才提出该生物变种的发展问题一样。”这句话表明马克思","options":{"A":"在揭示人类社会发展一般规律的基础上指明社会发展的方向","B":"在剖析资本主义社会旧世界中阐发未来新世界的特点","C":"立足于揭示未来社会的一般特征","D":"对未来社会不作详尽的细节描绘"},"answer":"A","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_9"},{"stem":"社会主义的发展道路必然呈现出多样性的特点。造成社会主义发展道路多样性的现实原因是","options":{"A":"无产阶级政党自身成熟程度的不同","B":"历史文化传统的差异性","C":"时代和实践的不断发展","D":"革命传统不同"},"answer":"C","chapter":"第六章","subject":"marx","type":"single","id":"marx_第六章_single_10"},{"stem":"恩格斯指出：“德国的理论上的社会主义永远不会忘记，它是站在圣西门、傅立叶和欧文这三个人的肩上的。虽然这三个人的学说含有十分虚幻和空想的性质，但他们终究是属于一切时代最伟大的智士之列的，他们天才地预示了我们现在已经科学地证明了其正确性的无数真理。”空想社会主义的局限性表现在","options":{"A":"未能揭示资本主义必然灭亡的命运","B":"没有找到埋葬资本主义的力量","C":"没有找到通往理想社会的现实道路","D":"没有对未来社会作出详尽的描述"},"answer":"BC","chapter":"第六章","subject":"marx","type":"multi","id":"marx_第六章_multi_1"},{"stem":"社会主义发展道路必然呈现多样性的原因在于","options":{"A":"各个社会主义国家的生产力发展状况和社会发展阶段不同","B":"各个社会主义国家的历史文化传统存在差异性","C":"各个社会主义国家的指导思想不同","D":"时代的不断前进和实践的不断发展"},"answer":"ABD","chapter":"第六章","subject":"marx","type":"multi","id":"marx_第六章_multi_2"},{"stem":"无产阶级执政党在探索符合本国国情的社会主义发展道路时","options":{"A":"必须坚持科学社会主义的基本原则","B":"必须坚持对待马克思主义的科学态度","C":"必须从当时当地的历史条件出发","D":"必须充分吸收人类一切文明成果"},"answer":"ABCD","chapter":"第六章","subject":"marx","type":"multi","id":"marx_第六章_multi_3"},{"stem":"列宁指出：“设想世界历史会一帆风顺、按部就班地向前发展，不会有时出现大幅度的跃退，那是不辩证的，不科学的，在理论上是不正确的。”社会主义的发展也是前进性与曲折性相统一的过程，从中得出的启示是","options":{"A":"社会历史发展过程经历了否定之否定的辩证否定过程","B":"社会规律是历史的并且在不同的历史阶段有不同的表现形式","C":"要从有意识、有目的的活动中找到不以人的意志为转移的社会规律","D":"社会前进过程中会出现反复、停滞和倒退的现象"},"answer":"ABCD","chapter":"第六章","subject":"marx","type":"multi","id":"marx_第六章_multi_4"},{"stem":"纵观社会主义的发展历程，可以看到一个突出特点，即社会主义是在实践中开拓前进、不断发展的。深刻认识这一特点，有助于我们","options":{"A":"从理论上把握社会主义的发展规律","B":"在当今时代正确看待世界社会主义的发展态势","C":"正确看待中国特色社会主义实践探索对于世界社会主义事业的深远意义","D":"以开拓奋进的精神寻找适合所有社会主义国家的社会主义模式"},"answer":"ABC","chapter":"第六章","subject":"marx","type":"multi","id":"marx_第六章_multi_5"},{"stem":"科学社会主义理论诞生的标志是《共产党宣言》的发表。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_1"},{"stem":"空想社会主义的思想是科学社会主义的直接思想来源，因为三大空想社会主义者的社会历史观基本上都是唯物主义的。（     ）","answer":"B","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_2"},{"stem":"社会主义社会和共产主义社会是两种不同的社会形态，社会主义革命的胜利无法被当作共产主义理想是可以实现的证据。（     ）","answer":"B","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_3"},{"stem":"无产阶级专政和社会主义民主是根本对立的。（     ）","answer":"B","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_4"},{"stem":"无产阶级革命是迄今为止人类历史上最广泛、最彻底、最深刻的革命(  )。","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_5"},{"stem":"列宁对社会主义革命学说的重大贡献是提出了社会主义革命可以在经济文化比较落后的国家首先取得胜利的理论。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_6"},{"stem":"中国共产党的领导是中国特色社会主义最本质的特征。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_7"},{"stem":"某种社会主义模式的失败，不等于整个社会主义事业的失败。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_8"},{"stem":"中国式现代化既有各国现代化的共同特征，更有着基于自己国情的中国特色。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_9"},{"stem":"社会主义是人类历史发展到一定阶段的产物，发展社会主义必须结合本国国情。（     ）","answer":"A","chapter":"第六章","subject":"marx","type":"judge","id":"marx_第六章_judge_10"},{"stem":"如何正确认识和把握科学社会主义一般原则？","answer":"","chapter":"第六章","subject":"marx","type":"short","id":"marx_第六章_short_1"},{"stem":"怎么正确认识社会主义的发展规律？","answer":"","chapter":"第六章","subject":"marx","type":"short","id":"marx_第六章_short_2"},{"stem":"“通过批判旧世界来发现新世界”是","options":{"A":"空想社会主义预见未来社会的方法","B":"马克思主义预见未来社会的方法","C":"唯物主义预见未来社会的方法","D":"唯心主义预见未来社会的方法"},"answer":"B","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_1"},{"stem":"马克思主义追求的根本价值目标是","options":{"A":"实现人的自由而全面的发展","B":"人能够随心所欲,为所欲为","C":"人类能够摆脱必然性","D":"按需分配"},"answer":"A","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_2"},{"stem":"必然王国和自由王国是社会发展的","options":{"A":"两种不同的状态","B":"两种不同的选择","C":"两条不同的道路","D":"两种不同的理想"},"answer":"A","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_3"},{"stem":"共产主义是人类解放的实现。共产主义社会的根本特征是","options":{"A":"物质财富极大丰富，消费资料按需分配","B":"社会关系高度和谐","C":"人们精神境界极大提高","D":"实现人的自由而全面的发展"},"answer":"D","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_4"},{"stem":"自由王国是指人们处于","options":{"A":"绝对自由的社会状态","B":"不再受自然规律和社会规律支配的状态","C":"允许自由竞争的资本主义状态","D":"摆脱了自然和社会关系的奴役，成为自己社会关系主人的状态"},"answer":"D","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_5"},{"stem":"马克思主义认为，消灭“三大差别”的关键在于","options":{"A":"消灭工业与农业的差别","B":"消灭城市与乡村的差别","C":"消灭脑力劳动与体力劳动的差别","D":"消灭私有制和利益差别"},"answer":"D","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_6"},{"stem":"共产主义社会是人类社会发展的最高社会形态，这一社会实现的必要条件是","options":{"A":"社会关系的高度和谐","B":"人自由而全面的发展","C":"社会生产力的高度发展","D":"阶级和国家的消亡"},"answer":"C","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_7"},{"stem":"关于共产主义理想，以下表述中不正确的是","options":{"A":"要确定一个关于未来社会的最高目标","B":"要让人们把现实与理想社会结合起来，为实现理想而奋斗","C":"要给未来社会设计一个完美无缺的蓝图","D":"要让人们把握社会发展规律，在追求崇高理想的过程中实现人生价值"},"answer":"C","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_8"},{"stem":"马克思主义与空想社会主义在预见未来上的根本区别在于","options":{"A":"是否坚持科学的立场、观点和方法","B":"是否准确无误地预测未来","C":"是否提出未来社会的具体方案","D":"是否批判资本主义旧世界"},"answer":"A","chapter":"第七章","subject":"marx","type":"single","id":"marx_第七章_single_9"},{"stem":"马克思曾经在《1844年经济学哲学手稿》中描述：“共产主义是对私有财产即人的自我异化的积极的扬弃，因而是通过人并为了人而对人的本质的真正占有；因此，它是人向自身、也就是向社会的即合乎人性的人的复归，这种复归是完全的复归，是自觉实现并在以往发展的全部财富的范围内实现的复归。”但是，实现共产主义是一个长期的历史过程，这是因为","options":{"A":"资本主义向社会主义的转变是一个长期的过程","B":"社会主义的充分发展以及向共产主义过渡是一个长期过程","C":"经济文化落后的国家不可能跨越一种或多种社会形态","D":"共产主义在全世界范围的实现是长期、曲折的过程"},"answer":"ABD","chapter":"第七章","subject":"marx","type":"multi","id":"marx_第七章_multi_1"},{"stem":"共产主义远大理想与中国特色社会主义共同理想的关系是","options":{"A":"是最终理想与阶段性理想的关系","B":"是最高纲领与最低纲领的关系","C":"是全人类理想与全体中国人民理想的关系","D":"是人类通向共产主义的必由之路"},"answer":"ABC","chapter":"第七章","subject":"marx","type":"multi","id":"marx_第七章_multi_2"},{"stem":"马克思主义是关于无产阶级和人类解放的科学，实现共产主义是全人类解放的根本体现。人类解放包括","options":{"A":"从自然界的压迫下解放出来","B":"从客观规律的制约下解放出来","C":"从旧的社会关系的束缚下解放出来","D":"从旧的传统观念的禁锢下解放出来"},"answer":"ACD","chapter":"第七章","subject":"marx","type":"multi","id":"marx_第七章_multi_3"},{"stem":"共产主义是能够实现的社会理想，是","options":{"A":"以人类社会发展的客观规律为依据的","B":"以资本主义社会基本矛盾的发展为依据的","C":"可以用社会主义运动的实践来证明的","D":"要靠社会主义的不断完善和发展来实现的"},"answer":"ABCD","chapter":"第七章","subject":"marx","type":"multi","id":"marx_第七章_multi_4"},{"stem":"实现人的自由而全面的发展，是马克思主义追求的根本价值目标，也是共产主义社会的根本特征，共产主义社会中人的自由而全面的发展指的是","options":{"A":"全体社会成员的发展，即每一个人的发展","B":"社会不存在矛盾，人与人之间形成事实上的平等","C":"社会发展与个人发展实现了真正的统一","D":"社会发展不再以牺牲某些个人的发展为代价"},"answer":"ACD","chapter":"第七章","subject":"marx","type":"multi","id":"marx_第七章_multi_5"},{"stem":"马克思主义经典作家展望未来社会时既立足于揭示未来社会的一般特征，对未来社会的细节作了详尽描绘。（     ）","answer":"B","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_1"},{"stem":"在共产主义社会里，因为部分有觉悟的人的无私奉献，其他人才能”按需分配“。（     ）","answer":"B","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_2"},{"stem":"从时间上看，共产主义与中国特色社会主义的关系是最终理想与阶段性理想的关系。（     ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_3"},{"stem":"在共产主义社会，个人消费品分配实行“各尽所能，按劳分配”的原则。（     ）","answer":"B","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_4"},{"stem":"马克思主义认为“三大差别”中的消灭城乡差别是共产主义社会的重要特征。（     ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_5"},{"stem":"人的全面发展和社会进步密切相关，二者是辩证统一的，是相辅相成、缺一不可的 （   ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_6"},{"stem":"共产主义的实现是漫长而且充满艰难曲折的历史过程。（     ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_7"},{"stem":"新时代青年必须坚定理想信念，积极投身中国特色社会主义事业，勇做担当中华民族伟大复兴大任的时代新人。（     ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_8"},{"stem":"共产主义中的“产”指的是个人财产。（     ）","answer":"B","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_9"},{"stem":"无产阶级的解放与全人类的解放是完全一致的。（     ）","answer":"A","chapter":"第七章","subject":"marx","type":"judge","id":"marx_第七章_judge_10"},{"stem":"共产主义社会有哪些基本特征？","answer":"","chapter":"第七章","subject":"marx","type":"short","id":"marx_第七章_short_1"}]},"history":{"name":"中国近现代史纲要","chapters":[{"id":"ch0","name":"第一章"},{"id":"ch1","name":"第二章"},{"id":"ch2","name":"第三章"},{"id":"ch3","name":"第四章"},{"id":"ch4","name":"第五章"},{"id":"ch5","name":"第六章"},{"id":"ch6","name":"第七章"},{"id":"ch7","name":"第八章"},{"id":"ch8","name":"第九章"},{"id":"ch9","name":"第十章"}],"questions":[{"stem":"中国封建社会的基本生产结构（ ）。","options":{"A":"以个体家庭为单位并与家庭手工业牢固结合的小农经济","B":"自给自足的自然经济","C":"封建地主土地所有制","D":"土地私有制度"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_1"},{"stem":"（ ）标志着世界历史开始进入资本主义时代。","options":{"A":"英国光荣革命","B":"第一次工业革命","C":"地理大发现","D":"英国资产阶级革命"},"answer":"D","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_2"},{"stem":"19世纪末资本主义进入帝国主义阶段后，（ ）成为殖民主义剥削的重要形式，并出现瓜分世界的狂潮。","options":{"A":"商品输出","B":"资本输出","C":"贩卖奴隶","D":"掠夺土地"},"answer":"B","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_3"},{"stem":"鸦片战争以清政府的失败而告终。1842年8月29日，清政府与英国签订了中国近代史上的第一个不平等条约是（ ）。","options":{"A":"中英《南京条约》","B":"中英《虎门条约》","C":"中美《望厦条约》","D":"中法《黄埔条约》"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_4"},{"stem":"鸦片战争后，中国经济逐渐被卷入世界资本主义市场，其对中国的影响不包括（ ）。","options":{"A":"自给自足的自然经济逐步解体","B":"西方的先进生产技术逐步传入中国","C":"英国对华输出商品激增","D":"封建地主土地所有制瓦解"},"answer":"D","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_5"},{"stem":"中国工人阶级最早出现于（ ）。","options":{"A":"19世纪30至40年代","B":"19世纪40至50年代","C":"19世纪50至60年代","D":"19世纪60至70年代"},"answer":"B","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_6"},{"stem":"中国资产阶级也是近代中国新产生的阶级。它的来源不包括（ ）。","options":{"A":"买办","B":"商人","C":"地主","D":"城市工商业者"},"answer":"D","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_7"},{"stem":"1860年《北京条约》又规定增加开放（ ）为通商口岸。","options":{"A":"天津","B":"烟台","C":"营口","D":"台南"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_8"},{"stem":"资本-帝国主义对中国的军事侵略包括：发动侵略战争，屠杀中国人民；（ ）；勒索赔款，抢掠财富。","options":{"A":"侵占中国领土，划分势力范围","B":"享有最惠国待遇","C":"镇压中国人民的反抗","D":"扶植、收买代理人"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_9"},{"stem":"1843年（ ）规定，在通商口岸，中国人如与英侨“遇有交涉诉讼”，英国领事有“查察”“听诉”之权，“其英人如何科罪，由英国议定章程、法律，发给管事官照办”。","options":{"A":"《望厦条约》","B":"《五口通商章程》","C":"《烟台条约》","D":"《虎门条约》"},"answer":"B","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_10"},{"stem":"广学会发行的刊物（ ），在介绍西方史地、政治、文化的同时，也宣扬殖民主义奴化思想。","options":{"A":"《万国公报》","B":"《中外纪闻》","C":"《印度隶英十二益说》","D":"《泰西新史揽要》"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_11"},{"stem":"（ ），是外国侵略者控制中国政治的重要手段之一。","options":{"A":"奴化教育","B":"把持中国海关","C":"门户开放政策","D":"签订不平等条约"},"answer":"B","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_12"},{"stem":"洋货只需在海关交纳2.5%的（ ），就可以在中国内地通行无阻，不必像中国商品那样“逢关抽税，过卡抽厘”。","options":{"A":"关税","B":"海关税","C":"厘金","D":"子口税"},"answer":"D","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_13"},{"stem":"（ ），是中国近代史上中国人民第一次大规模的反侵略武装斗争，显示了中国人民不甘屈服和敢于斗争的英雄气概。","options":{"A":"虎门销烟","B":"三元里人民抗英斗争","C":"太平天国运动","D":"义和团运动"},"answer":"B","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_14"},{"stem":"资本主义列强还通过（ ），传播其价值理念：例如，1907年美国总统西奥多•罗斯福宣布将退还部分庚子赔款，用于资助中国政府选派留学生赴美留学，史称“庚款兴学”。","options":{"A":"兴办教育","B":"发展失业","C":"国民教育","D":"创建学校"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_15"},{"stem":"从1840年至1919年的80年间，中国人民对外来侵略进行了英勇顽强的反抗，这些斗争具有重大的历史作用。因为正是由于（ ），才使得经济技术落后的状况长期得不到改变。","options":{"A":"社会制度的腐败","B":"清王朝的腐朽","C":"不了解世界大势","D":"不懂得御敌之策"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_16"},{"stem":"帝国主义侵略中国的最终目的，是要（ ）。","options":{"A":"帮助中国发展资本主义","B":"传播西方先进文化","C":"为本国资本主义发展寻求市场和原料产地","D":"瓜分中国，灭亡中国"},"answer":"D","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_17"},{"stem":"郑观应在所著（ ）中提出大力发展民族工商业，同西方国家进行“商战”，设立议院，实行“君民共主”制度等主张。","options":{"A":"《劝学篇》","B":"《劝世良言》","C":"《盛世危言》","D":"《救亡决论》"},"answer":"C","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_18"},{"stem":"康有为1898年4月在（ ）的演说中把这种民族意识表达得淋漓尽致。他说：“吾中国四万万人，无贵无贱，当今日在覆屋之下，漏舟之中，薪火之上，如笼中之鸟，釜底之鱼，牢中之囚，为奴隶，为牛马，为犬羊，听人驱使，听人割宰，此四千年中二十朝未有之奇变。”","options":{"A":"保国会","B":"强学会","C":"日知会","D":"广学会"},"answer":"A","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_19"},{"stem":"中国自古以来的“天下兴亡，匹夫有责”的优良传统，得到了发扬和升华。救亡图存成了时代的主旋律。孙中山1894年11月在创立革命团体兴中会时喊出了（ ）这个时代的最强音。","options":{"A":"振兴中国","B":"伟大复兴","C":"振兴中华","D":"民族复兴"},"answer":"C","chapter":"第一章","subject":"history","type":"single","id":"history_第一章_single_20"},{"stem":"中国封建社会的社会结构特点是族权和政权相结合的封建宗法等级制度。其核心是宗族家长制，突出（ ）。","options":{"A":"父权","B":"夫权","C":"君权","D":"族长权"},"answer":"ABC","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_1"},{"stem":"资本-帝国主义列强在对中国进行文化渗透的目的包括（ ）。","options":{"A":"宣扬殖民主义奴化思想","B":"麻醉中国人民的精神","C":"进行侵略活动宣传宗教和西学","D":"摧毁中国人的民族自尊心和自信心"},"answer":"ABD","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_2"},{"stem":"中国政府举借外债，主要是以（ ）和（ ）为担保。","options":{"A":"关税","B":"厂矿","C":"盐税","D":"航运"},"answer":"AC","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_3"},{"stem":"资本-帝国主义列强对中国进行经济侵略的方式主要有（ ）。","options":{"A":"控制中国的通商口岸","B":"剥夺中国的关税自主权","C":"实行商品倾销和资本输出","D":"操纵中国的经济命脉"},"answer":"ABCD","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_4"},{"stem":"在中法战争后期，1885年3月，爱国将领冯子材指挥清军在中。境前线大败法军，取得（ ）和（ ），使法国侵略者处于内外交困的境地，茹费理内阁还为此而垮台可是清政府当权者却力主避战求和，接受法国条件签订《中法新约》，并下令前线清军停战撤兵。","options":{"A":"镇南关大捷","B":"谅山大捷","C":"宁远大捷","D":"徐东大捷"},"answer":"AB","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_5"},{"stem":"19世纪50～80年代，俄国共侵占我国领土150多万平方公里，这主要是通过（ ）完成的。","options":{"A":"《瑷辉条约》","B":"《北京条约》","C":"《勘分西北界约记》","D":"《改订伊犁条约》"},"answer":"ABCD","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_6"},{"stem":"日本则以再向中国勒索3000万两白银“赎辽费”作为补偿。三国又以干涉还辽“有功”为由，要求租借中国港湾作为报酬。三国包括（ ）。","options":{"A":"英国","B":"俄国","C":"法国","D":"德国"},"answer":"BCD","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_7"},{"stem":"19世纪70至80年代，列强从侵占中国周边邻国发展到众食中国边疆地区，（ ）、（ ）、（ ）、俄国从中亚入侵新疆。日本吞并琉球，侵犯台湾。","options":{"A":"英国从印度侵入西藏","B":"又从缅甸入侵云南","C":"法国则从越南侵犯广西","D":"葡萄牙占领澳门"},"answer":"ABC","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_8"},{"stem":"魏源在1843年1月编成（），其内容除包括世界各国的历史、地理以外，还 有总结鸦片战争经验教训、论述海防战略战术的（），翻译西人论 述的（）及西洋科技船炮图说等。","options":{"A":"《海国图志》","B":"《筹海篇》","C":"《夷情备采》","D":"《康蝤纪行》"},"answer":"ABC","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_9"},{"stem":"近代中国人民的反侵略战争（）。","options":{"A":"沉重地打击了资本—帝国主义列强的侵华野心。","B":"使我们的国家和民族历尽劫难、屡遭侵略而不亡。","C":"它表现出来的爱国主义精神，铸成了中华民族的民族魂。","D":"反侵略战争的失败，从反面教育了中国人民，极大地促进了中国人的思考、探索和奋起，反侵略战争的过程，是中华民族逐步觉醒的过程。"},"answer":"BCD","chapter":"第一章","subject":"history","type":"multi","id":"history_第一章_multi_10"},{"stem":"为什么说独立的中国逐渐变成了半殖民地的中国？","answer":"为什么说独立的中国逐步变成了半殖民地的中国? 答：这是因为，鸦片战争以后，资本—帝国主义列强通过发动侵略战争，强迫中国签订一系列不平等条约，破坏中同的领土主权、领海主权、关税主权、司法主权等，并一步一步地控制中国的政治、经济、外交和军事。中国已经丧失了完全独立的地位，在相当程度上被殖民地化了。近代中国尽管在实际上已经丧失拥有完整主权的独立国的地位，但是仍然维持着独立国家和政府的名义，还有一定的主权。由于它与连名义上的独立也没有而由殖民主义宗主国直接统治的殖民地间有区别，因此被称作半殖民地。","chapter":"第一章","subject":"history","type":"short","id":"history_第一章_short_1"},{"stem":"为什么说封建的中国逐步变成了半封建的中国？","answer":"为什么说封建的中国逐步变成了半封建的中国? 答：这是因为，外国资本—帝国主义列强用武力打开中国的门户，把中国卷入世界资本主义经济体系和世界市场之中。随着外国资本主义的入侵，在中国大量倾销商品，逐渐使中国的农业与家庭手工业分离，一方面，破坏了中国自给自足的自然经济的基础，破坏了城市的手工业和农民的家庭手工业；另一方面，则促进了中国城乡商品经济的发展，给中国资本主义的产生造成了某些客观条件。破产的农民和手工业者成了产业工人的后备军。一批官僚、买办、地主商人投资兴办新式工业。中国出现了资本主义生产关系中国已经不是完全的封建社会了，因此被称作半封建社会。","chapter":"第一章","subject":"history","type":"short","id":"history_第一章_short_2"},{"stem":"近代中国半殖民地半封建的社会有哪些特征？","answer":"谈谈近代中国半殖民地半封建的社会有哪些特征？ 第一，资本-帝国主义侵略势力不但逐步操纵了中国的财政和经济命脉，而且逐步控制了中国的政治，日益成为支配中国的决定性力量。 第二，中国的封建势力日益衰败并同外国侵略势力勾结，成为资本-帝国主义压迫、奴役中国人民的社会基础和统治支柱。 第三，中国自然经济的基础虽然遭到破坏，但是封建剥削制度的根基即封建地主的土地所有制依然在广大地区内保持着，成为中国发展进步的严重障碍。 第四，中国新兴的民族资本主义经济虽然已经产生，并在政治、文化生活中起了一定的作用，但是在帝国主义和封建主义的压迫下，它的发展很缓慢，力量很软弱，而且它的大部分与外国资本-帝国主义和本国封建主义都有或多或少的联系。 第五，由于近代中国处于资本-帝国主义列强的争夺和间接统治之下，加上中国地域广大，以及在地方性的农业经济的基础上形成的地方割据势力的存在，近代中国各地区经济、政治和文化的发展是极不平衡的。后来，帝国主义列强还分别支持不同的政治势力以分裂中国，使中国处于不统一状态。 第六，在资本-帝国主义和封建主义的双重压迫下（后来还加上官僚资本主义的压迫)，中国的广大人民尤其是农民日益贫困化以至大批地破产，过着饥寒交迫和毫无政治权利的生活。","chapter":"第一章","subject":"history","type":"short","id":"history_第一章_short_3"},{"stem":"材料一","answer":"结合所学知识，谈谈鸦片战争前和鸦片战争后中国的社会主要矛盾是什么？ 鸦片战争以前：地主阶级和农民阶级的矛盾 鸦片战争以后：帝国主义和中华民族的矛盾，封建主义和人民大众的矛盾 结合所学知识，谈谈为什么说鸦片战争是半殖民地半封建社会的开始，也是中国近代史的起点？ 第一、1840年，英国发动侵略中国的鸦片战争，中国历史发展从此发生重大转折。19世纪前期，英国已经基本上完成工业革命，成为世界资本主义最强大的国家。在亚洲，继占领印度后，中国成为它的主要目标。 第二、英国对华贸易长期处于入超状态，于是，英国殖民者以走私毒品鸦片作为牟取暴利及改变贸易逆养的手段，向中国贩卖鸦片。据不完全统计，鸦片战争前40年间，英国运入中国的鸦片约有40万箱。 第三、1825年和1837年英国发生了两次次资本主义经济危机。为了摆脱危机和转移国内人民的视线，英国政府迫不及待地要发武一场侵略战争。1840年4月，英国议会通过对华战争的决定。1840年6月，英国封锁了珠江入内口和广东海面。鸦片战争正式爆发。鸦片战争以清政府的失败而告终。 第四、1842年8月29日，清政府与英国签订了中国近代史上第一个不平等条约—《南京条约》。接着，相继又签订了《虎门条约》，与美国签订了《望厦条约》，与法国签订了《黄埔条约》。通过这一系列不平等条约，英国等西方列强在中国攫取了大最侵略特权。 第五、随着外国资本主义的入侵，中国的封建社会逐步变成了半殖民地半封建社会。正因如此，鸦片战争就成为中国近现代史的起点。","chapter":"第一章","subject":"history","type":"essay","id":"history_第一章_essay_1"},{"stem":"太平天国之所以是中国农民战争发展的最⾼峰，最主要是因为","options":{"A":"制定了⽐较完整的⾰命纲领","B":"建⽴了与清朝政府对⽴的政权","C":"其规模和延续时间均属空前","D":"对封建王朝的打击空前严重"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_1"},{"stem":"《资政新篇》的主张在太平天国内部并未引起⼴泛的影响，其根本原因是","options":{"A":"当时战事紧张，⽆暇顾及","B":"超越了农民战争应当承担的历史使命","C":"没有反映当时社会的主要⽭盾","D":"不切合当时中国社会的实际"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_2"},{"stem":"洋务运动欲“自强”而不强的结局，从根本上说是因为","options":{"A":"没有坚决反对西方列强侵略","B":"没有从根本上触动中国旧式的社会生产关系","C":"创办的近代企业采用落后的生产方式","D":"西方资本主义列强的破坏"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_3"},{"stem":"中国近代史上提出“以中国之伦常名教为原本,辅以诸国富强之本”之说的思想家是","options":{"A":"李鸿章","B":"左宗棠","C":"冯桂芬","D":"张之洞"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_4"},{"stem":"洋务派创办军事⼯业的⽅式是","options":{"A":"官办","B":"官督商办","C":"官商合办","D":"商办"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_5"},{"stem":"洋务运动时期，主要培养翻译人才的学校是","options":{"A":"京师大学堂","B":"工艺学堂","C":"船政学堂","D":"京师同文馆"},"answer":"B","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_6"},{"stem":"洋务运动中，洋务派创办的最⼤的军事⼯业是","options":{"A":"福州船政局","B":"天津机器局","C":"湖北枪炮厂","D":"上海江南制造总局"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_7"},{"stem":"戊戌维新时期，梁启超的主要著述是（） A《日本变政考》 B《仁学》 C《新学伪经考》 D《变法通议》 戊戌维新运动的性质是","options":{"A":"农民阶级反封建斗争","B":"地主阶级改良运动","C":"资产阶级改良运动","D":"资产阶级革命运动"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_8"},{"stem":"戊戌维新时期，康有为主持的重要学堂是","options":{"A":"京师大学堂","B":"广方言馆","C":"时务学堂","D":"广州万木草堂"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_9"},{"stem":"对洋务派兴办洋务事业的指导思想最先作出比较完整表述的是","options":{"A":"冯桂芬","B":"李鸿章","C":"林则徐","D":"魏源"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_10"},{"stem":"1898年6月下“明定国是”诏，宣布变法维新的皇帝是","options":{"A":"康熙帝","B":"乾隆帝","C":"光绪帝","D":"溥仪帝"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_11"},{"stem":"戊戌维新时期，维新派在上海创办的影响较大的报刊是","options":{"A":"《时务报》","B":"《国闻报》","C":"《湘报》","D":"《万国公报》"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_12"},{"stem":"1851年1月，洪秀全在广西领导农民起义的地点是","options":{"A":"安庆","B":"永安","C":"金田村","D":"武昌"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_13"},{"stem":"洋务运动中，左宗棠率领的用洋枪装备的军队是","options":{"A":"鄂军","B":"淮军","C":"新军","D":"湘军"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_14"},{"stem":"戊戌变法运动的突出历史功绩在于","options":{"A":"挽救了民族危亡","B":"推行了资本主义的政治改革","C":"促进了思想启蒙","D":"极大发展了资本主义经济"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_15"},{"stem":"戊戌政变后，慈禧太后重新“垂帘听政”的名义是","options":{"A":"“军政”","B":"“宪政”","C":"“亲政”","D":"“训政”"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_16"},{"stem":"标志洋务运动破产的事件是？","options":{"A":"甲午战争失败","B":"戊戌政变","C":"义和团运动","D":"八国联军侵华"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_17"},{"stem":"“公车上书”的直接导火索是？","options":{"A":"《马关条约》签订","B":"甲午战败","C":"戊戌变法","D":"瓜分狂潮"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_18"},{"stem":"戊戌变法的代表人物是？","options":{"A":"康有为、梁启超","B":"李鸿章、张之洞","C":"孙中山、黄兴","D":"陈独秀、李大钊"},"answer":"C","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_19"},{"stem":"戊戌变法持续的时间是？","options":{"A":"103天","B":"1年","C":"3个月","D":"50天"},"answer":"D","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_20"},{"stem":"维新派代表人物中，撰写《新学伪经考》《孔子改制考》的是？","options":{"A":"梁启超","B":"创办新式学堂","C":"推翻封建专制","D":"发展民主政治"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_21"},{"stem":"《马关条约》中割让的领土不包括？","options":{"A":"辽东半岛","B":"台湾全岛","C":"澎湖列岛","D":"香港岛"},"answer":"A","chapter":"第二章","subject":"history","type":"single","id":"history_第二章_single_22"},{"stem":"太平天国农民战争爆发的原因有","options":{"A":"鸦片战争失败后，清政府加重了赋税","B":"各级官吏横征暴敛，农民的负担加重","C":"西方资本帝国主义的入侵，中国的自然经济逐渐解体","D":"满汉民族矛盾"},"answer":"ABC","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_1"},{"stem":"下列关于《天朝田亩制度》叙述正确的是","options":{"A":"体现了农民平均分配土地的愿望","B":"是以解决土地问题为中心的比较完整的社会改革方案","C":"具有空想性质，不可能实现","D":"否定了封建土地所有制"},"answer":"ABCD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_2"},{"stem":"天京事变中发生的历史事件包括","options":{"A":"陈玉成、李秀成等青年将领被提拔","B":"杨秀清、韦昌辉被杀","C":"石达开出走","D":"洪仁玕开始总领朝政"},"answer":"BC","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_3"},{"stem":"与太平军作战的外国军队包括（） 《天朝田亩制度》的局限性体现在","options":{"A":"绝对平均主义不切实际 B 没有触及封建土地私有制 C缺乏实施的社会条件 D 不利于调动生产积极性","B":"“哥萨克旅”","C":"“十字军”","D":"“常捷军”"},"answer":"AD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_4"},{"stem":"下列关于洋务运动叙述正确的是","options":{"A":"是封建统治阶级的一场自救运动","B":"是由资产阶级发动的","C":"口号是“自强”和“求富”","D":"触及到了封建统治的根基"},"answer":"ACD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_5"},{"stem":"洋务运动时期，不属于弈䜣的主张是","options":{"A":"“灭发、捻为先，治俄次之，治英又次之”","B":"“但求外敦和好，内要自强”","C":"“师夷长技以制夷”","D":"“变者天下之公理也”"},"answer":"AC","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_6"},{"stem":"下列人物中属于洋务派的有","options":{"A":"曾国藩","B":"奕诉","C":"张之洞","D":"左宗棠"},"answer":"BCD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_7"},{"stem":"康有为向光绪皇帝进呈的介绍外国变法经验教训的书籍是","options":{"A":"《日本变政考》","B":"《俄彼得变政记》","C":"《波兰分灭记》","D":"《新学伪经考》"},"answer":"ABCD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_8"},{"stem":"下列关于戊戌变法的说法正确的是","options":{"A":"“公车上书”为变法维新运动揭开了序幕","B":"戊戌变法从开始到失败历时103天","C":"慈禧太后为首的保守势力镇压了戊戌变法","D":"是中国民族资产阶级第一次登上政治舞台"},"answer":"ABC","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_9"},{"stem":"以下属于戊戌六君子的是","options":{"A":"谭嗣同","B":"梁启超","C":"林旭","D":"康广仁"},"answer":"ABCD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_10"},{"stem":".甲午战争失败对中国的直接影响有？","options":{"A":"废除八股取士","B":"设立京师大学堂","C":"裁撤冗官","D":"实行君主立宪"},"answer":"ACD","chapter":"第二章","subject":"history","type":"multi","id":"history_第二章_multi_11"},{"stem":"洋务运动失败的主要原因是什么？","answer":"","chapter":"第二章","subject":"history","type":"short","id":"history_第二章_short_1"},{"stem":"洋务运动期间举办了哪些洋务事业?","answer":"","chapter":"第二章","subject":"history","type":"short","id":"history_第二章_short_2"},{"stem":"维新派与守旧派论战的焦点有哪些？","answer":"","chapter":"第二章","subject":"history","type":"short","id":"history_第二章_short_3"},{"stem":"太平天国农民战争的意义和失败的原因、教训?","answer":"答:太平天国农名战争虽然失败了，但是有不可磨灭的历史功绩和重大的历史意义，具体表现为： 第一，沉重打击了清王朝的封建专制统治秩序，强烈撼动了清政府的统治根基。 第二，是中国旧式农民战争的最高峰。具有不同于以往农名战争的新的历史特点。 第三，冲击了孔子和儒家经典的正统权威，这在一定程度上削弱了封建统治的精神支柱。 第四，有力地打击了外国侵略势力。 第五，在19世纪中叶的亚洲民族解放运动中，和其他亚洲国家的民族解放运动汇合在一起，冲击了西方殖民主义者在亚洲的统治。 太平天国农民战争失败的原因： 客观上，清政府实行“借师助剿”，双方实力对比悬殊。 主观上：第一，农民阶级不是新的生产力和生产关系的代表，无法克服小生产者所固有的阶级局限性，缺乏科学思想理论的指导，没有先进阶级的领导，因而无法从根本上提出完整的、正确的政治纲领和社会改革方案。 第二，后期无法制止和克服领导集团自身腐败现象的滋生，领导集团的一些人在生活上追求享乐，在政治上争权夺利。 第三，军事战略上出现重大失误。没有解决好与捻军的关系，没有同他们结成同盟。天京被围的时候又“死守孤城”。 第四，以宗教来发动、组织群众，拜上帝教教义不仅不能正确指导斗争，而且给农民战争带来了危害。 第五，未能正确对待儒学。 第六，对于西方资本主义侵略者缺乏理性的认识，不能把西方国家的侵略者与其人民群众区别开来。 经验教训：在半殖民地半封建的中国，农民具有伟大的革命潜力，但它自身不能担负起领导反帝反封建斗争取得胜利的重任。单纯的农民战争不可能完成争取民族独立和人民解放的历史任务。","chapter":"第二章","subject":"history","type":"essay","id":"history_第二章_essay_1"},{"stem":"戊戌维新运动的意义和失败的原因、教训？","answer":"戊戌维新运动失败的原因 戊戌维新运动的失败，主要是由于维新派自身的局限和以慈禧太后为首的强大的守旧势力的反对。同时资产阶级维新派自身的局限性也是这场运动失败的重要原因，具体表现在以下三个方面;一是不敢否定封建主义。二是对帝国主义抱有幻想。三是惧怕人民群众。","chapter":"第二章","subject":"history","type":"essay","id":"history_第二章_essay_2"},{"stem":"为什么说19世纪中后期的三次探索（太平天国、洋务运动、戊戌变法）都以失败告终","answer":"答：阶级局限性：农民阶级不代表先进生产力，无科学理论；地主阶级洋务派维护封建统治，拒绝制度变革；资产阶级维新派软弱妥协，不敢彻底反帝反封建。 时代与社会条件：半殖民地半封建国情，中外反动势力强大，联合绞杀革命与改革；民族资本主义发展不充分，资产阶级力量薄弱；封建思想根深蒂固，改革阻力大。 探索局限：均未找到适合中国的正确道路，或局限农民战争，或仅学技术，或温和改良，均未彻底解决中国社会根本矛盾。","chapter":"第二章","subject":"history","type":"essay","id":"history_第二章_essay_3"},{"stem":"资产阶级革命派的骨干是一批() ①小资产阶级知识分子 ②无产阶级 ③买办阶级 ④资产阶级 ⑤工人阶级","options":{"A":"①⑤","B":"①④","C":"③④","D":"③⑤"},"answer":"B","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_1"},{"stem":"1903年，章炳麟发表《驳康有为论革命书》，反对康有为的保皇观点，歌颂革命为（ ）的良药","options":{"A":"思想解放，除旧布新","B":"启迪民智，推陈出新","C":"顺应民意，推陈出新","D":"启迪民智，除旧布新"},"answer":"D","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_2"},{"stem":"1894年11月，孙中山到檀香山组建了第一个革命团体兴中会，立誓驱除鞑虏、（ ）、创立合众政府","options":{"A":"恢复中国","B":"恢复民主","C":"恢复中华","D":"平均地权"},"answer":"A","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_3"},{"stem":"南京临时政府制定的各项政策措施，集中代表和反映了中国（ ）的愿望和利益，在相当程度上也符合广大中国人民的利益","options":{"A":"新兴工人阶级","B":"民族资产阶级","C":"买办资产阶级","D":"官僚资产阶级"},"answer":"B","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_4"},{"stem":"（ ）年1月1日，孙中山在南京宣誓就职，改国号为中华民国","options":{"A":"1911","B":"1921","C":"1912","D":"1913"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_5"},{"stem":"毛泽东指出：“中国反帝反封建的（ ）,正规说起来,是从孙中山开始的”","options":{"A":"资产阶级民主改革","B":"资产阶级民主革命","C":"无产阶级民主革命","D":"无产阶级民主改革"},"answer":"B","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_6"},{"stem":"毛泽东说：“民国元年的《中华民国临时约法》，在那时期是一个比较好的东西；当然，是不完全的、有缺点的，是资产阶级性的，但它带有（ ）。” ① 革命性 ②人民性 ③科学性 ④民主性","options":{"A":"①②","B":"②③","C":"①④","D":"③④"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_7"},{"stem":"1912年8月,宋教仁在征得（ ）、（ ）的同意后,以同盟会为基础联合其他几个政党,组成国民党 ①陈独秀 ②孙中山 ③毛泽东 ④黄兴","options":{"A":"①③","B":"③④","C":"②③","D":"②④"},"answer":"D","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_8"},{"stem":"民权主义的内容是“创立民国”，即推翻（ ），建立资产阶级民主共和国","options":{"A":"封建王朝专制制度","B":"封建地主专制制度","C":"封建君主专制制度","D":"封建军阀专制制度"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_9"},{"stem":"以下说法，错误的是","options":{"A":"民族主义包括“驱除鞑虏,恢复中国”","B":"民族主义包括“驱除鞑虏,恢复中华”","C":"三民主义包括‌民族主义‌、‌民权主义‌和‌民生主义‌","D":"同盟会的成立标志着中国资产阶级民主革命进入了一个新的阶段"},"answer":"A","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_10"},{"stem":"袁世凯窃夺辛亥革命的果实之后，建立了代表大地主和（ ）利益的北洋军阀反动政权","options":{"A":"民族资产阶级","B":"买办资产阶级","C":"封建地主阶级","D":"知识分子阶级"},"answer":"B","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_11"},{"stem":"预备立宪并没有能够挽救清王朝，反而激化了社会矛盾，主要原因在于清政府改革的根本目的是为了","options":{"A":"延续其反动统治","B":"发展资本主义","C":"缓和阶级矛盾","D":"挽救民族危机"},"answer":"A","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_12"},{"stem":"1917年9月，在广州成立以孙中山为大元帅的护法军政府，并出师","options":{"A":"讨袁","B":"反袁","C":"北伐","D":"北上"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_13"},{"stem":"中华革命党带有强烈的（ ），严重脱离群众，社会影响不大","options":{"A":"反动性","B":"封建性","C":"买办性","D":"宗派性"},"answer":"D","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_14"},{"stem":"孙中山指出，辛亥革命之所以失败，“非袁氏兵力之强，实同党人心之涣”，这表明","options":{"A":"旧官僚、立宪派不支持革命","B":"不能充分发动和依靠人民群众","C":"没有提出彻底的反帝反封建的革命纲领","D":"不能建立坚强的革命政党"},"answer":"D","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_15"},{"stem":"孙中山说：“曾几何时，已为情势所迫，不得已而与反革命的专制阶级谋妥协。此种妥协，实间接与帝国主义相调和。遂为革命第一次失败之根源。”这说明","options":{"A":"反革命的专制阶级是帝国主义","B":"资产阶级主动采取了灵活措施","C":"没有提出彻底的反帝反封建的革命纲领","D":"不能充分发动和依靠人民群众"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_16"},{"stem":"下列不是同盟会得以成⽴的条件是","options":{"A":"革命形势有了重⼤发展","B":"清政府“预备立宪”破产","C":"民主革命思想⼴泛传播","D":"资产阶级革命团体纷纷建⽴"},"answer":"B","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_17"},{"stem":"南京临时政府是⼀个革命政府，对其依据表述，不正确的是（ ）。","options":{"A":"以⾰命⼿段夺取政权⽽建⽴","B":"⾰命派在政权中占⼤多数","C":"政府颁布了反封建的法定措施","D":"政府不向帝国主义妥协"},"answer":"D","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_18"},{"stem":"1912年3⽉第⼀届内阁在南京组成，其内阁总理是（ ）。","options":{"A":"陈其美","B":"蔡元培","C":"唐绍仪","D":"宋教仁"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_19"},{"stem":"1903年6月，章炳麟在上海（ ）发表《驳康有为论革命书》，批驳康有为所谓“中国之可立宪，不可革命”的谬论","options":{"A":"《皖报》","B":"《沪报》","C":"《苏报》","D":"《民报》"},"answer":"C","chapter":"第三章","subject":"history","type":"single","id":"history_第三章_single_20"},{"stem":"以下关于辛亥革命的说法，正确的是","options":{"A":"推翻了清朝政府","B":"结束了在中国延续几千年的君主专制制度","C":"孙中山在日本建立了兴中会","D":"没有完成反帝反封建的任务"},"answer":"ABD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_1"},{"stem":"清末“新政”的内容包括","options":{"A":"设立商部、学部、巡警部等中央行政机构","B":"裁撤绿营，建立新军","C":"颁布商法商律，奖励工商","D":"颁布新的学制"},"answer":"ABCD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_2"},{"stem":"20世纪初，传播民主革命思想的书籍纷纷涌现，其中包括","options":{"A":"《革命军》","B":"《猛回头》《警世钟》","C":"《变法通议》","D":"《驳康有为论革命书》"},"answer":"ABD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_3"},{"stem":"20世纪初，宣传资产阶级民主革命思想的主要人物有","options":{"A":"康有为","B":"章炳麟","C":"邹容","D":"陈天华"},"answer":"BCD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_4"},{"stem":"中国同盟会纲领中涉及到的问题有","options":{"A":"推翻满洲贵族的统治","B":"建立资产阶级共和国","C":"驱逐占据中国的帝国主义势力","D":"提出了资本主义的土地纲领"},"answer":"ABD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_5"},{"stem":"1905年至1907年间，资产阶级革命派与改良派论战的主要议题是","options":{"A":"要不要以革命手段推翻清王朝","B":"要不要推翻帝制，实行共和","C":"要不要社会革命","D":"要不要废科举和兴西学"},"answer":"ABC","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_6"},{"stem":"策划武昌起义的革命党领导人是","options":{"A":"黄兴","B":"黎元洪","C":"蒋翊武","D":"孙武"},"answer":"CD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_7"},{"stem":"《临时约法》的内容包括","options":{"A":"中华民国主权属于国民全体","B":"人民享有各项权利","C":"实行总统制，总统有行政、立法、司法权","D":"国家体制实行内阁制"},"answer":"ABD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_8"},{"stem":"袁世凯篡夺辛亥革命胜利果实的主要原因是","options":{"A":"帝国主义和国内封建势力的支持","B":"袁世凯拥有强大的军事力量","C":"袁世凯假意赞成共和","D":"资产阶级的软弱性"},"answer":"ABCD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_9"},{"stem":"以袁世凯为首的北洋军阀投靠帝国主义的表现为","options":{"A":"出卖路权、矿权，大肆借款，并签订众多不平等条约","B":"与列强签订“善后大借款”合同，使列强控制和监督中国财政","C":"基本接受日本提出的严重损害中国权益的“二十一条”","D":"以各种手段兼并土地，对农民征收苛捐杂税"},"answer":"ABCD","chapter":"第三章","subject":"history","type":"multi","id":"history_第三章_multi_10"},{"stem":"论述辛亥革命的历史意义","answer":"在近代历史上，辛亥革命是中国人民为救亡图存、振兴中华而奋起革命的一座里程碑，它使中国发生了历史性的巨变，具有伟大的历史意义。 第一，辛亥革命推翻了封建势力的政治代表、帝国主义在中国的代理人清王朝的统治，沉重打击了中外反动势力，使中国反动统治者在政治上乱了阵脚。在这以后，帝国主义和封建势力在中国再也不能建立起比较稳定的统治，从而为中国人民斗争的发展开辟了道路。 第二，辛亥革命结束了中国延续两千多年的封建君主专制制度，建立了中国历史上第一个资产阶级共和政府，使民主共和的观念开始深入人心，并在中国形成了“敢有帝制自为者，天下共击之”的民主主义观念。正因为如此，当袁世凯、张勋先后复辟帝制时，均受到了社会舆论的强烈谴责和人民群众的坚决反抗。 第三，辛亥革命推动了中国人民的思想解放。自古以来，皇帝被看作至高无上、神圣不可侵犯的绝对权威，如今连皇帝都可以被打倒，那么还有什么陈腐的东西不可以被怀疑、不可以被抛弃?辛亥革命激发了人民的爱国热情和民族觉醒，打开了禁锢思想进步的闸门。 第四，辛亥革命推动了中国的社会变革，促使中国的社会经济、思想习惯和社会风俗等方面发生了新的积极变化。南京临时政府成立后，以振兴实业为目标，设立实业部，先后颁布了一系列有利于工商业发展的政策和措施，以推动民族资本主义经济的发展，使随后的几年成了资本主义发展的“黄金时代”。革命政府还提倡社会新风，扫除旧时代的“风俗之害”。 第五，辛亥革命不仅在一定程度上打击了帝国主义的侵略势力，而且推动了亚洲各国民族解放运动的高涨。","chapter":"第三章","subject":"history","type":"essay","id":"history_第三章_essay_1"},{"stem":"论述三民主义学说的基本内容    \n    同盟会的政治纲领是“驱除鞑虏，恢复中华，创立民国，平均地权。”1905年11月，在同盟会机关报《民报》发刊词中，孙中山将同盟会的纲领概括为三大主义，即民族主义、民权主义、民生主义，后被称为三民主义。\n   民族主义包括“驱除鞑虏，恢复中华”两项内容。一是要以革命\n手段推翻清朝政府，改变它一贯推行的民族歧视和民族压迫政策；二是追求独立，建立“民族独立的国家”，变半殖民地半封建社会的中国为独立的中国。但是，同盟会纲领中的民族主义没有从正面鲜明地提出反对帝国主义的主张。当时的革命派对于帝国主义的本质认识不清，害怕帝国主义干涉，甚至幻想以承认不平等条约“继续有效”为条件来换取列强对自己的支持。同时，他们也没有明确地把汉族军阀、官僚、地主作为革命对象，从而给了这部分人后来从内部和外部破坏革命以可乘之机。\n   民权主义的内容是“创立民国”，即推翻封建专制制度，建立资产阶级民主共和国。这就是孙中山所说的政治革命。不过，民权主义虽然强调了要建立民主共和国，却忽略了广大劳动群众在国家中的地位，因而难以使人民的民主权利得到真正地保证。\n   民生主义在当时指的是“平均地权”，也就是孙中山所说的社会革命。但是孙中山的“平均地权”脱离了中国的实际，它没有触动封建土地所有制，不能满足广大农民的土地要求，在革命中难以成为发动广大工农群众的理论武器。\n    孙中山的三民主义学说，初步描绘出中国还不曾有过的资产阶级共和国方案，是一个比较完整而明确的资产阶级民主革命纲领。它的提出，对推动革命的发展产生了重大而积极的影响。","answer":"","chapter":"第三章","subject":"history","type":"essay","id":"history_第三章_essay_2"},{"stem":"论述辛亥革命爆发的历史条件\n   民族危机加深，社会矛盾激化。戊戌维新运动失败后，以孙中山为代表的革命派在中国掀起了一场资产阶级革命运动。这场革命的发生，是当时民族危机加深、社会矛盾激化的结果。","answer":"","chapter":"第三章","subject":"history","type":"essay","id":"history_第三章_essay_3"},{"stem":"新文化运动是从1915年9月（ ）在上海创办《青年杂志》开始的。","options":{"A":"蔡元培","B":"陈独秀","C":"鲁迅","D":"胡适"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_1"},{"stem":"中国工人阶级政党最早的组织，是在中国工人阶级最密集的中心城市（ ）建立的。","options":{"A":"北京","B":"上海","C":"武汉","D":"青岛"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_2"},{"stem":"下列口号中不是五四运动期间学生在示威游行时高呼的是（ ）。","options":{"A":"“打倒列强，除军阀”","B":"“取消二十一条”","C":"“还我青岛”","D":"“外争国权，内惩国贼”"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_3"},{"stem":"关于新文化运动与欧洲启蒙运动，下列说法错误的是（ ）。","options":{"A":"都促进了自然科学的发展","B":"都引发了一场大规模的资产阶级革命运动","C":"都正面批判了封建思想","D":"都属于资产阶级的反封建斗争"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_4"},{"stem":"第一次国共合作采取了共产党员以个人身份加⼊国民党的“党内合作”方式，最早提出这种方式的是（ ）。","options":{"A":"共产国际","B":"中国共产党","C":"孙中山","D":"廖仲恺"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_5"},{"stem":"一战期间，中国资本主义的发展出现了一个“短暂的春天”，这从根本上说明（ ）。","options":{"A":"辛亥革命为资本主义发展创造了条件","B":"列强侵略是中国资本主义发展的主要障碍","C":"欧洲战争提供了极大商机","D":"资本主义在中国有很大发展潜力"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_6"},{"stem":"大革命的失败给中国共产党最深刻的教训是（ ）。","options":{"A":"坚持无产阶级对革命的领导权","B":"坚持武装斗争","C":"不能相信资产阶级","D":"坚持走农村包围城市的道路"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_7"},{"stem":"五四运动是中国新民主主义革命的开端，最主要的依据是（ ）。","options":{"A":"彻底的反帝反封建的斗争","B":"无产阶级成为运动的主力","C":"是先进阶级领导的具有⼴泛群众基础","D":"十月革命的影响"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_8"},{"stem":"与资产阶级改良派、革命派的思想相⽐，前期的新文化运动的作用主要新在（ ）。","options":{"A":"传播了资产阶级民权平等思想","B":"深⼊研究和传播了马克思主义","C":"绝对肯定了西方文化的进步性","D":"较为彻底地批判了儒家正统思想"},"answer":"D","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_9"},{"stem":"第一次国共合作时，采取共产党和共青团员以个人⾝份加⼊国民党，实⾏党内合作的主要原因是 ( )。","options":{"A":"便于在国民党内部开展组织工作","B":"借助国民党的威望和地位壮大共产党的力量","C":"对国民党实⾏内部⽡解","D":"能被孙中⼭接受，有利于国民党改组"},"answer":"D","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_10"},{"stem":"十月革命的胜利对殖民地半殖民地国家产生了巨大影响，中国先进知识分子（ ）。","options":{"A":"找到了一条改造中国的新的革命道路","B":"提出了民主与科学才能使中国富强的主张","C":"提出了彻底的反帝反封建的民主革命的纲领","D":"认识到了统一战线是中国革命胜利的法宝"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_11"},{"stem":"中国共产党之所以能够明确提出彻底的民主革命纲领，最主要的原因是（ ）。","options":{"A":"中国共产党是无产阶级政党","B":"中国共产党具有广泛的群众基础","C":"中国共产党得到共产国际的支持","D":"中国共产党正确认识和分析中国国情"},"answer":"D","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_12"},{"stem":"五四运动的直接导火线是（ ）。","options":{"A":"袁世凯接受日本提出的“二十一条”","B":"俄国十月革命的胜利","C":"巴黎和会上中国的外交失败","D":"李大钊《庶民胜利》的发表"},"answer":"C","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_13"},{"stem":"中国共产党一经成⽴，中国革命就展现了新的⾯貌。不久中国共产党就开始采取民族资产阶级、 ⼩资产阶级的政党和政治派别没有采取过也不可能采取的路线，即","options":{"A":"⼟地革命的方法","B":"群众路线的方法","C":"统一战线的方法","D":"武装斗争的方法"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_14"},{"stem":"对新文化运动，毛泽东曾作出这样的评价：“他们对于现状，对于历史，对于外国事物，没有历史唯物主义的批判精神，所谓坏的就是绝对坏，好的就是绝对好，一切都好。”这段话指出了新文化存在的缺陷是（ ）。","options":{"A":"对东西方文化的认识存在绝对化的倾向","B":"尚未领会马克思主义理论的精髓","C":"没有动摇封建正统思想的统治地位","D":"矫枉过正是文化运动的通病"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_15"},{"stem":"中国共产党第一次全国代表大会召开地点是？","options":{"A":"上海和嘉兴南湖","B":"北京","C":"广州","D":"武汉"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_16"},{"stem":"北伐战争的主要对象是？","options":{"A":"吴佩孚、孙传芳、张作霖","B":"袁世凯、段祺瑞、冯国璋","C":"蒋介石、汪精卫","D":"日本侵略者"},"answer":"A","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_17"},{"stem":"1923年6月举行的中国共产党第（ ）次全国代表大会决定共产党以个人身份加入国民党，以实现国共合作。","options":{"A":"二","B":"三","C":"四","D":"五"},"answer":"B","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_18"},{"stem":"（ ）标志着国共第一次合作正式形成。","options":{"A":"中国共产党第二次全国代表大会","B":"中国共产党第四次全国代表大会","C":"国民党一大的召开","D":"广东国民政府的建立"},"answer":"C","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_19"},{"stem":"（ ）前后坚持16个月之久，是中国工人运动史上持续时间最长的一次政治大罢工。","options":{"A":"香港海员罢工","B":"京汉铁路工人罢工","C":"安源路矿工人罢工","D":"省港大罢工"},"answer":"D","chapter":"第四章","subject":"history","type":"single","id":"history_第四章_single_20"},{"stem":"1925 年至 1927 年的大革命规模宏伟，内涵丰富。与辛亥革命相比较，其不同点在于( )。","options":{"A":"它广泛而深刻地发动了工农群众","B":"它的主要斗争形式是武装斗争","C":"它的革命对象是帝国主义和封建军阀","D":"它是在以国共合作为基础的统一战线的组织形式下进行的"},"answer":"ACD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_1"},{"stem":"新文化运动的主要阵地有( )。","options":{"A":"《新青年》杂志","B":"北京大学","C":"《中外纪闻》","D":"《时务报》"},"answer":"AB","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_2"},{"stem":"中国早期信仰马克思主义的人物的类型主要有( )。","options":{"A":"一部分原同盟会会员、辛亥革命时期的活动家","B":"五四以前新文化运动的精神领袖","C":"第一个工人运动高潮中工人领袖","D":"五四爱国运动的左翼骨干"},"answer":"ABD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_3"},{"stem":"十月革命推动中国的先进分子从资产阶级民主主义转向社会主义的原因是： ( )。","options":{"A":"十月革命启示中国人在经济文化落后的国家也可以用社会主义指引自己走向解放之路","B":"十月革命后，苏维埃俄国号召反对帝国主义，以新的平等姿态对待中国，推动了社会主义思想在中国的传播","C":"十月革命中工人和士兵的广泛发动并由此赢得胜利的事实昭示中国先进分子以新的方法开展革命","D":"十月革命一声炮响，给我们送来了马克思列宁主义"},"answer":"ABC","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_4"},{"stem":"下列人物中参加过中共一大的有( )。","options":{"A":"陈独秀","B":"陈公博","C":"李达","D":"张国焘"},"answer":"BCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_5"},{"stem":"国民党一大的主要内容及意义是","options":{"A":"讨论了国民党改组的问题","B":"重新解释了三民主义","C":"确立了联俄联共扶助农工政策","D":"标志第一次国共合作的正式形成"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_6"},{"stem":"中国早期马克思主义思想运动的特点是（ ）。","options":{"A":"重视对马克思主义基本理论的学习","B":"明确地同第二国际的社会民主主义划清界限","C":"注意从中国实际出发，学习、运用马克思主义的理论","D":"开始提出知识分子应当同劳动群众相结合的思想"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_7"},{"stem":"1915 年 9 月，陈独秀在上海创办《青年杂志》(后改名《新青年》)，吹响了新文化运动的号角。新文化运动高举民主和科学两面大旗，向封建主义思想文化发起了前所未有的猛烈冲击。 新文化运动的历史意义表现在它( )。","options":{"A":"彻底否定了孔学的历史作用","B":"在社会上掀起了一股思想解放的潮流","C":"为马克思主义在中国的传播创造了有利条件","D":"是中国历史上一次前所未有的启蒙运动"},"answer":"BCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_8"},{"stem":"关于“新三民主义”，下列说法正确的有( )。","options":{"A":"提出民主权利应“为一般平民所共有”","B":"民族主义中增加了反帝的内容","C":"提出要改善工农的生活状况","D":"与中共在民主革命阶段的纲领基本一致"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_9"},{"stem":"新文化运动中宣传十月革命的著作有（ ）。","options":{"A":"《我的马克思主义观》","B":"《法俄革命之比较观》","C":"《庶民的胜利》","D":"《 Bolshevism 的胜利》"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_10"},{"stem":"新文化运动的主要内容有？","options":{"A":"提倡民主与科学","B":"反对封建礼教","C":"提倡白话文","D":"传播马克思主义"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_11"},{"stem":"（ ）标志着国共第一次合作全面破裂，大革命最终失败。","options":{"A":"四一二反革命政变","B":"七一五反革命政变","C":"中山舰事件","D":"整理党务案"},"answer":"AB","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_12"},{"stem":"中国共产党早期组织创办的专供工人阶级阅读的马克思主义启蒙教育刊物包括（ ）。","options":{"A":"《劳动届》","B":"《劳动音》","C":"《工人月刊》","D":"《济南劳动月刊》"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_13"},{"stem":"伟大建党精神的主要内容包括( ）。","options":{"A":"坚持真理、坚守理想","B":"践行初心、担当使命","C":"不怕牺牲、英勇斗争","D":"对党忠诚、不负人民"},"answer":"ABCD","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_14"},{"stem":"新文化运动的倡导者以（ ）为主要武器。","options":{"A":"提倡资产阶级民主主义","B":"进化论观点","C":"个性解放思想","D":"民主和科学"},"answer":"BC","chapter":"第四章","subject":"history","type":"multi","id":"history_第四章_multi_15"},{"stem":"为什么说五四运动是中国新民主主义革命的开端？","answer":"五四运动以彻底反帝反封建的革命性、追求救国强国真理的进步性、各族各界群众积极参与的广泛性，推动了中国社会进步，促进了马克思主义在中国的传播，促进了马克思主义同中国工人运动的结合，为中国共产党的成立做了思想上干部上的准备，为新的革命力量、革命文化、革命斗争登上历史舞台创造了条件。因此，五四运动成为中国新民主主义革命的开端。","chapter":"第四章","subject":"history","type":"short","id":"history_第四章_short_1"},{"stem":"简述中国早期信仰马克思主义者的类型及代表人物","answer":"（1）五四以前的新文化运动的精神领袖，代表人物有李大钊、陈独秀。 （2）五四爱国运动的左翼骨干，代表人物有毛泽东、蔡和森、周恩来。 （3）一部分原中国同盟会会员，辛亥革命时期的活动家，代表人物有董必武、吴玉章、林伯渠。 中国早期马克思主义者的队伍中李大钊、陈独秀属于先驱者和擎旗人，毛泽东等五四运动的左翼骨干则是其主体部分。","chapter":"第四章","subject":"history","type":"short","id":"history_第四章_short_2"},{"stem":"中国共产党成立的历史意义？","answer":"","chapter":"第四章","subject":"history","type":"short","id":"history_第四章_short_3"},{"stem":"五四运动的历史意义？","answer":"","chapter":"第四章","subject":"history","type":"short","id":"history_第四章_short_4"},{"stem":"新文化运动与五四运动之间的相互影响有哪些？","answer":"（1）前期新文化运动动摇了封建正统思想的统治地位，掀起了一股思想解放潮流，为五四运动做了思想宣传； （2）新文化运动的领导者陈独秀、李大钊等人指导和推动了五四运动的发展； （3）新文化运动的基地 —— 北京大学成为五四运动的发祥地； （4）五四运动促进了马克思主义的⼴泛传播，促使新文化运动的阵营逐渐分化； （5）五四运动后，马克思主义传播成为新文化运动的主流，李大钊等人开始把马克思主义同中国 工人运动初步结合起来。","chapter":"第四章","subject":"history","type":"essay","id":"history_第四章_essay_1"},{"stem":"南京国民政府改组的时间","options":{"A":"1926年2月","B":"1927年2月","C":"1928年2月","D":"1929年2月"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_1"},{"stem":"1928年12月29日发出通告，宣布“遵守三民主义，服从国民政府，改易旗帜” 的人是","options":{"A":"冯玉祥","B":"李宗仁","C":"阎锡山","D":"张学良"},"answer":"D","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_2"},{"stem":"1928年蒋介石在南京建立的国民党政府的统治依然是","options":{"A":"民族资产阶级统治","B":"官僚资产阶级统治","C":"地主阶级统治","D":"地主阶级和买办性的大资产阶级的统治"},"answer":"D","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_3"},{"stem":"结束陈独秀右倾机会主义错误的会议是","options":{"A":"八七会议","B":"中共六大","C":"文家市会议","D":"古田会议"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_4"},{"stem":"1927年8月1日，中共在南昌举行起义，前敌委员会的书记是","options":{"A":"毛泽东","B":"周恩来","C":"朱德","D":"贺龙"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_5"},{"stem":"打响武装反抗国民党反动派第一枪的起义是","options":{"A":"南昌起义","B":"上海工人武装起义","C":"秋收起义","D":"武昌起义"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_6"},{"stem":"大革命失败后，湘赣边界秋收起义的领导人是","options":{"A":"叶挺","B":"周恩来","C":"毛泽东","D":"叶剑英"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_7"},{"stem":"农村包围城市、武装夺取政权这条革命新道路的开辟，是中国共产党集体智慧的结晶，而其中杰出的代表是","options":{"A":"毛泽东","B":"王明","C":"陈独秀","D":"博古"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_8"},{"stem":"毛泽东在井冈山主持制定中国共产党历史上第一个土地法的时间是","options":{"A":"1927年12月","B":"1928年12月","C":"1929年12月","D":"1930年12月"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_9"},{"stem":"中华苏维埃第一次全国代表大会在江西省瑞金县举行的时间是","options":{"A":"1929年11月","B":"1930年11月","C":"1931年11月","D":"1932年11月"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_10"},{"stem":"1927年11月至1928年4月的第一次“左”倾盲动错误的代表是","options":{"A":"瞿秋白","B":"李立三","C":"王明","D":"张国焘"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_11"},{"stem":"开始确立以毛泽东为代表的马克思主义的正确路线在中共中央的领导地位的重要会议是","options":{"A":"八七会议","B":"遵义会议","C":"瓦窑堡会议","D":"中共七大"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_12"},{"stem":"1935年6月中央红军同红四方面军会师的地址是","options":{"A":"吴起镇","B":"会宁","C":"懋功","D":"甘孜"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_13"},{"stem":"1931年前后中国共产党制定的土地革命路线中，对富农的政策是","options":{"A":"消灭富农","B":"联合富农","C":"限制富农","D":"保护富农"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_14"},{"stem":"毛泽东提出“没有调查，没有发言权“的重要思想的文章是","options":{"A":"《实践论》","B":"《井冈山的斗争》","C":"《反对本本主义》","D":"《新民主主义论》"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_15"},{"stem":"中国共产党独立领导革命战争和创建人民军队的开始是","options":{"A":"南昌起义","B":"八七会议","C":"秋收起义","D":"广州起义"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_16"},{"stem":"毛泽东在《反对本本主义》一文发表的时间是","options":{"A":"1930年5月","B":"1931年6月","C":"1932年7月","D":"1933年9月"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_17"},{"stem":"国民革命失败后，以毛泽东为代表的中国共产党人逐步将革命的重心","options":{"A":"由乡村转移到城市","B":"由城市转移到乡村","C":"由大城市转向小城市","D":"由南方转向北方"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_18"},{"stem":"中国共产党认识和把握中国革命发展的客观规律，最终要靠","options":{"A":"马克思列宁主义基本原理与中国实际相结合","B":"马克思主义本本","C":"听从共产国际的指挥","D":"照搬苏联经验"},"answer":"A","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_19"},{"stem":"中国共产党领导革命武装建立的全国第一个农村革命根据地是","options":{"A":"湘赣根据地","B":"井冈山根据地","C":"湘鄂西根据地","D":"陕甘宁根据地"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_20"},{"stem":"在红军长征途中，中共中央同分裂中央、分裂红军，犯严重错误的红四方面军领导人（ ）进行了坚决斗争。","options":{"A":"王明","B":"李德","C":"张国焘","D":"博古"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_21"},{"stem":"中国共产党开始从大革命失败到土地革命战争兴起的转折是（ ）。","options":{"A":"南昌起义","B":"井冈山革命根据地的创立","C":"八七会议的召开","D":"工农武装割据思想的提出"},"answer":"C","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_22"},{"stem":"1931年11月成立的中华苏维埃共和国实行的制度是","options":{"A":"人民代表大会制度","B":"工农兵代表大会制度","C":"农民代表大会制度","D":"工人代表大会制度"},"answer":"B","chapter":"第五章","subject":"history","type":"single","id":"history_第五章_single_23"},{"stem":"国民党在全国统治建立的标志是","options":{"A":"国民党的南京国民政府和武汉国民政府实现了宁、汉合流","B":"国民党政府的军队继续北伐，于6月进驻北京、天津一带","C":"张学良宣布“遵守三民主义，服从国民政府，改易旗帜”","D":"北洋军阀作为独立的政治力量继续存在"},"answer":"ABC","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_1"},{"stem":"在1927年大革命失败以后，国民党代表的利益是","options":{"A":"地主阶级","B":"买办性的大资产阶级","C":"工人阶级","D":"农民阶级"},"answer":"AB","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_2"},{"stem":"国民党政府实行一党专政的军事独裁统治的方法是","options":{"A":"建立了庞大的军队","B":"建立了庞大的全国性特务系统","C":"大力推行保甲制度","D":"厉行文化专制主义"},"answer":"ABCD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_3"},{"stem":"国民党庞大的全国性特务系统主要是","options":{"A":"中统","B":"军统","C":"保甲队","D":"还乡团"},"answer":"AB","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_4"},{"stem":"大革命失败后的艰难环境是","options":{"A":"中国社会的半殖民地半封建性质没有改变","B":"反革命力量大大超过了有组织的革命力量","C":"白色恐怖笼罩着全国城乡","D":"中国革命转入低潮"},"answer":"ABCD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_5"},{"stem":"在革命的危急关头，1927年7月中旬，中共中央临时政治局常委会决定的三件大事是","options":{"A":"将党所掌握和影响的部队向南昌集中，准备起义","B":"组织湘、鄂、赣、粤四省的农民，在秋收季节举行暴动","C":"召集中央会议，讨论和决定新时期的方针和政策","D":"继续同国民党合作"},"answer":"ABC","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_6"},{"stem":"1927年8月1日，领导南昌起义的主要领导者是","options":{"A":"周恩来","B":"叶挺","C":"朱德","D":"刘伯承"},"answer":"ABCD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_7"},{"stem":"1927年12月11日，领导广州起义的主要领导者是","options":{"A":"张太雷","B":"叶挺","C":"叶剑英","D":"刘伯承"},"answer":"ABC","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_8"},{"stem":"从1930年10月到1931年7月，红一方面军连续粉碎国民党军队三次“围剿”而贯彻的积极防御方针是","options":{"A":"诱敌深入","B":"避敌主力","C":"打其虚弱","D":"积极冒进"},"answer":"ABC","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_9"},{"stem":"毛泽东和邓子恢等一起制定的土地革命中的阶级路线是","options":{"A":"坚定地依靠贫农、雇农","B":"联合中农，限制富农","C":"保护中小工商业者","D":"消灭地主阶级"},"answer":"ABCD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_10"},{"stem":"先进青年们在救亡图存的运动中清醒认识到，（）是解救民族危亡的良方。","options":{"A":"以农民阶级为基础","B":"以工人阶级为基础","C":"以马克思列宁主义武装自己","D":"要对人民无私奉献"},"answer":"BC","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_11"},{"stem":"20世纪初赴法勤工俭学的学生日常生活主要包括","options":{"A":"工厂做工","B":"奋力斗争","C":"读书学习","D":"考察社会"},"answer":"ABCD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_12"},{"stem":"红一方面军","options":{"A":"红二方面军","B":"红三方面军","C":"红四方面军"},"answer":"ABD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_13"},{"stem":"从1927年7月大革命失败到1935年1月遵义会议召开，“左”倾错误先后三次在党中央的领导机关取得统治地位，它们是（ ）。","options":{"A":"瞿秋白的“左”倾盲动主义","B":"陈独秀的“左”倾机会主义","C":"李立山的“左”倾冒险主义","D":"王明的“左”倾教条主义"},"answer":"ACD","chapter":"第五章","subject":"history","type":"multi","id":"history_第五章_multi_14"},{"stem":"简述土地革命的阶级路线、土地分配方法。","answer":"","chapter":"第五章","subject":"history","type":"short","id":"history_第五章_short_1"},{"stem":"以毛泽东为代表的中国共产党人是如何探索和开辟中国革命新道路的？","answer":"1931年2月，毛泽东进一步总结根据地土地革命的经验，要求各地各级工农民主政府发布公告，明确规定农民已经分得的田归农民个人私有，可以自主租借买卖，别人不得侵犯；生产的产品，除向政府缴纳土地税外，均归农民个人私有，任凭自由买卖。毛泽东还和邓子恢等一起制定了土地革命中的阶级路线和土地分配方法：坚定地依靠贫农、雇农，联合中农，限制富农，保护中小工商业者，消灭地主阶级；以乡为单位，按人口平分土地，在原耕地的基础上，实行抽多补少、抽肥补瘦。这样，中国共产党就在中国历史上第一个制定了可以付诸实施的比较完整的土地革命纲领和路线。 （1）内容：遵义会议集中解决了当时具有决定意义的军事问题和组织问题。经过激烈的争论，多数人同意以毛泽东为代表的正确意见，批评了博古、李德在第五次反“围剿”中的错误。会议增选毛泽东为中央政治局常务委员，并委托张闻天起草《中央关于反对敌人五次“围剿”的总结的决议》(即遵义会议决议)。会后不久，中共中央政治局常务委员分工，根据毛泽东的提议，决定由张闻天代替博古负总的责任；博古任红军总政治部代理主任；成立了由周恩来、毛泽东、王稼祥组成的新的“三人团”,全权负责红军的军事行动。会议的一系列重大决策，是在中国共产党同共产国际的联系中断的情况下，独立自主地作出的。 （2）历史意义：遵义会议开始确立以毛泽东为主要代表的马克思主义的正确路线在党中央的领导地位，从而在极其危急的情况下挽救了中国共产党、挽救了中国工农红军、挽救了中国革命，成为中国共产党历史上一个生死攸关的转折点。这为党和革命事业转危为安、不断打开新局面提供了最重要的保证。","chapter":"第五章","subject":"history","type":"essay","id":"history_第五章_essay_1"},{"stem":"答：（1）、把全国人民和中华民族的根本利益看得高于一切，坚定革命的理想和信念，坚信正义事业必然胜利的精神；","answer":"","chapter":"第五章","subject":"history","type":"essay","id":"history_第五章_essay_2"},{"stem":"答：（1）开展武装反抗国民党统治的斗争。1927年8月，中共中央在汉口召开八七会议，彻底清算了大革命后期的陈独秀右倾机会主义错误，确定了土地革命和武装反抗国民党反动派的总方针。八七会议前后，举行了南昌起义、湘赣边界秋收起义、广州起义。中国革命由此发展到了一个新阶段，进入创建红军和革命根据地的新时期。","answer":"（1）开展武装反抗国民党统治的斗争。1927年8月，中共中央在汉口召开八七会议，彻底清算了大革命后期的陈独秀右倾机会主义错误，确定了土地革命和武装反抗国民党反动派的总方针。八七会议前后，举行了南昌起义、湘赣边界秋收起义、广州起义。中国革命由此发展到了一个新阶段，进入创建红军和革命根据地的新时期。 （2）创建农村革命根据地，保存和发展革命力量。在敌强我弱的形势下，以农村为重点，到农村去发动农民，进行土地革命，开展武装斗争，建设根据地，这是1927年以后中国革命发展的客观规律所要求的。农村包围城市、武装夺取政权这条革命新道路的开辟，依靠了党和人民的集体奋斗，凝聚了党和人民的集体智慧。而毛泽东是其中的杰出代表，他在秋收起义失败后，及时地将进攻的方向转向农村，点燃了“工农武装割据”的星星之火。 （3）毛泽东从理论上阐明了武装斗争的极端重要性和农村应当成为党的工作中心的思想。1928年，毛泽东写了《中国的红色政权为社么能够存在？》、《井冈山的斗争》等文章，明确指出以农业为主要经济的中国革命，以军事发展暴动，是一种特征；还科学阐明了共产党领导的土地革命、武装斗争和根据地建设这三者之间的辩证统一关系。1930年，毛泽东在《星星之火可以燎原》一文中指出：红军、游击队和红色区域的建立和发展，是半殖民地中国在无产阶级领导下的农民斗争的最高形式，是半殖民地农民斗争发展的必然结果，并且无疑义的是促进全国革命高潮的最重要因素。 （4）革命新道路的开辟，使中国革命开始走向复兴。随着革命新道路的开辟，中国共产党领导的红军和根据地逐步发展起来，红军游击战争实际上已经成为中国革命的主要形式，农村根据地成为积蓄和锻炼革命力量的主要战略阵地。 （5）农村包围城市，武装夺取政权理论的提出，标志着中国化的马克思主义——毛泽东思想的初步形成。革命新道路的理论，是中国共产党领导的红军和根据地斗争经验的科学概括，它是以毛泽东为代表的中国共产党人同当时党内盛行的把马克思主义教条化、把共产国际和苏联经验神圣化的错误倾向做坚决斗争基础上形成的，是马克思主义和中国革命具体实践相结合产生的第一次历史性飞跃的重大成果。","chapter":"第五章","subject":"history","type":"essay","id":"history_第五章_essay_3"},{"stem":"答：以毛泽东为主要代表的中国共产党人历来重视总结经验，加强党的思想理论建设。土地革命时期，党内连续发生“左”倾错误，给中国革命带来了极其严重的危害。这些错误的发生，主要是对于马克思列宁主义的理论和中国革命的实践没有统一的理解而产生的。正因为如此，毛泽东强调，为了纠正错误，必须端正思想路线，实行马克思列宁主义与中国实际相结合的原则。","answer":"","chapter":"第五章","subject":"history","type":"essay","id":"history_第五章_essay_4"},{"stem":"1931年9月18日，日本关东军在中国（ ）市郊柳条湖爆破铁路，制造借口向中国军队进攻。“九·一八”事变后，日军迅即侵占我国东北三省。","options":{"A":"沈阳","B":"长春","C":"大连","D":"旅顺"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_1"},{"stem":"抗日战争进入相持阶段后，日本对国民党政府采取的方针是（ ）。","options":{"A":"以华治华，以战养战","B":"速战速决","C":"“三光”政策","D":"以政治诱降为主、军事打击为辅"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_2"},{"stem":"中华民族进入全民族抗战是在（ ）。","options":{"A":"九一八事变后","B":"一·二八事变后","C":"华北事变后","D":"卢沟桥事变后"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_3"},{"stem":"1940年5月，国民革命军第三十三集团军总司令（ ）在枣宜会战中殉国。","options":{"A":"谢晋元","B":"赵禹登","C":"张自忠","D":"佟麟阁"},"answer":"C","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_4"},{"stem":"1935年12月，中共中央提出党的基本策略任务是建立广泛的抗日民族统一战线的会议是（ ）。","options":{"A":"遵义会议","B":"瓦窑堡会议","C":"洛川会议","D":"晋绥干部会议"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_5"},{"stem":"1937年8月，中国共产党在陕北洛川召开的政治局扩大会议上制定了（ ），强调要打倒日本帝国主义，关键在于使已经发动的抗战成为全面的全民族抗战。","options":{"A":"中国人民对日作战的基本纲领","B":"抗日救国十大纲领","C":"抗日民族统一战线的策略总方针","D":"持久抗战的总方针"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_6"},{"stem":"广州、武汉失守之后，中国抗日战争开始进入相持阶段的时间是（ ）。","options":{"A":"1937年7月","B":"1938年5月","C":"1938年10月","D":"1941年12月"},"answer":"C","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_7"},{"stem":"抗日战争期间，中国共产党非常重视文化建设和干部教育。中国共产党创办的（ ）成为了中国共产党历史上第一个开展自然科学教学与研究的专门机构。","options":{"A":"延安理工学院","B":"延安工业学院","C":"延安科学院","D":"延安自然科学院"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_8"},{"stem":"1942年2月，毛泽东先后作了《整顿党的作风》和《反对党八股》的演讲，整风运动在全党范围内普遍展开。（ ）是延安整风运动的最主要任务。","options":{"A":"反对主观主义以整顿学风","B":"反对宗派主义以整顿党风","C":"反对党八股以整顿文风","D":"反对官僚主义以整顿作风"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_9"},{"stem":"抗战后期，国民党军队遭到大溃败的战役是（ ），这次溃败也成为大后方人心变动的重要转折点。","options":{"A":"长沙会战","B":"豫湘桂战役","C":"淞沪会战","D":"武汉会战"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_10"},{"stem":"（ ）把毛泽东思想确立为党的指导思想并写入党章。","options":{"A":"中共六届四中全会","B":"中共七大","C":"中共六届六中全会","D":"中共八大"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_11"},{"stem":"中国人民抗日战争取得完全胜利的标志是（ ）。","options":{"A":"1945年8月14日，日本政府表示接受波茨坦公告","B":"1945年8月15日，日本天皇发表终战诏书","C":"1945年9月2日，日本向同盟国投降签字","D":"1945年10月25日，中国收回被日本占领的台湾及澎湖列岛"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_12"},{"stem":"1935年，北平学生举行声势浩大的抗日游行，喊出“反对华北自治”“打倒日本帝国主义”“停止内战，一致对外”等口号，标志着中国人民抗日救亡运动新高潮的到来的是（ ）。","options":{"A":"第十九路军抗战","B":"卢沟桥抗战","C":"华北事变","D":"一二·九运动"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_13"},{"stem":"抗日战争时期，国民党第二次反共高潮达到顶点的标志是（ ）。","options":{"A":"平江惨案","B":"皖南事变","C":"陇东事变","D":"晋西事变"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_14"},{"stem":"抗日战争时期，中国共产党解决农民问题的基本政策是（ ）。","options":{"A":"土地国有","B":"没收地主土地","C":"减租减息","D":"按人口平均分配土地"},"answer":"C","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_15"},{"stem":"近代以来中国第一次取得反侵略完全胜利的战争是（ ）。","options":{"A":"中法战争","B":"甲午战争","C":"抗日战争","D":"抗美援朝战争"},"answer":"C","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_16"},{"stem":"毛泽东明确提出“马克思主义的中国化”这个命题是在中国共产党的（ ）。","options":{"A":"二大","B":"七大","C":"六届六中全会","D":"八七会议"},"answer":"C","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_17"},{"stem":"（ ）取得全民族抗战以来中国军队主动寻歼敌人的第一次重大胜利，打破了日军不可战胜的神话。","options":{"A":"平型关战役","B":"台儿庄战役","C":"百团大战","D":"淞沪会战"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_18"},{"stem":"在惨绝人寰、震惊中外的南京大屠杀中，日军共杀害了（ ）的中国军民。","options":{"A":"10万以上","B":"30万以上","C":"5万","D":"50万以上"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_19"},{"stem":"毛泽东在《论持久战》中指出，中国抗日战争取得胜利最关键的阶段是（ ）。","options":{"A":"战略防御阶段","B":"战略相持阶段","C":"战略反攻阶段","D":"战略决战阶段"},"answer":"B","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_20"},{"stem":"抗日战争时期，中国共产党领导的敌后战场战略总后方是","options":{"A":"陕甘宁边区","B":"晋察冀根据地","C":"山东根据地","D":"苏北根据地"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_21"},{"stem":"抗日战争进入相持阶段的标志是","options":{"A":"武汉会战结束","B":"淞沪会战结束","C":"南京沦陷","D":"台儿庄战役胜利"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_22"},{"stem":"中国共产党在抗日根据地实行的土地政策是","options":{"A":"减租减息","B":"没收地主土地","C":"土地国有化","D":"平均地权"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_23"},{"stem":"日本宣布无条件投降的时间是","options":{"A":"1945年8月15日","B":"1945年9月2日","C":"1945年9月3日","D":"1945年10月1日"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_24"},{"stem":"确立毛泽东思想为党的指导思想的会议是","options":{"A":"中共七大","B":"遵义会议","C":"瓦窑堡会议","D":"洛川会议"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_25"},{"stem":"中国人民抗日战争胜利的关键是","options":{"A":"世界反法西斯力量的同情和支持","B":"反侵略战争的正义性和进步性","C":"民族意识的觉醒和全民族抗战","D":"中国共产党的中流砥柱的作用"},"answer":"D","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_26"},{"stem":"1936年12月12日，张学良、杨虎城发动“兵谏”，扣留了蒋介石。这就是震惊中外的西安事变。事变发生后，中共中央确定了促成事变和平解决的基本方针，其原因是中国共产党","options":{"A":"为了团结国民党共同抗日","B":"不赞成张学良、杨虎城的主张","C":"工作重心转向城市斗争","D":"接受了共产国际的指示"},"answer":"A","chapter":"第六章","subject":"history","type":"single","id":"history_第六章_single_27"},{"stem":"根据地政权是共产党领导的抗日民族统一战线性质的政权，在工作人员分配上实行“三三制”原则，即（ ）、（ ）和（ ）各占1/3。这样做，可以容纳各方面的代表，团结一切赞成抗日又赞成民主的各阶级、阶层。","options":{"A":"共产党员","B":"党外进步人士","C":"中间派","D":"地方实力派"},"answer":"ABC","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_1"},{"stem":"中国共产党在抗日民族统一战线中的策略总方针是（ ）。","options":{"A":"发展进步势力","B":"争取中间势力","C":"打击资产阶级","D":"孤立顽固势力"},"answer":"ABD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_2"},{"stem":"抗日民主根据地的建设包括（ ）。","options":{"A":"民主政权建设","B":"军队战斗力建设","C":"减租减息","D":"文化建设"},"answer":"ACD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_3"},{"stem":"抗战初期，国民党正面战场除了台儿庄战役取得大捷外，其他战役几乎都是以退却、失败而结束的，造成这种状况的原因包括（ ）。","options":{"A":"由于在敌我力量对比上，日军占很大优势","B":"国民党战略指导方针上的失误","C":"实行片面抗战路线","D":"国民党政府在军事、政治、经济各方面陷入深刻的危机"},"answer":"ABC","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_4"},{"stem":"毛泽东总结中国共产党成立以来的历史经验，指出（ ）、（ ）、（ ）是中国共产党在中国革命中战胜敌人的三个主要法宝。","options":{"A":"独立自主","B":"统一战线","C":"武装斗争","D":"党的建设"},"answer":"BCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_5"},{"stem":"日本对中国的大规模侵略和在中国部分地区的殖民统治犯下了空前严重的罪行，其主要表现是（ ）。","options":{"A":"制造惨绝人寰的大屠杀","B":"控制铁路交通","C":"肆意掠夺矿产资源、土地及农产品","D":"强制推行奴化教育"},"answer":"ABCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_6"},{"stem":"在20世纪30年代后期和40年代前期，为了将中国革命的实际经验马克思主义化，以便更好地指导抗日战争和中国革命，毛泽东撰写了（ ），系统阐明了新民主主义理论。","options":{"A":"《<共产党人>发刊词》","B":"《中国革命和中国共产党》","C":"《新民主主义论》","D":"《星星之火，可以燎原》"},"answer":"ABC","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_7"},{"stem":"抗日民族统一战线中，中间势力指的是（ ）。","options":{"A":"民族资产阶级","B":"开明绅士","C":"城市小资产阶级","D":"地方实力派"},"answer":"ABD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_8"},{"stem":"在抗日战争的战略防御阶段，国民党正面战场组织的大战役主要有（ ）。","options":{"A":"武汉会战","B":"淞沪会战","C":"忻口会战","D":"徐州会战"},"answer":"ABCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_9"},{"stem":"党的七大把党在长期奋斗中形成的优良作风概括为（ ）。","options":{"A":"自我批评的作风","B":"艰苦奋斗的作风","C":"理论和实践相结合的作风","D":"和人民群众紧密联系在一起的作风"},"answer":"ACD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_10"},{"stem":"下列关于1927年“东方会议”的表述正确的有","options":{"A":"由田中义一在东京主持","B":"制定了《对华政策纲要》","C":"提出满蒙与日本利益相关","D":"日本可以采取断然措施维护在满蒙的利益"},"answer":"ABCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_11"},{"stem":"在抗日战争进入相持阶段后，国民党的抗战态度趋向消极体现在","options":{"A":"实行保守的收缩战略以便保存实力","B":"打击、限制共产党及其领导下的抗日军队","C":"国民党五届五中全会决定成立“防共委员会”","D":"国民党五届五中全会制定了“防共、限共、溶共、反共”的方针"},"answer":"ABCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_12"},{"stem":"毛泽东在谈到党对民主革命规律的认识时指出，从党的建立到抗日时期，我们经过了两次胜利两次失败。“在抗日时期，我们才制定了合乎情况的党的总路线和一整套具体政策。这时候，中国民主革命这个必然王国才被我们认识，我们才有了自由”。这表明","options":{"A":"党已完全掌握了新民主主义革命的发展规律","B":"马克思主义必须与中国革命具体实际相结合","C":"党对民主革命规律的认识必须有一个过程","D":"新民主主义革命理论是总结正反两方面经验形成的"},"answer":"BCD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_13"},{"stem":"抗日民主根据地是认真贯彻和实现中国共产党全面抗战路线、坚持抗战和争取胜利的坚强阵地。中国共产党高度重视抗日民主根据地的政权建设，其主要举措有","options":{"A":"抗日民主政府在工作人员分配上实行“三三制”原则","B":"各级抗日民主政权机构领导人通过人民选举产生","C":"实行工农兵代表大会制度","D":"在少数民族聚居地区试行民族区域自治"},"answer":"ABD","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_14"},{"stem":"党的六届六中全会是在抗日战争即将进入新阶段时召开的一次重要会议。毛泽东曾说过：“六中全会是决定中国之命运的。”下列关于六届六中全会表述正确的有","options":{"A":"会上毛泽东明确提出“马克思主义的中国化”命题","B":"会议提出了由新民主主义社会向社会主义社会转变的发展方向","C":"会议纠正了王明的右倾错误，统一了全党的思想和步调","D":"会议指明了党内小资产阶级思想的来源、表现及纠正方法"},"answer":"AC","chapter":"第六章","subject":"history","type":"multi","id":"history_第六章_multi_15"},{"stem":"简述抗日游击战争的战略地位和作用?","answer":"以爱国主义为核心的民族精神是中国人民抗日战争胜利的决定因素。近代以来，中国人民为争取民族独立和解放进行的一系列抗争，是中华民族觉醒和民族精神升华的历史进程，这在抗日战争时期达到全新高度。中华儿女众志成城、共御外侮，谱写了伟大的爱国主义篇章。","chapter":"第六章","subject":"history","type":"short","id":"history_第六章_short_1"},{"stem":"简述抗日战争胜利的原因?","answer":"中国坚持持久抗战，抗击和牵制着日本军队主力，大大减轻了其他战场的压力，并为同盟军队实施战略反攻创造了有利条件。","chapter":"第六章","subject":"history","type":"short","id":"history_第六章_short_2"},{"stem":"简述中国人民抗日战争在世界反法西斯战争中的地位？","answer":"中国作为亚太地区盟军对日作战的重要后方基地，为盟军提供了大量战略物资和军事情报。中国人民为了自己的解放，为了帮助各同盟国，付出了巨大牺牲，作出了伟大贡献。","chapter":"第六章","subject":"history","type":"short","id":"history_第六章_short_3"},{"stem":"材料一","answer":"中国人民抗日战争的胜利，彻底粉碎了日本军国主义殖民奴役中国的图谋。 有力捍卫了国家主权和领土完整，彻底洗刷了近代以来抗击外来侵略屡战屡败的民族耻辱。","chapter":"第六章","subject":"history","type":"essay","id":"history_第六章_essay_1"},{"stem":"抗日战争胜利后，中国社会的主要矛盾是","options":{"A":"中美民族矛盾","B":"中日民族矛盾","C":"资产阶级同无产阶级的矛盾","D":"中国人民同美帝国主义支持的国民党反动派之间的矛盾"},"answer":"D","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_1"},{"stem":"1945年8月25日中国共产党在对时局的宣言中明确提出（）的口号。","options":{"A":"避免内战，和平建国","B":"建立民主联合政府","C":"和平、民主、团结","D":"打到蒋介石，解放全中国"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_2"},{"stem":"1946年10月10日，国共两党经过谈判，签订《政府与中共代表会谈纪要》，确定","options":{"A":"建立民主联合政府","B":"和平建国的基本方针","C":"实行宪政、结束训政","D":"保护人民的民主、自由权利"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_3"},{"stem":"1946年6月底，国民党军以进攻（）为起点，挑起全国性的内战。","options":{"A":"中原解放区","B":"华北解放区","C":"华中解放区","D":"东北解放区"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_4"},{"stem":"1947年6月底，根据中共中央的决策和部署（）率领的晋冀鲁豫野战军主力，千里跃进大别山。","options":{"A":"陈毅、粟裕","B":"陈庚、谢富治","C":"刘伯承、邓小平","D":"谭震林、许世友"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_5"},{"stem":"揭开人民解放军全国性战略进攻序幕的是","options":{"A":"孟良崮战役开始","B":"刘邓大军挺进大别山","C":"三大战役开始","D":"渡江战役开始"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_6"},{"stem":"解放战争时期，最早与蒋介石集团决裂的民主党派是","options":{"A":"中国民主同盟","B":"民主建国会","C":"中国民主促进会","D":"中国国民党革命委员会"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_7"},{"stem":"解放战争时期，国民党统治区人民民主运动高涨的根本原因是","options":{"A":"中国共产党组织了反蒋统治的第二条战线","B":"上海学生举行了声势浩大的“三反”斗争","C":"国民党蒋介石集团的经济崩溃和政治危机","D":"民主党派的联合斗争和人民起义遍及各地"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_8"},{"stem":"对第三次国内革命战争时期反蒋斗争第二条战线的准确表述是","options":{"A":"国统区的学生运动","B":"国统区的工农运动","C":"国统区的地下斗争","D":"国统区的民主运动"},"answer":"D","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_9"},{"stem":"在全面内战爆发前夕，中共中央发出（），决定将党在抗日战争时期实行的减租减息政策改变为“耕者有其田”的政策。","options":{"A":"《关于土地问题的指示》","B":"《中国土地法大纲》","C":"《关于发展农业生产的决议》","D":"《关于抗日根据地土地政策的决定》"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_10"},{"stem":"解放战争时期制定的《中国土地法大纲》规定","options":{"A":"废除封建性及半封建性剥削的土地制度","B":"调整减租减息政策","C":"按贫雇农人口分配土地","D":"没收地主、富农的土地"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_11"},{"stem":"解放战争期间，台湾人民反抗国民党暴政的重要活动是","options":{"A":"五二运动","B":"二二八起义","C":"一二九运动","D":"一二一运动"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_12"},{"stem":"1949年3月23日上午，中共中央离开西柏坡向北平进发。临行前，毛泽东把进北平比作“进京赶考”，说“我们决不当李自成 ，我们都希望考个好成绩。”3月25日，毛泽东等中共中央领导人与中央机关、人民解放军总部进驻北平香山，标志着","options":{"A":"旧民主主义革命向新民主主义革命转变","B":"新民主主义社会开始向社会主义社会过渡","C":"中国革命重心从农村转向城市","D":"民族民主革命任务的完成"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_13"},{"stem":"1949年蒋介石发表“求和”声明，其真实意图是","options":{"A":"希望结束内战","B":"希望国共两党关系恢复到政协协议的框架下","C":"与中共和谈，划江而治","D":"争取时间，准备卷土重来"},"answer":"D","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_14"},{"stem":"中共七届二中全会需要解决的重要问题是","options":{"A":"如何夺取全国革命胜利","B":"如何解决民主革命遗留的任务的问题","C":"党的工作重心转移问题","D":"民主革命向社会主义革命转变的问题"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_15"},{"stem":"1949年9月，中国人民政治协商会议第一届全体会议召开的地点是","options":{"A":"北平","B":"延安","C":"西柏坡","D":"上海"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_16"},{"stem":"1949年6月30日毛泽东发表了（），向全中国人民阐述了中国共产党在建立新中国问题上的主张。","options":{"A":"《论联合政府》","B":"《论人民民主专政》","C":"《新民主主义论》","D":"《目前的形势和我们的任务》"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_17"},{"stem":"人民解放战争走向胜利的历史转折点是","options":{"A":"粉碎重点进攻","B":"战略反攻","C":"三大战役","D":"渡江作战"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_18"},{"stem":"中国革命胜利的基本经验中，最核心的是","options":{"A":"统一战线","B":"武装斗争","C":"党的建设","D":"土地革命"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_19"},{"stem":"全面内战爆发，毛泽东指出，我们战胜蒋介石的政治基础是","options":{"A":"蒋介石军事力量的优势和美国的援助，只是临时起作用的因素","B":"我们有苏联的援助","C":"解放区即将开展大规模的土地改革运动","D":"人民解放军的战争所具有的爱国的、正义的革命性质"},"answer":"D","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_20"},{"stem":"解放战争战略决战的三大战役不包括","options":{"A":"渡江战役","B":"辽沈战役","C":"淮海战役","D":"平津战役"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_21"},{"stem":"1949年中国人民政治协商会议通过的纲领性文件是","options":{"A":"《共同纲领》","B":"《中华人民共和国宪法》","C":"《土地改革法》","D":"《论人民民主专政》"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_22"},{"stem":"重庆谈判期间，国共双方签署的文件是","options":{"A":"《停战协议》","B":"《政府与中共代表会谈纪要》","C":"《共同纲领》","D":"《国内和平协定》"},"answer":"B","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_23"},{"stem":"1949年4月，人民解放军占领南京，宣告","options":{"A":"抗日战争胜利","B":"解放战争胜利结束","C":"国民党反动统治覆灭","D":"中华人民共和国成立"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_24"},{"stem":"毛泽东提出“两个务必”的会议是","options":{"A":"一二·一","B":"五二","C":"一二三","D":"二二八"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_25"},{"stem":"中国共产党领导的多党合作和政治协商格局初步形成的标志是（） A,重庆谈判","options":{"B":"新政协会议的召开","C":"各民主党派公开宣告接受中国共产党领导","D":"解放战争胜利"},"answer":"A","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_26"},{"stem":"抗战胜利后，民主党派提出的“第三条道路”实质是","options":{"A":"建立资产阶级共和国","B":"建立人民共和国","C":"实行君主立宪制","D":"继续国民党独裁统治"},"answer":"C","chapter":"第七章","subject":"history","type":"single","id":"history_第七章_single_27"},{"stem":"抗战结束后，蒋介石愿与中国共产党进行和平谈判，其目的是","options":{"A":"敷衍国内外要求和平的舆论","B":"诱使中共交出人民军队和解放区政权","C":"为把战争责任转嫁给中共制造借口","D":"争取时间为进行内战做准备"},"answer":"ABC","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_1"},{"stem":"通过重庆谈判和签订的“双十协定”，中共取得的成果有","options":{"A":"在全国人民面前表现了和平诚意","B":"迫使国民党承认和平建国的基本方针","C":"实现了中共在国家政治生活中的合法地位","D":"团结了民主力量"},"answer":"ABD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_2"},{"stem":"参加1945年重庆谈判的中共代表有","options":{"A":"毛泽东","B":"周恩来","C":"王若飞","D":"张闻天"},"answer":"ABC","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_3"},{"stem":"国民党统治区第二条战线的斗争形式有","options":{"A":"学生运动","B":"工人罢工","C":"商人罢市","D":"农民抗捐抗税"},"answer":"ABCD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_4"},{"stem":"对1946年政协会议协议的有关表述，正确的是","options":{"A":"有利于实现民主政治与和平建国","B":"在许多方面反映了人们的愿望","C":"体现了民主协商的精神","D":"很快被国民政府撕毁"},"answer":"ABD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_5"},{"stem":"从抗战结束到新中国建立前，中国共产党关于土地问题的文件有","options":{"A":"《五四指示》B《兴国土地法》","C":"《共同纲领》D《中国土地法大纲》"},"answer":"AD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_6"},{"stem":"第二条战线形成的主要原因有","options":{"A":"国民党政府的专制独裁","B":"国民党政府官员的贪污腐化","C":"国民党执行内战政策","D":"国统区出现严重的经济危机，人民生活陷入困境"},"answer":"ACD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_7"},{"stem":"毛泽东提出的“两个务必”是","options":{"A":"务必使同志们继续地保持谦虚，谨慎，不骄，不躁的作风","B":"务必使同志们继续地保持艰苦奋斗的作风","C":"务必使同志们继续保持密切联系群众的作风","D":"务必使同志们继续保持团结协作的作风"},"answer":"ABCD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_8"},{"stem":"中国共产党在新民主主义革命不同时期提出的土地政策的共同点是","options":{"A":"体现中国共产党的民主革命纲领","B":"消灭封建剥削制度","C":"维护农民基本利益","D":"促进社会经济发展"},"answer":"AB","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_9"},{"stem":"新中国成立前夕，中国共产党提出的建国目标是建立","options":{"A":"工人阶级领导的","B":"以工农联盟为基础的","C":"人民民主专政的","D":"各革命阶级联合专政的"},"answer":"ABCD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_10"},{"stem":"中国各民主党派形成时的社会基础是","options":{"A":"宣传","B":"练兵","C":"减租","D":"生产"},"answer":"ABCD","chapter":"第七章","subject":"history","type":"multi","id":"history_第七章_multi_11"},{"stem":"抗日战争胜利后，国民党政府为什么会陷入全民的包围中并迅速走向崩溃？","answer":"坚持把马克思列宁主义基本原理同中国具体实际结合起来，不断推进马克思主义中国化的事业。在中国化的马克思主义理论——毛泽东思想指引下，找到了适合本国国情的革命道路。","chapter":"第七章","subject":"history","type":"short","id":"history_第七章_short_1"},{"stem":"为什么说“没有共产党就没有新中国”？","answer":"在革命过程中，积累了丰富的经验，锻造并充分运用了有效的克敌制胜的三大法宝：统一战线、武装斗争与党的建设。","chapter":"第七章","subject":"history","type":"short","id":"history_第七章_short_2"},{"stem":"中国革命取得胜利的基本经验？","answer":"坚持中国革命斗争中的坚强领导核心——中国共产党的领导。","chapter":"第七章","subject":"history","type":"short","id":"history_第七章_short_3"},{"stem":"第三条道路的破产根本原因是蒋介石的专制统治造成的。","answer":"解放战争时期中国共产党在解放区的土地革命政策： ①1946年5月4日， 中共中央发出《关于清算、减租及土地问题的指示》（史称《五四指示》），决定将党在抗日战争时期实行的减租减息政策改变为实现“耕者有其田”的政策。在此之后，通过开展清算斗争等，到1947年下半年，解放区已有2/3 的地区基本上解决了农民的土地问题。 ②在人民解放军转入战略进攻之后，为了维护广大农民的利益、进一步激发他们支援解放战争的积极性，1947年7月至9 月 ， 中国共产党制定和通过了《中国土地法大纲》。明确规定“废除封建性及半封建性剥削的土地制度，实现耕者有其田的土地制度”“乡村中一切地主的土地及公地，由乡村农会接收”，分配给无地或少地的农民。 ③全国土地会议以后，解放区广大农村迅速掀起了土地制度改革运动的热潮。尽管在土改运动广泛发动之后，一度发生过侵犯部分中农利益、侵犯某些民族工商业等的“左”的错误，但中共中央一经发现，便立即采取坚决的措施加以纠正，使运 动迅速走上健康发展的轨道。","chapter":"第七章","subject":"history","type":"essay","id":"history_第七章_essay_1"},{"stem":"解放区内的土地改革为新中国的建立奠定了深厚的基础。","answer":"解放战争时期中国共产党在解放区的土地革命政策的意义 ① 经过土地改革运动，到1948年秋，1亿人口的解放区消灭了封建生产关系。广大农民分得土地并在政治上获得翻身以后，其政治觉悟和组织程度空前提高，农村生产力得到解放，工农联盟进一步巩固和加强。人民解放战争获得了源源不断的人力、物力的支援。 ②土地制度改革，是从根本上摧毁中国封建制度根基的社会大变革。土改运动的发展表明，解放战争在胜利推进的同时，中国的社会变革也在深入发展。经过这个运动，农民进一步认识到，中国共产党是自身利益的坚决维护者， 因而自觉地在党的周围团结起来。这就为打败蒋介石、建立新中国奠定了深厚的群众基础。","chapter":"第七章","subject":"history","type":"essay","id":"history_第七章_essay_2"},{"stem":"社会主义革命和建设时期，党面临的主要任务是，实现从新民主主义到社会主义的转变，进行社会主义革命，推进社会主义建设，为实现中华民族伟大复兴奠定根本政治前提和制度基础。中国进入社会主义社会最主要的标志是( )。","options":{"A":"社会主义政治制度的确立","B":"社会主义经济制度的建立","C":"民主革命遗留任务的完成","D":"人民民主专政国家政权的建立"},"answer":"B","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_1"},{"stem":"1956年4月，毛泽东提出把马克思列宁主义基本原理同中国具体实际进行“第二次结合”，其目的是（ ）。","options":{"A":"加强中国共产党的自身建设","B":"为社会主义改造创造条件","C":"找出在中国怎样建设社会主义的道路","D":"全面建设社会主义现代化强国"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_2"},{"stem":"1956年4和5月，毛泽东先后在中央政治局扩大会议和最高国务会议上作《论十大关系》的报告，他指出：“最近苏联方面暴露了他们在建设社会主义过程中的一些缺点和错误，他们走过的弯路，你还想走？过去我们就是鉴于他们的经验教训，少走了一些弯路，现在当然更要引以为戒”，这表明，以毛泽东为主要代表的中国共产党人（ ）。","options":{"A":"实现了马克思主义同中国实际的“第二次结合”","B":"开始探索中国自己的社会主义建设道路","C":"开始找到自己的一条适合中国的路线","D":"已经突破社会主义苏联模式的束缚"},"answer":"B","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_3"},{"stem":"新中国的工业化是在苏联的影响下起步的。走中国工业化道路，是中国共产党初步探索我国社会主义建设道路的一个重要思想。当时所讲的工业化道路问题，主要是指（ ）。","options":{"A":"中央和地方的关系问题","B":"经济建设和国防建设的关系问题","C":"沿海工业和内地工业的关系问题","D":"重工业、轻工业和农业的发展关系问题"},"answer":"D","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_4"},{"stem":"1951年底到1952年春，中国共产党在党政机关干部中开展的“三反”运动的内容是（ ）。","options":{"A":"反贪污、反浪费、反官僚主义","B":"反主观主义、反宗派主义、反党八股","C":"反受贿、反贪污、反自由主义","D":"反浪费、反行贿、反形式主义"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_5"},{"stem":"中国进入新民主主义社会后，经济上处于领导地位的是（ ）。","options":{"A":"私人资本主义经济","B":"国家资本主义经济","C":"国营经济","D":"合作社经济"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_6"},{"stem":"中国共产党在过渡时期总路线的主体是实现（ ）。","options":{"A":"对个体农业的社会主义改造","B":"对个体手工业的社会主义改造","C":"对资本主义工商业的社会主义改造","D":"国家的社会主义工业化"},"answer":"D","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_7"},{"stem":"在推进手工业合作化的过程中，中国共产党采取的方针是（ ）。","options":{"A":"合作化","B":"积极引导、稳步前进","C":"和平赎买","D":"自愿互利"},"answer":"B","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_8"},{"stem":"我国在对资本主义工商业进行社会主义改造中，对民族资产阶级采取的政策是（ ）。","options":{"A":"和平赎买（利用、限制、改造）","B":"国家资本主义","C":"没收","D":"保护"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_9"},{"stem":"中国在对资本主义工商业实行社会主义改造的过程中，在利润分配上采取的政策是（ ）。","options":{"A":"统筹兼顾","B":"劳资两利","C":"公私兼顾","D":"四马分肥"},"answer":"D","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_10"},{"stem":"中共八大提出社会主义改造完成后中国社会的主要矛盾是（ ）。","options":{"A":"生产关系与生产力、上层建筑与经济基础之间的矛盾","B":"敌我矛盾与人民内部矛盾","C":"人民对于经济文化迅速发展的需要同当前经济文化不能满足人民需要的状况之间的矛盾","D":"无产阶级与资产阶级之间的矛盾"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_11"},{"stem":"1961年1月，中共中央正式决定对国民经济实行“调整、巩固、充实、提高”方针的会议是（ ）。","options":{"A":"中共八届五中全会","B":"中共八届六中全会","C":"中共八届九中全会","D":"中共八届十中全会"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_12"},{"stem":"1962年初，中共中央召开的扩大的中央工作会议是（ ）。","options":{"A":"“七千人大会”","B":"庐山会议","C":"南宁会议","D":"武昌会议"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_13"},{"stem":"毛泽东在1956年提出的十大关系围绕的基本方针是（ ）。","options":{"A":"调动国内外一切积极因素，为社会主义服务","B":"正确处理人民内部矛盾","C":"满足人民日益增长的物质文化需要","D":"实现社会主义四个现代化"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_14"},{"stem":"中华人民共和国在联合国合法席位的恢复是在（ ）。","options":{"A":"1949年10月","B":"1956年10月","C":"1971年10月","D":"1978年10月"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_15"},{"stem":".1957年，毛泽东在《关于正确处理人民内部矛盾的问题》中指出，在我国，工人阶级与民族资产阶级的矛盾属于人民内部的矛盾。如果处理不当，会变成（A）","options":{"A":"对抗性的敌我矛盾","B":"非对抗性的敌我矛盾","C":"对抗性的人民内部矛盾","D":"非对抗性的人民内部矛盾"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_16"},{"stem":"1956年4月和5月，毛泽东在《论十大关系》的报告中初步总结了我国社会主义建设的经验，明确提出了（ B ）","options":{"A":"党在过渡时期的总路线","B":"以苏为鉴，独立自主地探索适合中国情况的社会主义建设道路","C":"建设有中国特色社会主义","D":"多快好省地建设社会主义"},"answer":"B","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_17"},{"stem":"毛泽东提出社会主义社会基本矛盾和两类不同性质矛盾学说的著作是（ D ）。","options":{"A":"《论十大关系》","B":"《矛盾论》","C":"《论人民民主专政》","D":"《关于正确处理人民内部矛盾的问题》"},"answer":"D","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_18"},{"stem":"在社会主义建设道路初步探索的过程中，毛泽东提出了（ A ）发展国民经济的总方针。","options":{"A":"以农业为基础，以工业为主导，以农轻重为序","B":"以农业为基础，以重工业为主导，以农轻重为序","C":"以工业为基础，以农业为主导，以工农兵为序","D":"全面发展，综合平衡"},"answer":"A","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_19"},{"stem":"《论十大关系》是以毛泽东为主要代表的中国共产党人开始探索中国自己的社会主义建设道路的标志。毛泽东在《论十大关系》中提出的中国社会主义建设的基本方针是（C）","options":{"A":"不要四面出击","B":"积极引导、稳步前进","C":"调动国内外一切积极因素为社会主义事业服务","D":"实现工业、农业、国防和科学技术的现代化"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_20"},{"stem":"合作社经济","options":{"A":"国营经济","B":"个体经济","C":"资本主义经济"},"answer":"C","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_21"},{"stem":"1954年，我国第一部宪法规定我国的最高权力机关是（ ）。 国家主席 全国人民代表大会","options":{"C":"政务院","D":"法院 答案：B"},"answer":"B","chapter":"第八章","subject":"history","type":"single","id":"history_第八章_single_22"},{"stem":"新中国成立初期，中国共产党和人民政府着重抓的工作有（ ）。","options":{"A":"完成民主革命的遗留任务","B":"恢复和发展国民经济","C":"维护国家主权和安全","D":"加强党自身的建设"},"answer":"ABCD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_1"},{"stem":"中国共产党在过渡时期的总路线和总任务是逐步实现（ ）。","options":{"A":"国家的社会主义工业化","B":"对农业的社会主义改造","C":"对手工业的社会主义改造","D":"对资本主义工商业的社会主义改造"},"answer":"ABCD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_2"},{"stem":"我国对手工业合作化的组织形式有（ ）。","options":{"A":"手工业生产合作小组","B":"手工业供销合作社","C":"手工业生产合作社","D":"互助组"},"answer":"ABC","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_3"},{"stem":"新中国成立后，毛泽东探索社会主义建设道路的重要文章有（ ）。","options":{"A":"《论人民民主专政》","B":"《论十大关系》","C":"《关于正确处理人民内部矛盾的问题》","D":"《在中国共产党第七届中央委员会第二次全体会议上的报告》"},"answer":"BC","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_4"},{"stem":"毛泽东在《关于正确处理人民内部矛盾的问题》中指出，社会主义社会的基本矛盾仍然是（ ）。","options":{"A":"生产力和生产关系之间的矛盾","B":"人民对于经济文化迅速发展的需要同当前经济文化不能满足人民需要的状况之间的矛盾","C":"经济基础和上层建筑之间的矛盾","D":"敌我矛盾和人民内部矛盾"},"answer":"AC","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_5"},{"stem":"1957年4月,中共中央下发《关于整风运动的指示》指出，这次整风主要反对的错误倾向是（ ）。","options":{"A":"主观主义","B":"宗派主义","C":"自由主义","D":"官僚主义"},"answer":"ABD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_6"},{"stem":"毛泽东在《一九五七年夏季的形势》一文中提出，必须在我国建立一个现代化的工业基础和现代化的农业基础，这样，我们的社会主义的经济制度和政治制度，才能获得自己的比较充分的物质基础；为了建成社会主义，工人阶级必须有自己的技术干部队伍，必须有自己的教授、教员、科学家、新闻记者、文学家、艺术家和马克思主义理论家的队伍，这是一个宏大的队伍，人少了是不成的；要造成一个政治局面，这种政治局面是（ ）。","options":{"A":"又有集中又有民主","B":"又有纪律又有自由","C":"又有权利又有义务","D":"又有统一意志、又有个人心情舒畅、生动活泼"},"answer":"ABD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_7"},{"stem":"毛泽东提出，处理中国共产党与民主党派的关系，应坚持的方针为（ ）。","options":{"A":"长期共存","B":"互相监督","C":"肝胆相照","D":"荣辱与共"},"answer":"AB","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_8"},{"stem":"从1953年开始，在过渡时期总路线的指引下，中国共产党领导人民开始进行有计划的社会主义建设和有系统的社会主义改造。当时中国之所以要着力进行和可能进行社会主义改造，主要是因为（ ）。","options":{"A":"资本主义国家的封锁和遏制，社会主义国家的同情和援助","B":"资本主义经济力量弱小，发展困难","C":"对个体农业进行社会主义改造，是实现国家工业化的一个必要条件","D":"社会主义性质的国营经济力量相对来说比较强大"},"answer":"ABCD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_9"},{"stem":"中国共产党根据马克思列宁主义关于农业社会主义改造的思想，从我国的实际出发，开创了一条有中国特点的农业合作化道路，成功地实现了对个体农业的社会主义改造。其历史经验主要有（ ）。","options":{"A":"国家用先进的技术和装备发展农业经济","B":"遵循自愿互利、典型示范和国家帮助的原则","C":"在土地改革后不失时机地引导个体农民走互助合作道路","D":"采取从互助组到初级社再到高级社的逐步过渡形式"},"answer":"BCD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_10"},{"stem":"1956年4月至5月，毛泽东先后在中央政治局扩大会议和最高国务会议上，作了《论十大关系》的报告，这是党探索中国社会主义建设道路的良好开端。《论十大关系》提出","options":{"A":"以苏为鉴，独立自主地探索适合中国情况的社会主义建设道路","B":"调动一切积极因素为社会主义事业服务","C":"探索在中国实行改革开放的道路","D":"完成马克思主义同中国实际的“第二次结合” 答案：AB"},"answer":"AB","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_11"},{"stem":"20世纪50年代至60年代初，党领导人民探索社会主义建设道路，历经艰辛和曲折，在理论和实践上取得了一系列重要成果。这些成果具有重要的意义，主要是","options":{"A":"巩固和发展了我国的社会主义制度","B":"为开创中国特色社会主义提供了宝贵经验、理论准备、物质基础","C":"为其他社会主义国家的建设提供了现实的发展模式","D":"丰富了科学社会主义的理论和实践 答案：ABD 《论十大关系》前五条主要讨论的问题包括（ ）。 重工业与轻工业、农业的关系 沿海工业与内地工业的关系 中央与地方的关系 革命与反革命的关系 答案：ABC"},"answer":"ABD","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_12"},{"stem":"说服","options":{"A":"示范","B":"赎买","C":"国家援助"},"answer":"ABC","chapter":"第八章","subject":"history","type":"multi","id":"history_第八章_multi_13"},{"stem":"简述过渡时期总路线及其特点。","answer":"能不能保卫住革命胜利成果，巩固新生人民政权。","chapter":"第八章","subject":"history","type":"short","id":"history_第八章_short_1"},{"stem":"简述建立社会主义制度的重大意义的。","answer":"能不能战胜严重经济困难，迅速恢复和发展国民经济。","chapter":"第八章","subject":"history","type":"short","id":"history_第八章_short_2"},{"stem":"中华人民共和国成立初期，我国面临的主要考验有哪些？","answer":"能不能巩固民族独立，维护国家主权和安全。","chapter":"第八章","subject":"history","type":"short","id":"history_第八章_short_3"},{"stem":"请结合当前中国面临的国际局势，谈谈我国建立独立的、比较完整的工业体系和国民经济体系的重大意义。","answer":"它是中国人民在中国共产党领导下艰苦奋斗的伟大成果，是社会主义制度优越性的生动体现，具有极其重要的战略意义。它为我们继续推进社会主义建设开拓了可以依靠的阵地，为实现现代化的伟大事业奠定了初步的物质基础。","chapter":"第八章","subject":"history","type":"essay","id":"history_第八章_essay_1"},{"stem":"中国社会主义建设道路艰辛探索的经验教训是什么？","answer":"随着独立的、比较完整的工业体系的形成，工业在国民经济中的主导地位日益明显，发挥着越来越重要的作用。工业部门不仅为改善人民生活提供了大量的日用消费品，为国民经济其他部门和国防建设提供了大批燃料、动力、原材料和技术装备，而且还为出口提供了相当数量的产品，它使中国在赢得政治上的独立之后赢得了经济上的独立。","chapter":"第八章","subject":"history","type":"essay","id":"history_第八章_essay_2"},{"stem":"1992 年，以邓小平南方谈话和中共十四大为标志，中国社会主义改革开放和现代化建设事业所进入的新的发展阶段是（ ）。","options":{"A":"从计划经济体制向多种经济体制转变","B":"从多种经济体制向单一经济体制转变","C":"从计划经济体制向社会主义市场经济体制转变","D":"从新民主主义经济体制向社会主义市场经济体制转变"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_1"},{"stem":"标志着中国进入改革开放和社会主义现代化建设的历史新时期的重要会议是（ ）。","options":{"A":"中共十一届三中全会","B":"中共十二届三中全会","C":"中共十三届三中全会","D":"中共十四届三中全会"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_2"},{"stem":"1981 年 6 月，中共十一届六中全会通过的重要决议是（ ）。","options":{"A":"《关于党的若干历史问题的决议》","B":"《关于教育体制改革的决定》","C":"《关于建国以来党的若干历史问题的决议》","D":"《关于加强社会主义精神文明建设若干重要问题的决议》"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_3"},{"stem":"1982 年 9 月在中国共产党第十二次全国代表大会开幕词中，邓小平明确提出的重大命题是 ( ) 。","options":{"A":"坚持四项基本原则","B":"发展社会主义市场经济","C":"建设有中国特色社会主义","D":"没有民主就没有社会主义"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_4"},{"stem":"1987 年 10 月，中国共产党第十三次全国代表大会提出的党在社会主义初级阶段的基本路线被概括为（ ）。","options":{"A":"一个中心、两个基本点","B":"一化三改","C":"一体两翼","D":"三步走"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_5"},{"stem":"1995年,中共中央、国务院作出了《关于加速科学技术进步的决定》,正式提出（）的重大决策。","options":{"A":"实施科教兴国战略","B":"建立现代企业制度","C":"坚持可持续发展战略","D":"科学技术是第一生产力"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_6"},{"stem":"建设有中国特色社会主义的构想是在哪一次会议上提出的?","options":{"A":"十一届三中全会","B":"中共十二大","C":"全国人大六届一次会议","D":"中共十四大"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_7"},{"stem":"中国政府第一次公开提出和平解决台湾问题的方针是在（）。","options":{"A":"《告台湾同胞书》中","B":"《关于台湾回归祖国､实现和平统一的方针政策》中","C":"《联合声明》中","D":"六届人大二次会议"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_8"},{"stem":"制定出党在社会主义初级阶段基本路线的会议是()。","options":{"A":"中共十一届三中全会","B":"中共十二大","C":"中共十三大","D":"中共十四大"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_9"},{"stem":"邓小平提出中国社会主义农业的发展会有两个飞跃，第一个飞跃是废除人民公社，实行家庭联产承包为主的责任制，第二个飞跃是（ ）。","options":{"A":"发展集体经济","B":"发展个体经济","C":"发展国有经济","D":"发展合作经济"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_10"},{"stem":"确定我国经济体制改革目标,核心问题是正确认识和处理()。","options":{"A":"计划与市场的关系","B":"改革与发展的关系","C":"经济体制与经济制度的关系","D":"发展与稳定的关系"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_11"},{"stem":"下列选项不是在《关于建国以来党的若干历史问题的决议》中提出的是（ ）。","options":{"A":"实事求是地评价了毛泽东的历史地位","B":"决定走适合我国国情的社会主义现代化建设道路","C":"否定了“无产阶级专政下继续革命理论”","D":"首次提出我国社会主义制度还处于初级阶段"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_12"},{"stem":"1978年直接领导和发动真理标准问题讨论的中央领导人是（）。","options":{"A":"邓小平","B":"汪东兴","C":"胡耀邦","D":"陈云"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_13"},{"stem":"系统阐明社会主义初级阶段理论是在（）。","options":{"A":"《关于建国以来党的若干历史问题的决议》","B":"1982年党的十二大报告","C":"1987年党的十三大报告","D":"1988年党的十三届三中全会"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_14"},{"stem":"党的十三大召开前夕，邓小平强调指出：“社会主义本身是共产主义的初级阶段，而我们中国又处在社会主义的初级阶段，就是不发达的阶段，一切都要从这个实际出发，根据这个实际来制订规划。”这一论述（）。","options":{"A":"首次提出了社会主义初级阶段概念","B":"首次系统阐述了社会主义初级阶段理论","C":"首次对社会主义发展阶段进行了划分","D":"首次把社会主义初级阶段作为事关全局的基本国情加以把握"},"answer":"D","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_15"},{"stem":"继延安整风之后又一场马克思主义思想解放运动是指（）。","options":{"A":"中共十一届三中全会","B":"十一届三中全会前的中央工作会议","C":"关于真理标准问题的大讨论","D":"中共十三大"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_16"},{"stem":"针对1977年至1978年我国出现国民经济比例失调的情况，1979年4月召开的中共中央工作会议决定，对国民经济实行调整的方针是（）。","options":{"A":"既反保守，又反冒进，在综合平衡中稳步前进","B":"以工业为先导，以农业为基础","C":"调整、充实、巩固、提高","D":"调整、改革、整顿、提高"},"answer":"D","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_17"},{"stem":"1984年10月，中共十二届三中全会通过了《中共中央关于经济体制改革的决定》，在社会主义经济理论上的重大突破是（）。","options":{"A":"指出我国社会主义经济是在公有制基础上的有计划的商品经济","B":"指出计划与市场都是手段","C":"指出社会主义也可以搞市场经济","D":"指出社会主义只能以计划经济为主，以市场调节为辅"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_18"},{"stem":"明确提出我国经济体制改革的目标是建立社会主义市场经济体制的会议是（）。","options":{"A":"中共十三大","B":"中共十四大","C":"中共十五大","D":"中共十六大"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_19"},{"stem":"1978年真理标准问题的讨论，其实质在于（ ）。","options":{"A":"是不是坚持马列主义、毛泽东思想","B":"是不是坚持改革开放","C":"是不是坚持社会主义","D":"是不是坚持科学发展"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_20"},{"stem":"1978年5月11日，《光明日报》发表题为（ ）的特约评论员文章，从根本上否定了“两个凡是”的错误方针，揭开了真理标准讨论的序幕。","options":{"A":"《实践是检验真理的唯一标准》","B":"《一切主观世界的东西都要接受实践的检验》","C":"《马克思主义的一个最基本的原则》","D":"《唯一的标准》"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_21"},{"stem":"坚持四项基本原则，是实现我国现代化的根本前提。这四项基本原则是（ ）。","options":{"A":"坚持社会主义道路;坚持人民民主专政;坚持中国共产党的领导;坚持马克思列宁主义毛泽东思想","B":"坚持社会主义道路;坚持人民代表大会制度;坚持中国共产党的领导;坚持马克思列宁主义毛泽东思想","C":"坚持社会主义道路;坚持无产阶级专政;坚持多党合作制度;坚持马克思列宁主义毛泽东思想","D":"坚持社会主义道路;坚持人民民主专政;坚持政治协商制度;坚持马克思列宁主义毛泽东思想"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_22"},{"stem":"党的十一届三中全会以来，我国农村发生了许多重大变化。影响最深远的是普遍实行了多种形式的农村生产责任制，而（ ）又越来越成为主要形式。","options":{"A":"集体经营","B":"家庭联产承包制","C":"包产到户","D":"土地私有"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_23"},{"stem":"党在社会主义初级阶段基本路线的核心是（ ）。","options":{"A":"以经济建设为核心","B":"坚持四项基本原则、坚持发展改革开放","C":"“一个中心、两个基本点”","D":"发展"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_24"},{"stem":"1992年初，邓小平在视察南方谈话中指出：社会主义的本质，是解放生产力，发展生产力，消灭剥削，消除两极分化，最终达到（ ）。","options":{"A":"小康社会","B":"生活富裕","C":"共同富裕","D":"经济繁荣"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_25"},{"stem":"从1979年11月起，在邓小平主持下，中共中央着手起草《关于建国以来党的若干历史问题的决议》。邓小平对《决议》的起草提出了指导原则，其中，最核心的一条是","options":{"A":"对建国30年来历史上的大事，要进行实事求是的分析","B":"宜粗不宜细，总结过去是为了引导大家团结一致向前看","C":"确立毛泽东同志的历史地位，坚持和发展毛泽东思想","D":"走自己的路，开辟中国特色社会主义道路"},"answer":"C","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_26"},{"stem":"1981年，党的十一届六中全会通过了《关于建国以来党的若干历史问题的决议》，具有深远历史意义。《决议》的通过标志着","options":{"A":"党重新确立了马克思主义的思想路线、政治路线、组织路线","B":"党在指导思想上拨乱反正的胜利完成","C":"新中国成立以来党的历史上具有深远意义的伟大转折的实现","D":"我国改革开放和社会主义现代化建设新时期的开启"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_27"},{"stem":"“把马克思主义的普遍真理同我国的具体实际结合起来，走自己的道路，建设有中国特色的社会主义”，这是邓小平在党的代表大会上的开幕词中提出的，这次党的代表大会是","options":{"A":"中共十二大","B":"中共十三大","C":"中共十四大","D":"中共十五大"},"answer":"A","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_28"},{"stem":"( )成为开辟中国特色社会主义新道路、开创中国特色社会主义新理论的宣言书的是","options":{"A":"《中共十一届三中全会公报》","B":"《解放思想，实事求是，团结一致向前看》","C":"《关于建国以来党的若干历史问题的决议》","D":"《实践是检验真理的唯一标准》"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_29"},{"stem":"（ ）首次使用“邓小平理论”这个概念，把邓小平理论同马克思列宁主义、毛泽东思想一起作为党的指导思想写入党章。","options":{"A":"党的十四大","B":"党的十五大","C":"党的十四届三中全会","D":"党的十六大"},"answer":"B","chapter":"第九章","subject":"history","type":"single","id":"history_第九章_single_30"},{"stem":"党的十一届三中全会标志着中国共产党重新确立了马克思主义的思想路线、政治路线、组织路线，实现了新中国成立以来党的历史上具有深远意义的伟大转折，开启了我国改革开放和社会主义现代化建设的新时期。全会做出实行改革开放的历史性决策，是基于（）。","options":{"A":"对党和国家前途命运的深刻把握","B":"对社会主义革命和建设实践的深刻总结","C":"对时代潮流的深刻洞察","D":"对人民群众期盼和需要的深刻体悟"},"answer":"ABCD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_1"},{"stem":"1978年12月18日到22日，党的十一届三中全会在北京召开，会议的主要任务是确定把全党工作重心转移到社会主义现代化建设上来。这次全会是新中国成立以来党的历史上具有深远意义的伟大转折，全会结束了粉碎“四人帮”后两年党和国家工作在徘徊中前进的局面，标志着中国共产党（）。","options":{"A":"重新确立了马克思主义的思想路线、政治路线、组织路线","B":"开始了在思想、政治、组织等领域的全面拨乱反正","C":"形成了以邓小平为核心的党的中央领导集体","D":"揭开了社会主义改革开放的序幕"},"answer":"ABCD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_2"},{"stem":"1992年初，在关乎中国改革开放和社会主义现代化建设前途命运的关键时刻，邓小平在视察武昌、深圳、珠海、上海等地时，发表了重要谈话。谈话的主要内容有（）。","options":{"A":"计划多一点还是市场多一点，不是社会主义与资本主义的本质区别","B":"不坚持社会主义，不改革开放，不发展经济，不改善人民生活，只能是死路一条","C":"走社会主义道路，就是要逐步实现共同富裕","D":"革命是解放生产力，改革也是解放生产力"},"answer":"ABCD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_3"},{"stem":"在庆祝中国共产党成立95周年大会上，习近平总书记强调指出：“坚持不忘初心，继续前进，要坚持党的基本路线不动摇，不断把中国特色社会主义伟大事业推向前进。”改革开放以来，党和国家领导人一再强调要毫不动摇地坚持党的基本路线，这主要是因为，实践已经证明党的基本路线是（）。","options":{"A":"党和国家的生命线，人民的幸福线","B":"兴国、立国、强国的重大法宝","C":"实现科学发展的政治保证","D":"思想路线的核心"},"answer":"ABC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_4"},{"stem":"关于真理标准问题的大讨论（）。","options":{"A":"是继延安整风之后又一场马克思主义思想解放运动","B":"成为拨乱反正和改革开放的思想先导","C":"为党重新确立实事求是的思想路线，实现历史性的转折作了思想理论准备","D":"是新中国成立以来党的历史上具有深远意义的伟大转折"},"answer":"ABC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_5"},{"stem":"《关于建国以来党的若干历史问题的决议》关于毛泽东的评价有（）。","options":{"A":"伟大的马克思主义者","B":"无产阶级革命家、战略家和理论家","C":"功绩是第一位的，错误是第二位的","D":"错误是第一位的，功绩是第二的"},"answer":"ABC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_6"},{"stem":"1979年3月30日，邓小平在理论工作务虚会上作了题为《坚持四项基本原则》的讲话，首次提出“四项基本原则”这一概念。这就是（）。","options":{"A":"坚持社会主义道路","B":"坚持人民民主专政","C":"坚持共产党的领导","D":"坚持马克思列宁主义、毛泽东思想"},"answer":"ABCD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_7"},{"stem":"1987年10月召开的中国共产党第十三次全国代表大会最突出的贡献是（）。","options":{"A":"比较系统地阐述了关于社会主义初级阶段的理论","B":"完整地概括了中国共产党在社会主义初级阶段“一个中心、两个基本点”的基本路线","C":"制定了下一步经济体制改革和政治体制改革的基本任务和奋斗目标","D":"规定了三步走的发展战略"},"answer":"ABC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_8"},{"stem":"中共十三大正式制定了社会主义现代化建设的战略部署是（）。","options":{"A":"第一步，实现国民生产总值比1980年翻一番，解决人民的温饱问题","B":"第二步，到20世纪末，使国民生产总值再增长一倍，人民生活达到小康水平","C":"第三步，到21世纪中叶，人均国民生产总值达到中等发达国家水平，人民生活比较富裕，基本实现现代化","D":"第三步，到21世纪中叶，人均国民生产总值达到发达国家水平，人民生活比较富裕，全面实现现代化"},"answer":"ABC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_9"},{"stem":"2002年，中共十六大首次提出加强党的执政能力建设，提高党的领导水平和执政水平，并把党的执政能力概括为()。","options":{"A":"驾驭市场经济的能力","B":"科学判断形势的能力","C":"应对复杂局面的能力","D":"依法执政的能力和总揽全局的能力"},"answer":"ABCD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_10"},{"stem":"党在社会主义初级阶段基本路线的主要内容是（ ）。","options":{"A":"以经济建设为中心 B 以精神文明建设为动力","C":"坚持四项基本原则 D 坚持改革开放"},"answer":"ACD","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_11"},{"stem":"党的十一届三中全会以来，以邓小平为主要代表的中国共产党人初步回答的首要的基本理论问题是（ ）。","options":{"A":"什么是社会主义 B 建设什么样的党","C":"怎样建设社会主义 D 怎样建设党"},"answer":"AC","chapter":"第九章","subject":"history","type":"multi","id":"history_第九章_multi_12"},{"stem":"为什么说党的十一届三中全会是新中国成立以来的伟大历史转折？","answer":"中共十一届三中全会是新中国成立以来的伟大历史转折，这是因为： （1）从十一届三中全会的内容来说 ①全会冲破了长期“左”倾错误的严重束缚，彻底否定了“两个凡是”的错误方针，高度评价了关于真理标准问题的讨论，并且果断停用了“以阶级斗争为纲”的口号，作出了把工作重点转移到社会主义现代化建设上来和实行改革开放的战略决策。 ②全会恢复了党的民主集中制的优良传统，审查解决了历史上遗留的一批重大问题和一些重要领导人的功过是非问题。 （2）从十一届三中全会的影响和意义来讲 ①中共十一届三中全会是新中国成立以来党的历史上具有深远意义的伟大转折。 ②全会结束了粉碎“四人帮”后党和国家工作在徘徊中前进的局面，标志着中国共产党重新确立了马克思主义的思想路线、政治路线、组织路线，开始了在思想、政治、组织等领域的全面拨乱反正，形成了以邓小平为核心的党的中央领导集体，揭开了社会主义改革开放的序幕。 ③以这次全会为起点，中国进入了改革开放和社会主义现代化建设的历史新时期。党和国家充满希望和活力地踏上了实现社会主义现代化的伟大征程。","chapter":"第九章","subject":"history","type":"short","id":"history_第九章_short_1"},{"stem":"中国特色社会主义是怎样接续发展的？","answer":"中国特色社会主义的接续发展经过了以下几个阶段： （1）以毛泽东为主要代表的中国共产党人，把马克思列宁主义的基本原理同中国革命的具体实践结合起来，创立了毛泽东思想。在毛泽东思想指引下，中国共产党领导全国各族人民，经过长期的反对帝国主义、封建主义、官僚资本主义的革命斗争，取得了新民主主义革命的胜利，建立了人民民主专政的中华人民共和国；新中国成立以后，顺利地进行了社会主义改造，完成了从新民主主义到社会主义的过渡，确立了社会主义基本制度，发展了社会主义的经济、政治和文化。 （2）十一届三中全会以来，以邓小平为主要代表的中国共产党人，总结新中国成立以来正反两方面的经验，解放思想，实事求是，实现全党工作中心向经济建设的转移，实行改革开放，开辟了社会主义事业发展的新时期，逐步形成了建设中国特色社会主义的路线、方针、政策，阐明了在中国建设社会主义、巩固和发展社会主义的基本问题，创立了邓小平理论。 （3）十三届四中全会以来，以江泽民为主要代表的中国共产党人，在建设中国特色社会主义的实践中，加深了对什么是社会主义、怎样建设社会主义和建设什么样的党、怎样建设党的认识，积累了治党治国新的宝贵经验，形成了“三个代表”重要思想。 （4）十六大以来，以胡锦涛为主要代表的中国共产党人，坚持以邓小平理论和“三个代表”重要思想为指导，根据新的发展要求，深刻认识和回答了新形势下实现什么样的发展、怎样发展等重大问题，形成了以人为本、全面协调可持续发展的科学发展观。 （5）十八大以来，以习近平为主要代表的中国共产党人，顺应时代发展，理论和实践结合，系统回答了新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义这个重大时代课题，创立了习近平新时代中国特色社会主义思想。在习近平新时代中国特色社会主义思想指导下，中国共产党领导全国各族人民，统揽伟大斗争、伟大工程、伟大事业、伟大梦想，推动中国特色社会主义进入了新时代。","chapter":"第九章","subject":"history","type":"short","id":"history_第九章_short_2"},{"stem":"（  ）对全面建成小康社会作出科学谋划，对夺取中国特色社会主义新胜利作出全面部署，标志着中国特色社会主义进入新时代。","options":{"A":"党的十八大","B":"党的十九大","C":"党的十九届六中全会","D":"党的二十大"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_1"},{"stem":"习近平新时代中国特色社会主义思想被写入党章是在","options":{"A":"党的十八大","B":"党的十九大","C":"党的十九届六中全会","D":"党的二十大"},"answer":"B","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_2"},{"stem":"（  ），习近平在参观《复兴之路》展览时首次提出并阐释实现中华民族伟大复兴的中国梦。","options":{"A":"2012年","B":"2013年","C":"2014年","D":"2015年"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_3"},{"stem":"2014年，习近平首次提出“总体国家安全观”，这系统回答了中国特色社会主义新时代，如何既解决好（  ）的共性安全问题，同时处理好中华民族伟大复兴关键阶段的特殊安全问题这个重大时代课题。","options":{"A":"大国发展进程中","B":"百年未有之大变局下","C":"社会主义发展进程中","D":"新兴国家发展过程中"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_4"},{"stem":"2015年，（  ）在北京召开，全会审议通过的《中共中央关于制定国民经济和社会发展第十三个五年规划的建议》中明确提出了以人民为中心的发展思想，提出了创新、协调、绿色、开放、共享的新发展理念。","options":{"A":"党的十八届二中全会","B":"党的十八届三中全会","C":"党的十八届四中全会","D":"党的十八届五中全会"},"answer":"D","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_5"},{"stem":"2013年，习近平在十八届中央纪委二次全会上指出，严明党的纪律，首要的就是严明（  ）。","options":{"A":"工作纪律 B 政治纪律","C":"组织纪律 D 生活纪律"},"answer":"B","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_6"},{"stem":"（  ），习近平在视察国防科技技术大学时首次提出了实施人才强军战略。","options":{"A":"2013年","B":"2015年","C":"2018年","D":"2020年"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_7"},{"stem":"2016年7月1日，习近平总书记在庆祝中国共产党成立95周年大会上强调，中国共产党人“坚持不忘初心、继续前进”，就要坚持","options":{"A":"四个自信","B":"四个意识","C":"四个全面","D":"五位一体"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_8"},{"stem":"2014年，新世纪第一次全军政治工作会议在（  ）召开。习近平强调革命的政治工作是革命军队的生命线，明确提出了军队政治工作的时代主题。","options":{"A":"嘉兴","B":"北京","C":"延安","D":"古田"},"answer":"D","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_9"},{"stem":"（  ）鲜明指出，“党确立习近平同志党中央的核心、全党的核心地位，确立习近平新时代中国特色社会主义思想的指导地位，反映了全党全军全国各族人民共同心愿，对新时代党和国家事业发展、对推进中华民族伟大复兴历史进程具有决定性意义”。","options":{"A":"党的十八大","B":"党的十九大","C":"党的十九届六中全会","D":"党的二十大"},"answer":"C","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_10"},{"stem":"2019年，（  ）在北京召开，专门研究国家制度和国家治理问题，这在党的历史上还是第一次。全会最重要的成果就是审议通过《中共中央关于坚持和完善中国特色社会主义制度、推进国家治理体系和治理能力现代化若干重大问题的决定》，全面回答了在我国国家制度和国家治理上，应该“坚持和巩固什么，完善和发展什么”这个重大政治问题。","options":{"A":"十九届二中全会","B":"十九届三中全会","C":"十九届四中全会","D":"十九届五中全会"},"answer":"C","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_11"},{"stem":"2020年，十三届全国人大三次会议通过（），这是新中国成立以来第一部以“法典”命名的法律。","options":{"A":"《中华人民共和国民法典》","B":"《中华人民共和国刑法典》","C":"《中华人民共和国行政法典》","D":"《中华人民共和国诉讼法典》"},"answer":"A","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_12"},{"stem":"历史和现实都证明，中国人民和中华民族之所以能够扭转近代以后的历史命运、取得今天的伟大成就，最根本的是有（ ）。","options":{"A":"中国特色社会主义文化","B":"中国特色社会主义道路","C":"中国共产党的坚强领导","D":"中国特色社会主义制度"},"answer":"C","chapter":"第十章","subject":"history","type":"single","id":"history_第十章_single_13"},{"stem":"实现中国梦，必须","options":{"A":"走中国道路","B":"弘扬中国精神","C":"凝聚中国力量","D":"走资本主义道路"},"answer":"ABC","chapter":"第十章","subject":"history","type":"multi","id":"history_第十章_multi_1"},{"stem":"2021年7月1日，习近平总书记在庆祝中国共产党成立100周年大会上明确提出“两个结合”的重大理论命题，其内容是把马克思主义基本原理","options":{"A":"同中国具体实际相结合","B":"同中华优秀传统文化相结合","C":"同中国历史发展情况相结合","D":"同中华文明标识性概念相结合"},"answer":"AB","chapter":"第十章","subject":"history","type":"multi","id":"history_第十章_multi_2"},{"stem":"习近平新时代中国特色社会主义思想从理论和实践的结合上科学回答了新时代（  ）等重大时代课题。","options":{"A":"建设什么样的社会主义现代化强国、怎样建设社会主义现代化强国","B":"建设什么样的长期执政的马克思主义政党、怎样建设长期执政的马克思主义政党","C":"坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义","D":"实现什么样的发展，如何实现发展"},"answer":"ABC","chapter":"第十章","subject":"history","type":"multi","id":"history_第十章_multi_3"},{"stem":"2012年12月，习近平总书记在广东考察工作时深刻指出：\"我们的改革开放是（  ）的。\"","options":{"A":"有立场","B":"有方向","C":"有原则","D":"有部署"},"answer":"ABC","chapter":"第十章","subject":"history","type":"multi","id":"history_第十章_multi_4"},{"stem":"习近平新时代中国特色社会主义思想创立的时代背景是","options":{"A":"世界百年未有之大变局加速演进","B":"新时代中国正处于中华民族伟大复兴的关键时期","C":"我国经济高速度发展","D":"中国成为世界领导角色"},"answer":"AB","chapter":"第十章","subject":"history","type":"multi","id":"history_第十章_multi_5"},{"stem":"推动高质量发展的必要性。","answer":"首先，推动高质量发展是保持经济持续健康发展的必然要求。只有推动高质量发展，才能适应科技新变化、人民新需要，形成优质高效多样化的供给体系，提供更多优质产品和服务，在新的水平上实现供求均衡和经济持续健康发展。 其次，推动高质量发展是适应我国社会主要矛盾变化的必然要求。我国经济发展阶段也在发生历史性变化，不平衡不充分的发展就是发展质量不高的表现，发展中的矛盾和问题主要就集中在发展质量上。 最后，推动高质量发展是遵循经济发展规律的必然要求。经济发展是一个螺旋式上升的过程，上升不是线性的，量积累到一定阶段，必须转向质的提升，我国经济发展要遵循这一规律。","chapter":"第十章","subject":"history","type":"short","id":"history_第十章_short_1"},{"stem":"推进中国式现代化需要把握的重大原则。","answer":"全面建设社会主义现代化国家，是一项伟大而艰巨的事业，前途光明，任重道远。 必须牢牢把握以下重大原则： 第一，坚持和加强党的全面领导。确保我国社会主义现代化建设正确方向，确保拥有团结奋斗的强大政治凝聚力、发展自信心。 第二，坚持中国特色社会主义道路。坚持以经济建设为中心，坚持四项基本原则，坚持改革开放，坚持独立自主、自力更生，坚持道不变、志不改，始终坚持和发展中国特色社会主义。 第三，坚持以人民为中心的发展思想。不断实现发展为了人民、发展依靠人民、发展成果由人民共享，让现代化建设成果更多更公平惠及全体人民。 第四，坚持深化改革开放。不断彰显中国特色社会主义制度优势，不断增强社会主义现代化建设的动力和活力，把我国制度优势更好转化为国家治理效能。 第五，坚持发扬斗争精神。增强全党全国各族人民的志气、骨气、底气，不信邪、不怕鬼、不怕压，依靠顽强斗争打开事业发展新天地。","chapter":"第十章","subject":"history","type":"essay","id":"history_第十章_essay_1"}]}};
